{
  "name": "Agua Cristalina Manager",
  "description": "Um aplicativo de gestão completo para lojas de água purificada, focado em controle de vendas, despesas, estoque e insights inteligentes com IA.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type TransactionType = 'sale' | 'expense' | 'investment';

export interface Transaction {
  id: string;
  date: string;
  type: TransactionType;
  category: string;
  amount: number;
  description: string;
  quantity?: number;
}

export interface InventoryItem {
  id: string;
  name: string;
  quantity: number;
  unit: string;
  minThreshold: number;
}

export interface BusinessState {
  transactions: Transaction[];
  inventory: InventoryItem[];
}

export type ViewType = 'dashboard' | 'sales' | 'expenses' | 'inventory' | 'ai';

import React from 'react';
import { LayoutDashboard, ShoppingCart, CreditCard, Box, Sparkles } from 'lucide-react';
import { TransactionType, ViewType } from './types';

export const SALE_CATEGORIES = ['Galão 20L', 'Garrafa 5L', 'Garrafa 1.5L', 'Copo 200ml', 'Entrega'];
export const EXPENSE_CATEGORIES = ['Aluguel', 'Energia', 'Salários', 'Manutenção', 'Combustível', 'Impostos', 'Marketing'];
export const INVESTMENT_CATEGORIES = ['Maquinário', 'Novos Galões', 'Reforma Loja', 'Veículo'];

export const NAV_ITEMS = [
  { id: 'dashboard' as ViewType, label: 'Início', icon: <LayoutDashboard size={20} /> },
  { id: 'sales' as ViewType, label: 'Vendas', icon: <ShoppingCart size={20} /> },
  { id: 'expenses' as ViewType, label: 'Gastos', icon: <CreditCard size={20} /> },
  { id: 'inventory' as ViewType, label: 'Estoque', icon: <Box size={20} /> },
  { id: 'ai' as ViewType, label: 'Consultor', icon: <Sparkles size={20} /> },
];

export const INITIAL_INVENTORY = [
  { id: '1', name: 'Galões 20L Vazios', quantity: 150, unit: 'un', minThreshold: 20 },
  { id: '2', name: 'Lacres', quantity: 1000, unit: 'un', minThreshold: 100 },
  { id: '3', name: 'Tampas', quantity: 800, unit: 'un', minThreshold: 50 },
  { id: '4', name: 'Rótulos', quantity: 2000, unit: 'un', minThreshold: 200 },
];

import { GoogleGenAI } from "@google/genai";
import { BusinessState } from "../types";

export const getBusinessInsights = async (state: BusinessState): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const salesTotal = state.transactions
    .filter(t => t.type === 'sale')
    .reduce((acc, t) => acc + t.amount, 0);

  const expensesTotal = state.transactions
    .filter(t => t.type === 'expense')
    .reduce((acc, t) => acc + t.amount, 0);

  const investmentTotal = state.transactions
    .filter(t => t.type === 'investment')
    .reduce((acc, t) => acc + t.amount, 0);

  const prompt = `
    Como consultor especialista em negócios de água purificada (Marca: Agua Cristalina), analise os seguintes dados financeiros e de estoque:
    - Vendas Totais: R$ ${salesTotal.toFixed(2)}
    - Despesas Totais: R$ ${expensesTotal.toFixed(2)}
    - Investimentos Totais: R$ ${investmentTotal.toFixed(2)}
    - Lucro Líquido: R$ ${(salesTotal - expensesTotal).toFixed(2)}
    - Número de Transações: ${state.transactions.length}
    - Status do Estoque: ${state.inventory.map(i => `${i.name}: ${i.quantity}${i.unit}`).join(', ')}

    Por favor, forneça:
    1. Uma análise rápida da saúde financeira (está no lucro ou prejuízo?).
    2. Duas sugestões práticas para aumentar as vendas ou reduzir custos na operação de água.
    3. Alerta de estoque se algo estiver baixo.

    Responda em Português de forma motivadora e profissional, adequada para leitura rápida em celular.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
        topP: 0.95,
      }
    });

    return response.text || "Desculpe, não consegui gerar uma análise no momento. Tente novamente mais tarde.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Erro ao conectar com a inteligência artificial. Verifique sua conexão.";
  }
};

import React from 'react';
import { ViewType } from '../types';
import { NAV_ITEMS } from '../constants';

