    <div className="flex flex-col h-screen max-w-md mx-auto bg-slate-50 relative overflow-hidden shadow-2xl">
      {/* Header */}
      <header className="bg-blue-600 text-white px-6 py-4 flex items-center justify-between shadow-md z-10">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-white rounded-full flex items-center justify-center">
            <span className="text-blue-600 font-bold text-lg">A</span>
          </div>
          <h1 className="font-bold text-xl tracking-tight">Agua Cristalina</h1>
        </div>
        <div className="text-blue-100 text-xs font-medium uppercase tracking-wider">Gestão Pro</div>
