import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, Legend } from 'recharts';
import { Transaction, BusinessState } from '../types';
import { TrendingUp, TrendingDown, Wallet, Droplets } from 'lucide-react';

interface DashboardProps {
  state: BusinessState;
}

const Dashboard: React.FC<DashboardProps> = ({ state }) => {
  const sales = state.transactions.filter(t => t.type === 'sale').reduce((sum, t) => sum + t.amount, 0);
  const expenses = state.transactions.filter(t => t.type === 'expense').reduce((sum, t) => sum + t.amount, 0);
  const investments = state.transactions.filter(t => t.type === 'investment').reduce((sum, t) => sum + t.amount, 0);
  const balance = sales - expenses;

  const chartData = [
    { name: 'Vendas', value: sales, color: '#2563eb' },
    { name: 'Despesas', value: expenses, color: '#ef4444' },
    { name: 'Investimento', value: investments, color: '#f59e0b' },
  ];

  // Simple grouping for bar chart (last 5 transactions)
  const lastTransactions = state.transactions.slice(-5).map(t => ({
    name: t.category,
    valor: t.amount,
    type: t.type
  }));

  return (
    <div className="space-y-6 animate-fadeIn">
      {/* Quick Summary Grid */}
      <div className="grid grid-cols-2 gap-3">
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex flex-col items-start">
          <div className="bg-blue-100 p-2 rounded-lg text-blue-600 mb-2">
            <TrendingUp size={20} />
          </div>
          <span className="text-slate-500 text-xs font-medium">Vendas</span>
          <span className="text-xl font-bold text-slate-800">R$ {sales.toLocaleString()}</span>
        </div>

        <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex flex-col items-start">
          <div className="bg-red-100 p-2 rounded-lg text-red-600 mb-2">
            <TrendingDown size={20} />
          </div>
          <span className="text-slate-500 text-xs font-medium">Gastos</span>
          <span className="text-xl font-bold text-slate-800">R$ {expenses.toLocaleString()}</span>
        </div>

        <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex flex-col items-start col-span-2">
          <div className="flex justify-between w-full">
            <div className="flex flex-col">
              <span className="text-slate-500 text-xs font-medium">Lucro Líquido</span>
              <span className={`text-2xl font-black ${balance >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                R$ {balance.toLocaleString()}
              </span>
            </div>
            <div className="bg-emerald-100 p-3 rounded-full text-emerald-600">
              <Wallet size={24} />
            </div>
          </div>
        </div>
      </div>

      {/* Pie Chart Section */}
      <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100">
        <h3 className="text-slate-800 font-bold mb-4 flex items-center gap-2">
          <Droplets size={18} className="text-blue-500" />
          Visão Geral
        </h3>
        <div className="h-48 w-full">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={chartData}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={80}
                paddingAngle={5}
                dataKey="value"
              >
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
        </div>
        <div className="flex justify-center gap-4 mt-2">
          {chartData.map(item => (
            <div key={item.name} className="flex items-center gap-1">
              <div className="w-2 h-2 rounded-full" style={{ backgroundColor: item.color }} />
              <span className="text-[10px] text-slate-500 font-medium">{item.name}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Inventory Alert Simple List */}
      <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100">
        <h3 className="text-slate-800 font-bold mb-3">Alertas de Estoque</h3>
        <div className="space-y-3">
          {state.inventory.filter(i => i.quantity <= i.minThreshold).length === 0 ? (
            <p className="text-slate-400 text-sm italic">Tudo em ordem no estoque.</p>
          ) : (
            state.inventory
              .filter(i => i.quantity <= i.minThreshold)
              .map(item => (
                <div key={item.id} className="flex items-center justify-between p-3 bg-red-50 rounded-xl">
                  <span className="text-red-700 text-sm font-semibold">{item.name}</span>
                  <span className="bg-red-200 text-red-700 text-xs px-2 py-1 rounded-full font-bold">
                    {item.quantity} {item.unit}
                  </span>
                </div>
              ))
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Transaction, TransactionType } from '../types';
import { Plus, X } from 'lucide-react';
import { SALE_CATEGORIES, EXPENSE_CATEGORIES, INVESTMENT_CATEGORIES } from '../constants';

interface TransactionFormProps {
  type: TransactionType;
  onAdd: (transaction: Omit<Transaction, 'id'>) => void;
  transactions: Transaction[];
}

const TransactionForm: React.FC<TransactionFormProps> = ({ type, onAdd, transactions }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [amount, setAmount] = useState('');
  const [category, setCategory] = useState('');
  const [description, setDescription] = useState('');
  const [quantity, setQuantity] = useState('1');

  const categories = type === 'sale' ? SALE_CATEGORIES : 
                    type === 'expense' ? EXPENSE_CATEGORIES : 
                    INVESTMENT_CATEGORIES;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !category) return;

    onAdd({
      date: new Date().toISOString(),
      type,
      category,
      amount: parseFloat(amount),
      description,
      quantity: parseInt(quantity)
    });

    setAmount('');
    setCategory('');
    setDescription('');
    setQuantity('1');
    setIsOpen(false);
  };

  const filteredTransactions = transactions.filter(t => t.type === type).reverse();

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold text-slate-800 capitalize">
          {type === 'sale' ? 'Vendas Realizadas' : type === 'expense' ? 'Gastos Registrados' : 'Investimentos'}
        </h2>
        <button 
          onClick={() => setIsOpen(true)}
          className="bg-blue-600 text-white p-2 rounded-full shadow-lg hover:bg-blue-700 transition-colors"
        >
          <Plus size={24} />
        </button>
      </div>

      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-3xl p-6 shadow-2xl animate-scaleIn">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-lg font-bold text-slate-800">
                Novo Registro {type === 'sale' ? 'Venda' : 'Gasto'}
              </h3>
              <button onClick={() => setIsOpen(false)} className="text-slate-400">
                <X size={24} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-400 mb-1 uppercase">Categoria</label>
                <select 
                  value={category} 
                  onChange={e => setCategory(e.target.value)}
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
                  required
                >
                  <option value="">Selecione...</option>
                  {categories.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-400 mb-1 uppercase">Valor (R$)</label>
                <input 
                  type="number" 
                  step="0.01"
                  value={amount}
                  onChange={e => setAmount(e.target.value)}
                  placeholder="0,00"
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
                  required
                />
              </div>

              {type === 'sale' && (
                <div>
                  <label className="block text-xs font-bold text-slate-400 mb-1 uppercase">Quantidade</label>
                  <input 
                    type="number" 
                    value={quantity}
                    onChange={e => setQuantity(e.target.value)}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
              )}

              <div>
                <label className="block text-xs font-bold text-slate-400 mb-1 uppercase">Observação</label>
                <input 
                  type="text" 
                  value={description}
                  onChange={e => setDescription(e.target.value)}
                  placeholder="Ex: Entrega no Centro"
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
              </div>

              <button 
                type="submit"
                className="w-full bg-blue-600 text-white font-bold py-4 rounded-xl shadow-lg hover:bg-blue-700 transition-all active:scale-95"
              >
                Salvar
              </button>
            </form>
          </div>
        </div>
      )}

      <div className="space-y-3">
        {filteredTransactions.length === 0 ? (
          <div className="bg-white border-2 border-dashed border-slate-200 rounded-2xl p-8 text-center text-slate-400">
            Nenhum registro ainda.
          </div>
        ) : (
          filteredTransactions.map(t => (
            <div key={t.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between">
              <div className="flex flex-col">
                <span className="font-bold text-slate-800">{t.category}</span>
                <span className="text-xs text-slate-400">{new Date(t.date).toLocaleDateString()} • {t.description || 'Sem obs.'}</span>
              </div>
              <div className="flex flex-col items-end">
                <span className={`font-black ${type === 'sale' ? 'text-blue-600' : 'text-red-500'}`}>
                  {type === 'sale' ? '+' : '-'} R$ {t.amount.toFixed(2)}
                </span>
                {t.quantity && <span className="text-[10px] bg-slate-100 px-1.5 rounded-full text-slate-500">Qtd: {t.quantity}</span>}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default TransactionForm;

import React from 'react';
import { InventoryItem } from '../types';
import { Plus, Minus, AlertCircle } from 'lucide-react';

interface InventoryViewProps {
  inventory: InventoryItem[];
  onUpdate: (id: string, delta: number) => void;
}

const InventoryView: React.FC<InventoryViewProps> = ({ inventory, onUpdate }) => {
  return (
    <div className="space-y-4">
      <h2 className="text-xl font-bold text-slate-800">Controle de Estoque</h2>
      <p className="text-slate-500 text-sm">Gerencie insumos e garrafas vazias.</p>

      <div className="grid grid-cols-1 gap-3">
        {inventory.map(item => {
          const isLow = item.quantity <= item.minThreshold;
          return (
            <div key={item.id} className={`p-4 rounded-2xl bg-white border shadow-sm flex flex-col gap-3 ${isLow ? 'border-red-200 ring-1 ring-red-100' : 'border-slate-100'}`}>
              <div className="flex justify-between items-start">
                <div className="flex items-center gap-2">
                  <span className="font-bold text-slate-800">{item.name}</span>
                  {isLow && <AlertCircle size={16} className="text-red-500" />}
                </div>
                <span className={`px-3 py-1 rounded-full text-sm font-bold ${isLow ? 'bg-red-100 text-red-700' : 'bg-blue-50 text-blue-700'}`}>
                  {item.quantity} {item.unit}
                </span>
              </div>

              <div className="flex gap-2">
                <button 
                  onClick={() => onUpdate(item.id, -1)}
                  className="flex-1 bg-slate-100 py-2 rounded-xl text-slate-600 hover:bg-slate-200 active:scale-95 transition-all flex justify-center"
                >
                  <Minus size={20} />
                </button>
                <button 
                  onClick={() => onUpdate(item.id, 1)}
                  className="flex-1 bg-blue-600 py-2 rounded-xl text-white hover:bg-blue-700 active:scale-95 transition-all flex justify-center"
                >
                  <Plus size={20} />
                </button>
              </div>

              {isLow && (
                <div className="text-[10px] text-red-500 font-bold uppercase tracking-wider animate-pulse">
                  Reabastecimento necessário (Mínimo: {item.minThreshold})
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default InventoryView;

import React, { useState } from 'react';
import { BusinessState } from '../types';
import { getBusinessInsights } from '../services/geminiService';
import { Sparkles, Loader2, RefreshCw } from 'lucide-react';

interface AIAdvisorProps {
  state: BusinessState;
}

const AIAdvisor: React.FC<AIAdvisorProps> = ({ state }) => {
  const [insight, setInsight] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const fetchInsights = async () => {
    setLoading(true);
    try {
      const result = await getBusinessInsights(state);
      setInsight(result);
    } catch (err) {
      setInsight("Ocorreu um erro ao gerar os insights. Verifique sua chave API.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-gradient-to-br from-blue-600 to-cyan-500 p-6 rounded-3xl text-white shadow-xl overflow-hidden relative">
        <div className="relative z-10">
          <h2 className="text-2xl font-black mb-2">Consultor IA</h2>
          <p className="text-blue-50 text-sm leading-relaxed opacity-90">
            Analise seu desempenho comercial da Agua Cristalina com inteligência artificial de última geração.
          </p>
        </div>
        <Sparkles size={120} className="absolute -right-4 -bottom-4 text-white opacity-10" />
      </div>

      <div className="flex flex-col gap-4">
        {!insight && !loading && (
          <button 
            onClick={fetchInsights}
            className="w-full bg-white border-2 border-blue-100 p-8 rounded-3xl flex flex-col items-center gap-4 text-blue-600 hover:bg-blue-50 transition-all shadow-sm"
          >
            <div className="bg-blue-100 p-4 rounded-full">
              <Sparkles size={32} />
            </div>
            <span className="font-bold text-lg">Gerar Análise Estratégica</span>
          </button>
        )}

        {loading && (
          <div className="bg-white p-12 rounded-3xl flex flex-col items-center gap-4 shadow-sm">
            <Loader2 className="animate-spin text-blue-600" size={40} />
            <p className="text-slate-500 font-medium animate-pulse">Analisando seus dados...</p>
          </div>
        )}

        {insight && !loading && (
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 animate-fadeIn">
            <div className="flex justify-between items-center mb-4">
              <span className="text-xs font-black uppercase tracking-widest text-slate-400">Relatório de Insights</span>
              <button onClick={fetchInsights} className="text-blue-600 p-2 hover:bg-blue-50 rounded-full">
                <RefreshCw size={18} />
              </button>
            </div>
            <div className="prose prose-sm text-slate-700 leading-relaxed space-y-4">
              {insight.split('\n').map((paragraph, i) => (
                <p key={i} className={paragraph.trim() === '' ? 'h-2' : ''}>
                  {paragraph}
                </p>
              ))}
            </div>
            <div className="mt-6 p-4 bg-emerald-50 rounded-2xl border border-emerald-100">
              <p className="text-emerald-800 text-xs font-bold leading-tight">
                💡 Dica: Mantenha seus registros de vendas e estoque atualizados para insights mais precisos.
              </p>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default AIAdvisor;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import TransactionForm from './components/TransactionForm';
import InventoryView from './components/InventoryView';
import AIAdvisor from './components/AIAdvisor';
import { BusinessState, ViewType, Transaction, InventoryItem } from './types';
import { INITIAL_INVENTORY } from './constants';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [state, setState] = useState<BusinessState>(() => {
    const saved = localStorage.getItem('agua_cristalina_state');
    if (saved) return JSON.parse(saved);
    return {
      transactions: [],
      inventory: INITIAL_INVENTORY
    };
  });

  // Persist state to local storage
  useEffect(() => {
    localStorage.setItem('agua_cristalina_state', JSON.stringify(state));
  }, [state]);

  const handleAddTransaction = (newT: Omit<Transaction, 'id'>) => {
    const transaction: Transaction = {
      ...newT,
      id: Math.random().toString(36).substr(2, 9)
    };

    setState(prev => {
      // If it's a sale, we might want to automatically decrement inventory in a real app
      // For simplicity, we just add the transaction here
      return {
        ...prev,
        transactions: [...prev.transactions, transaction]
      };
    });
  };

  const updateInventory = (id: string, delta: number) => {
    setState(prev => ({
      ...prev,
      inventory: prev.inventory.map(item => 
        item.id === id ? { ...item, quantity: Math.max(0, item.quantity + delta) } : item
      )
    }));
  };

  const renderContent = () => {
    switch (activeView) {
      case 'dashboard':
        return <Dashboard state={state} />;
      case 'sales':
        return <TransactionForm type="sale" onAdd={handleAddTransaction} transactions={state.transactions} />;
      case 'expenses':
        return <TransactionForm type="expense" onAdd={handleAddTransaction} transactions={state.transactions} />;
      case 'inventory':
        return <InventoryView inventory={state.inventory} onUpdate={updateInventory} />;
      case 'ai':
        return <AIAdvisor state={state} />;
      default:
        return <Dashboard state={state} />;
    }
  };

  return (
    <Layout activeView={activeView} setActiveView={setActiveView}>
      <div className="pb-8">
        {renderContent()}
      </div>
    </Layout>
  );
};

export default App;

