        </div>

        <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex flex-col items-start">
          <div className="bg-red-100 p-2 rounded-lg text-red-600 mb-2">
            <TrendingDown size={20} />
          </div>
          <span className="text-slate-500 text-xs font-medium">Gastos</span>
          <span className="text-xl font-bold text-slate-800">R$ {expenses.toLocaleString()}</span>
        </div>

        <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex flex-col items-start col-span-2">
