              <span className={`text-2xl font-black ${balance >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                R$ {balance.toLocaleString()}
              </span>
            </div>
            <div className="bg-emerald-100 p-3 rounded-full text-emerald-600">
              <Wallet size={24} />
