                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                  formatter={(value: number) => `R$ ${value.toLocaleString()}`}
                />
                <Bar dataKey="value" fill="#3b82f6" radius={[0, 4, 4, 0]} barSize={16} />
              </BarChart>
            </ResponsiveContainer>
          ) : (
            <div className="h-full flex items-center justify-center text-slate-400 text-sm italic">
              Sem dados de venda.
            </div>
          )}
        </div>
      </div>

      {/* Inventory Alert Simple List */}
      <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100">
        <h3 className="text-slate-800 font-bold mb-3">Alertas de Estoque</h3>
        <div className="space-y-3">
          {state.inventory.filter(i => i.quantity <= i.minThreshold).length === 0 ? (
            <p className="text-slate-400 text-sm italic">Tudo em ordem no estoque.</p>
          ) : (
            state.inventory
              .filter(i => i.quantity <= i.minThreshold)
              .map(item => (
                <div key={item.id} className="flex items-center justify-between p-3 bg-red-50 rounded-xl">
                  <span className="text-red-700 text-sm font-semibold">{item.name}</span>
                  <span className="bg-red-200 text-red-700 text-xs px-2 py-1 rounded-full font-bold">
                    {item.quantity} {item.unit}
                  </span>
                </div>
              ))
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Transaction, TransactionType } from '../types';
import { Plus, X, Calendar } from 'lucide-react';
import { SALE_CATEGORIES, EXPENSE_CATEGORIES, INVESTMENT_CATEGORIES } from '../constants';

interface TransactionFormProps {
  type: TransactionType;
  onAdd: (transaction: Omit<Transaction, 'id'>) => void;
  transactions: Transaction[];
}

const TransactionForm: React.FC<TransactionFormProps> = ({ type, onAdd, transactions }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [amount, setAmount] = useState('');
  const [category, setCategory] = useState(type === 'sale' ? 'Total Diário' : '');
  const [description, setDescription] = useState('');
  const [quantity, setQuantity] = useState('1');

  const categories = type === 'sale' ? ['Total Diário', ...SALE_CATEGORIES] : 
                    type === 'expense' ? EXPENSE_CATEGORIES : 
                    INVESTMENT_CATEGORIES;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !category) return;

    onAdd({
      date: new Date().toISOString(),
      type,
      category,
      amount: parseFloat(amount),
      description: type === 'sale' ? (description || 'Venda consolidada do dia') : description,
      quantity: parseInt(quantity)
    });

    setAmount('');
    setCategory(type === 'sale' ? 'Total Diário' : '');
    setDescription('');
    setQuantity('1');
    setIsOpen(false);
  };

  // Grouping logic for sales to show daily totals in the list
  const groupedSales = useMemo(() => {
    if (type !== 'sale') return null;

    const groups: Record<string, { total: number, count: number, date: string }> = {};

    transactions
      .filter(t => t.type === 'sale')
      .forEach(t => {
        const dateStr = new Date(t.date).toLocaleDateString();
        if (!groups[dateStr]) {
          groups[dateStr] = { total: 0, count: 0, date: t.date };
        }
        groups[dateStr].total += t.amount;
        groups[dateStr].count += 1;
      });

    return Object.entries(groups).sort((a, b) => new Date(b[1].date).getTime() - new Date(a[1].date).getTime());
  }, [transactions, type]);

  const filteredTransactions = transactions.filter(t => t.type === type).reverse();

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold text-slate-800 capitalize">
          {type === 'sale' ? 'Vendas Diárias' : type === 'expense' ? 'Gastos Registrados' : 'Investimentos'}
        </h2>
        <button 
          onClick={() => setIsOpen(true)}
          className="bg-blue-600 text-white p-2 rounded-full shadow-lg hover:bg-blue-700 transition-colors"
        >
          <Plus size={24} />
        </button>
      </div>

      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-3xl p-6 shadow-2xl animate-scaleIn">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-lg font-bold text-slate-800">
                {type === 'sale' ? 'Lançar Total do Dia' : `Novo ${type === 'expense' ? 'Gasto' : 'Investimento'}`}
              </h3>
              <button onClick={() => setIsOpen(false)} className="text-slate-400">
                <X size={24} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-400 mb-1 uppercase">Categoria</label>
                <select 
                  value={category} 
                  onChange={e => setCategory(e.target.value)}
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
                  required
                >
                  <option value="">Selecione...</option>
                  {categories.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-400 mb-1 uppercase">Valor Total (R$)</label>
                <input 
                  type="number" 
                  step="0.01"
                  value={amount}
                  onChange={e => setAmount(e.target.value)}
                  placeholder="0,00"
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500 text-xl font-bold"
                  required
                />
              </div>

              {type !== 'sale' && (
                <div>
                  <label className="block text-xs font-bold text-slate-400 mb-1 uppercase">Observação</label>
                  <input 
                    type="text" 
                    value={description}
                    onChange={e => setDescription(e.target.value)}
                    placeholder="Descrição do registro"
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
              )}

              <button 
                type="submit"
                className="w-full bg-blue-600 text-white font-bold py-4 rounded-xl shadow-lg hover:bg-blue-700 transition-all active:scale-95"
              >
                Salvar Registro
              </button>
            </form>
          </div>
        </div>
      )}

      <div className="space-y-3">
        {type === 'sale' && groupedSales ? (
          groupedSales.length === 0 ? (
            <div className="bg-white border-2 border-dashed border-slate-200 rounded-2xl p-8 text-center text-slate-400 text-sm">
              Nenhuma venda registrada este mês.
            </div>
          ) : (
            groupedSales.map(([dateStr, data]) => (
              <div key={dateStr} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="bg-blue-50 p-2 rounded-xl text-blue-600">
                    <Calendar size={18} />
                  </div>
                  <div className="flex flex-col">
                    <span className="font-bold text-slate-800">{dateStr}</span>
                    <span className="text-[10px] text-slate-400 uppercase font-bold">{data.count} Lançamento(s)</span>
                  </div>
                </div>
                <div className="flex flex-col items-end">
                  <span className="font-black text-blue-600">
                    + R$ {data.total.toFixed(2)}
                  </span>
                </div>
              </div>
            ))
          )
        ) : (
          filteredTransactions.length === 0 ? (
            <div className="bg-white border-2 border-dashed border-slate-200 rounded-2xl p-8 text-center text-slate-400 text-sm">
              Nenhum registro encontrado.
            </div>
          ) : (
            filteredTransactions.map(t => (
              <div key={t.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between">
                <div className="flex flex-col">
                  <span className="font-bold text-slate-800">{t.category}</span>
                  <span className="text-xs text-slate-400">{new Date(t.date).toLocaleDateString()} • {t.description || 'Sem obs.'}</span>
                </div>
                <div className="flex flex-col items-end">
                  <span className={`font-black ${type === 'sale' ? 'text-blue-600' : 'text-red-500'}`}>
                    {type === 'sale' ? '+' : '-'} R$ {t.amount.toFixed(2)}
                  </span>
                </div>
              </div>
            ))
          )
        )}
      </div>
    </div>
  );
};

export default TransactionForm;

