import React, { useState, useMemo } from 'react';
import { Transaction, TransactionType } from '../types';
import { Plus, X, Calendar, TrendingDown, Landmark, Info } from 'lucide-react';
import { SALE_CATEGORIES, EXPENSE_CATEGORIES, INVESTMENT_CATEGORIES } from '../constants';

interface TransactionFormProps {
  type: TransactionType;
  onAdd: (transaction: Omit<Transaction, 'id'>) => void;
  transactions: Transaction[];
  onSubViewChange?: (type: 'expense' | 'investment') => void;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ type, onAdd, transactions }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [amount, setAmount] = useState('');
  const [subType, setSubType] = useState<'expense' | 'investment'>(type === 'sale' ? 'expense' : type as any);
  const [category, setCategory] = useState(type === 'sale' ? 'Total Diário' : '');
  const [description, setDescription] = useState('');
  const [quantity, setQuantity] = useState('1');

  // Logic to handle tab switching specifically for the "Gastos" main tab
  const activeType = type === 'sale' ? 'sale' : subType;

  const categories = activeType === 'sale' ? ['Total Diário', ...SALE_CATEGORIES] : 
                    activeType === 'expense' ? EXPENSE_CATEGORIES : 
                    INVESTMENT_CATEGORIES;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !category) return;

    onAdd({
      date: new Date().toISOString(),
      type: activeType as TransactionType,
      category,
      amount: parseFloat(amount),
      description: activeType === 'sale' ? (description || 'Venda consolidada do dia') : description,
      quantity: parseInt(quantity)
    });

    setAmount('');
    setCategory(activeType === 'sale' ? 'Total Diário' : '');
    setDescription('');
    setQuantity('1');
    setIsOpen(false);
  };

  // Totals for the summary cards
  const totalInvested = useMemo(() => {
    return transactions
      .filter(t => t.type === 'investment')
      .reduce((sum, t) => sum + t.amount, 0);
  }, [transactions]);

  const totalExpenses = useMemo(() => {
    return transactions
      .filter(t => t.type === 'expense')
      .reduce((sum, t) => sum + t.amount, 0);
  }, [transactions]);

  // Grouping logic for sales
  const groupedSales = useMemo(() => {
    if (type !== 'sale') return null;
    const groups: Record<string, { total: number, count: number, date: string }> = {};
    transactions
      .filter(t => t.type === 'sale')
      .forEach(t => {
        const dateStr = new Date(t.date).toLocaleDateString();
        if (!groups[dateStr]) {
          groups[dateStr] = { total: 0, count: 0, date: t.date };
        }
        groups[dateStr].total += t.amount;
        groups[dateStr].count += 1;
      });
    return Object.entries(groups).sort((a, b) => new Date(b[1].date).getTime() - new Date(a[1].date).getTime());
  }, [transactions, type]);

  const filteredTransactions = transactions.filter(t => t.type === activeType).reverse();

  return (
    <div className="space-y-4">
      {/* Header and Sub-navigation for Gastos */}
      <div className="flex flex-col gap-4">
        <div className="flex items-center justify-between">
          <h2 className="text-xl font-bold text-slate-800">
            {type === 'sale' ? 'Vendas Diárias' : 'Gestão Financeira'}
          </h2>
          <button 
            onClick={() => {
              // Ensure category is reset correctly based on active subtab
              setCategory(activeType === 'sale' ? 'Total Diário' : '');
              setIsOpen(true);
            }}
            className="bg-blue-600 text-white p-2 rounded-full shadow-lg hover:bg-blue-700 transition-colors"
          >
            <Plus size={24} />
          </button>
        </div>

        {type !== 'sale' && (
          <div className="flex bg-slate-200/50 p-1 rounded-xl">
            <button 
              onClick={() => { setSubType('expense'); setCategory(''); }}
              className={`flex-1 py-2 px-4 rounded-lg text-sm font-bold transition-all flex items-center justify-center gap-2 ${subType === 'expense' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}
            >
              <TrendingDown size={16} />
              Saídas
            </button>
            <button 
              onClick={() => { setSubType('investment'); setCategory(''); }}
              className={`flex-1 py-2 px-4 rounded-lg text-sm font-bold transition-all flex items-center justify-center gap-2 ${subType === 'investment' ? 'bg-white text-amber-600 shadow-sm' : 'text-slate-500'}`}
            >
              <Landmark size={16} />
              Investimentos
            </button>
          </div>
        )}
      </div>

      {/* Summary Cards */}
      {type !== 'sale' && (
        <div className={`p-4 rounded-2xl border flex flex-col gap-1 shadow-sm transition-all ${subType === 'investment' ? 'bg-amber-50 border-amber-100' : 'bg-red-50 border-red-100'}`}>
