            <Info size={12} />
            {subType === 'investment' ? 'Acumulado desde o início' : 'Total de Saídas Registradas'}
          </div>
          <div className={`text-2xl font-black ${subType === 'investment' ? 'text-amber-700' : 'text-red-700'}`}>
            R$ {(subType === 'investment' ? totalInvested : totalExpenses).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
          </div>
          {subType === 'investment' && (
            <p className="text-[10px] text-amber-600 font-medium italic">Todo capital investido no crescimento da Agua Cristalina.</p>
          )}
        </div>
      )}

      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-3xl p-6 shadow-2xl animate-scaleIn">
