              <button 
                type="submit"
                className={`w-full text-white font-bold py-4 rounded-xl shadow-lg transition-all active:scale-95 ${activeType === 'investment' ? 'bg-amber-600 hover:bg-amber-700' : 'bg-blue-600 hover:bg-blue-700'}`}
              >
                Salvar Registro
              </button>
            </form>
          </div>
        </div>
      )}

      {/* List Area */}
      <div className="space-y-3">
        {activeType === 'sale' && groupedSales ? (
          groupedSales.length === 0 ? (
            <div className="bg-white border-2 border-dashed border-slate-200 rounded-2xl p-8 text-center text-slate-400 text-sm">
              Nenhuma venda registrada.
            </div>
