import { GoogleGenAI } from "@google/genai";
import { BusinessState } from "../types";

export const getBusinessInsights = async (state: BusinessState): Promise<string> => {
  // Always use a named parameter and direct environment variable for API Key initialization.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const salesTotal = state.transactions
    .filter(t => t.type === 'sale')
    .reduce((acc, t) => acc + t.amount, 0);

  const expensesTotal = state.transactions
    .filter(t => t.type === 'expense')
    .reduce((acc, t) => acc + t.amount, 0);

  const investmentTotal = state.transactions
    .filter(t => t.type === 'investment')
    .reduce((acc, t) => acc + t.amount, 0);

  const netProfit = salesTotal - expensesTotal - investmentTotal;

  const prompt = `
    Como consultor especialista em negócios de água purificada (Marca: Agua Cristalina), analise os seguintes dados financeiros e de estoque:
    - Vendas Totais: R$ ${salesTotal.toFixed(2)}
    - Gastos (Saídas): R$ ${expensesTotal.toFixed(2)}
    - Investimentos: R$ ${investmentTotal.toFixed(2)}
    - Lucro Líquido Real (Vendas - Gastos - Investimentos): R$ ${netProfit.toFixed(2)}
    - Número de Transações: ${state.transactions.length}
    - Status do Estoque: ${state.inventory.map(i => `${i.name}: ${i.quantity}${i.unit}`).join(', ')}

    Por favor, forneça:
    1. Uma análise rápida da saúde financeira (está no lucro ou prejuízo após considerar todos os custos e investimentos?).
    2. Duas sugestões práticas para aumentar as vendas ou otimizar os investimentos na operação de água.
    3. Alerta de estoque se algo estiver baixo.

    Responda em Português de forma motivadora e profissional, adequada para leitura rápida em celular.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
        topP: 0.95,
      }
    });

    // Directly access the text property from the response object.
    return response.text || "Desculpe, não consegui gerar uma análise no momento. Tente novamente mais tarde.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Erro ao conectar com a inteligência artificial. Verifique sua conexão.";
  }
};

export type TransactionType = 'sale' | 'expense' | 'investment';

export interface Transaction {
  id: string;
  date: string;
  type: TransactionType;
  category: string;
  amount: number;
  description: string;
  quantity?: number;
}

export interface InventoryItem {
  id: string;
  name: string;
  quantity: number;
  unit: string;
  minThreshold: number;
}

export interface InventoryMovement {
  id: string;
  itemId: string;
  itemName: string;
  quantity: number;
  date: string; // ISO string
}

export interface BusinessState {
  transactions: Transaction[];
  inventory: InventoryItem[];
  inventoryMovements: InventoryMovement[];
}

export type ViewType = 'dashboard' | 'sales' | 'expenses' | 'inventory' | 'ai';

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import TransactionForm from './components/TransactionForm';
import InventoryView from './components/InventoryView';
import AIAdvisor from './components/AIAdvisor';
import { BusinessState, ViewType, Transaction, InventoryItem, InventoryMovement } from './types';
import { INITIAL_INVENTORY } from './constants';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [state, setState] = useState<BusinessState>(() => {
    const saved = localStorage.getItem('agua_cristalina_state');
    if (saved) {
      const parsed = JSON.parse(saved);
      // Ensure inventoryMovements exists for backward compatibility
      if (!parsed.inventoryMovements) parsed.inventoryMovements = [];
      return parsed;
    }
    return {
      transactions: [],
      inventory: INITIAL_INVENTORY,
      inventoryMovements: []
    };
  });

  // Persist state to local storage
  useEffect(() => {
    localStorage.setItem('agua_cristalina_state', JSON.stringify(state));
  }, [state]);

  const handleAddTransaction = (newT: Omit<Transaction, 'id'>) => {
    const transaction: Transaction = {
      ...newT,
      id: Math.random().toString(36).substr(2, 9)
    };

    setState(prev => {
      return {
        ...prev,
        transactions: [...prev.transactions, transaction]
      };
    });
  };

  const updateInventory = (id: string, delta: number) => {
    setState(prev => {
      const item = prev.inventory.find(i => i.id === id);
      const newMovements = [...prev.inventoryMovements];

      // Se delta for negativo, é uma saída de estoque
      if (delta < 0 && item) {
        const movement: InventoryMovement = {
          id: Math.random().toString(36).substr(2, 9),
          itemId: id,
          itemName: item.name,
          quantity: Math.abs(delta),
          date: new Date().toISOString()
        };
        newMovements.push(movement);
      }

      return {
        ...prev,
        inventory: prev.inventory.map(item => 
          item.id === id ? { ...item, quantity: Math.max(0, item.quantity + delta) } : item
        ),
        inventoryMovements: newMovements
      };
    });
  };

  const renderContent = () => {
    switch (activeView) {
      case 'dashboard':
        return <Dashboard state={state} />;
      case 'sales':
        return <TransactionForm type="sale" onAdd={handleAddTransaction} transactions={state.transactions} />;
      case 'expenses':
        return <TransactionForm type="expense" onAdd={handleAddTransaction} transactions={state.transactions} />;
      case 'inventory':
        return <InventoryView inventory={state.inventory} movements={state.inventoryMovements} onUpdate={updateInventory} />;
      case 'ai':
        return <AIAdvisor state={state} />;
      default:
        return <Dashboard state={state} />;
    }
  };

  return (
    <Layout activeView={activeView} setActiveView={setActiveView}>
      <div className="pb-8">
        {renderContent()}
      </div>
    </Layout>
  );
};

export default App;

