import React, { useState, useMemo } from 'react';
import { Transaction, TransactionType } from '../types';
import { Plus, X, Calendar, TrendingDown, Landmark, Info } from 'lucide-react';
import { SALE_CATEGORIES, EXPENSE_CATEGORIES, INVESTMENT_CATEGORIES } from '../constants';

interface TransactionFormProps {
  type: TransactionType;
  onAdd: (transaction: Omit<Transaction, 'id'>) => void;
  transactions: Transaction[];
}

const TransactionForm: React.FC<TransactionFormProps> = ({ type, onAdd, transactions }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [amount, setAmount] = useState('');
  const [subType, setSubType] = useState<'expense' | 'investment'>(type === 'sale' ? 'expense' : type as any);
  const [category, setCategory] = useState(type === 'sale' ? 'Total Diário' : '');
  const [description, setDescription] = useState('');

  const activeType = type === 'sale' ? 'sale' : subType;
  const categories = activeType === 'sale' ? ['Total Diário', ...SALE_CATEGORIES] : 
                    activeType === 'expense' ? EXPENSE_CATEGORIES : 
                    INVESTMENT_CATEGORIES;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !category) return;

    onAdd({
      date: new Date().toISOString(),
      type: activeType as TransactionType,
      category,
      amount: parseFloat(amount),
      description: activeType === 'sale' ? (description || 'Venda consolidada do dia') : description,
      quantity: 1
    });

    setAmount('');
    setCategory(activeType === 'sale' ? 'Total Diário' : '');
    setDescription('');
    setIsOpen(false);
  };

  const totalInvested = useMemo(() => transactions.filter(t => t.type === 'investment').reduce((sum, t) => sum + t.amount, 0), [transactions]);
  const totalExpenses = useMemo(() => transactions.filter(t => t.type === 'expense').reduce((sum, t) => sum + t.amount, 0), [transactions]);

  const groupedSales = useMemo(() => {
    if (type !== 'sale') return null;
    const groups: Record<string, { total: number, count: number, date: string }> = {};
    transactions.filter(t => t.type === 'sale').forEach(t => {
      const dateStr = new Date(t.date).toLocaleDateString();
      if (!groups[dateStr]) groups[dateStr] = { total: 0, count: 0, date: t.date };
      groups[dateStr].total += t.amount;
      groups[dateStr].count += 1;
    });
    return Object.entries(groups).sort((a, b) => new Date(b[1].date).getTime() - new Date(a[1].date).getTime());
  }, [transactions, type]);

  const filteredTransactions = transactions.filter(t => t.type === activeType).reverse();

  return (
    <div className="space-y-4">
      <div className="flex flex-col gap-4">
        <div className="flex items-center justify-between">
          <h2 className="text-xl font-bold text-slate-800">{type === 'sale' ? 'Vendas Diárias' : 'Gestão Financeira'}</h2>
          <button onClick={() => setIsOpen(true)} className="bg-blue-600 text-white p-2 rounded-full shadow-lg"><Plus size={24} /></button>
        </div>

        {type !== 'sale' && (
          <div className="flex bg-slate-200/50 p-1 rounded-xl">
            <button onClick={() => setSubType('expense')} className={`flex-1 py-2 px-4 rounded-lg text-xs font-bold transition-all flex items-center justify-center gap-2 ${subType === 'expense' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><TrendingDown size={14} /> Saídas</button>
            <button onClick={() => setSubType('investment')} className={`flex-1 py-2 px-4 rounded-lg text-xs font-bold transition-all flex items-center justify-center gap-2 ${subType === 'investment' ? 'bg-white text-amber-600 shadow-sm' : 'text-slate-500'}`}><Landmark size={14} /> Investimentos</button>
          </div>
        )}
      </div>

      {type !== 'sale' && (
        <div className={`p-4 rounded-2xl border flex flex-col gap-1 shadow-sm transition-all ${subType === 'investment' ? 'bg-amber-50 border-amber-100' : 'bg-red-50 border-red-100'}`}>
          <div className="flex items-center gap-2 text-slate-500 text-[10px] font-bold uppercase tracking-wider"><Info size={12} /> {subType === 'investment' ? 'Acumulado desde o início' : 'Total de Saídas'}</div>
          <div className={`text-xl font-black ${subType === 'investment' ? 'text-amber-700' : 'text-red-700'}`}>{(subType === 'investment' ? totalInvested : totalExpenses).toLocaleString()} Kz</div>
        </div>
      )}

      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-3xl p-6 shadow-2xl animate-scaleIn">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-lg font-bold text-slate-800">{activeType === 'sale' ? 'Lançar Venda' : activeType === 'expense' ? 'Nova Saída' : 'Novo Investimento'}</h3>
              <button onClick={() => setIsOpen(false)} className="text-slate-400"><X size={24} /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-400 mb-1 uppercase">Categoria</label>
                <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-slate-700 focus:outline-none" required>
                  <option value="">Selecione...</option>
                  {categories.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-400 mb-1 uppercase">Valor (Kz)</label>
                <input type="number" step="0.01" value={amount} onChange={e => setAmount(e.target.value)} placeholder="0,00" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-slate-700 text-xl font-bold focus:outline-none" required />
              </div>
              <button type="submit" className={`w-full text-white font-bold py-4 rounded-xl shadow-lg ${activeType === 'investment' ? 'bg-amber-600' : 'bg-blue-600'}`}>Salvar Registro</button>
            </form>
          </div>
        </div>
      )}

      <div className="space-y-3">
        {activeType === 'sale' && groupedSales ? (
          groupedSales.map(([dateStr, data]) => (
            <div key={dateStr} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="bg-blue-50 p-2 rounded-xl text-blue-600"><Calendar size={18} /></div>
                <div className="flex flex-col"><span className="font-bold text-slate-800">{dateStr}</span><span className="text-[10px] text-slate-400 uppercase font-bold">{data.count} lançamentos</span></div>
              </div>
              <div className="flex flex-col items-end"><span className="font-black text-blue-600">+ {data.total.toFixed(2)} Kz</span></div>
            </div>
          ))
        ) : (
          filteredTransactions.map(t => (
            <div key={t.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className={`p-2 rounded-xl ${activeType === 'investment' ? 'bg-amber-50 text-amber-600' : 'bg-red-50 text-red-600'}`}>{activeType === 'investment' ? <Landmark size={18} /> : <TrendingDown size={18} />}</div>
                <div className="flex flex-col"><span className="font-bold text-slate-800">{t.category}</span><span className="text-xs text-slate-400">{new Date(t.date).toLocaleDateString()}</span></div>
              </div>
              <div className="flex flex-col items-end"><span className={`font-black ${activeType === 'investment' ? 'text-amber-600' : 'text-red-500'}`}>- {t.amount.toFixed(2)} Kz</span></div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default TransactionForm;

