      {/* Resumo de Saídas Diárias */}
      <div className="bg-blue-600 p-5 rounded-3xl text-white shadow-lg overflow-hidden relative">
        <div className="relative z-10">
          <h3 className="text-sm font-bold opacity-80 mb-3 flex items-center gap-2 uppercase tracking-widest">
            <History size={16} /> Saídas de Hoje
