            {inventory.map(item => (
              <div key={item.id} className="flex flex-col">
                <span className="text-[10px] opacity-70 font-bold truncate">{item.name}</span>
                <span className="text-lg font-black">{dailyOutputs[item.id] || 0} {item.unit}</span>
