              <div className="flex justify-between items-start">
                <div className="flex items-center gap-2">
                  <span className="font-bold text-slate-800">{item.name}</span>
                  {isLow && <AlertCircle size={16} className="text-red-500" />}
                </div>
                <span className={`px-3 py-1 rounded-full text-xs font-bold ${isLow ? 'bg-red-100 text-red-700' : 'bg-blue-50 text-blue-700'}`}>
                  {item.quantity} {item.unit}
                </span>
              </div>

              <div className="flex gap-2">
                <button 
                  onClick={() => onUpdate(item.id, -1)}
                  className="flex-1 bg-slate-100 py-2 rounded-xl text-slate-600 hover:bg-slate-200 active:scale-95 transition-all flex justify-center"
                >
                  <Minus size={20} />
                </button>
                <button 
                  onClick={() => onUpdate(item.id, 1)}
                  className="flex-1 bg-blue-600 py-2 rounded-xl text-white hover:bg-blue-700 active:scale-95 transition-all flex justify-center"
                >
                  <Plus size={20} />
                </button>
              </div>

              {isLow && (
                <div className="text-[10px] text-red-500 font-bold uppercase tracking-wider animate-pulse text-center mt-1">
                  Reabastecer (Mínimo: {item.minThreshold})
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default InventoryView;

import { GoogleGenAI } from "@google/genai";
import { BusinessState } from "../types";

export const getBusinessInsights = async (state: BusinessState): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const salesTotal = state.transactions
    .filter(t => t.type === 'sale')
    .reduce((acc, t) => acc + t.amount, 0);

  const expensesTotal = state.transactions
    .filter(t => t.type === 'expense')
    .reduce((acc, t) => acc + t.amount, 0);

  const investmentTotal = state.transactions
    .filter(t => t.type === 'investment')
    .reduce((acc, t) => acc + t.amount, 0);

  const netProfit = salesTotal - expensesTotal - investmentTotal;

  const prompt = `
    Como consultor especialista em negócios de água purificada (Marca: Agua Cristalina), analise os seguintes dados (Valores em Kwanza - Kz):
    - Vendas Totais: ${salesTotal.toFixed(2)} Kz
    - Gastos (Saídas): ${expensesTotal.toFixed(2)} Kz
    - Investimentos: ${investmentTotal.toFixed(2)} Kz
    - Lucro Líquido Real: ${netProfit.toFixed(2)} Kz
    - Status do Estoque: ${state.inventory.map(i => `${i.name}: ${i.quantity}${i.unit}`).join(', ')}

    Por favor, forneça:
    1. Uma análise da saúde financeira considerando a realidade angolana.
    2. Duas sugestões práticas para aumentar as vendas ou otimizar custos.
    3. Alerta de estoque crítico se necessário.

    Responda em Português de forma motivadora e profissional.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { temperature: 0.7, topP: 0.95 }
    });
    return response.text || "Desculpe, não consegui gerar uma análise.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Erro ao conectar com a IA.";
  }
};

import React, { useMemo, useState } from 'react';
import { InventoryItem, InventoryMovement } from '../types';
import { Plus, Minus, AlertCircle, History, ChevronLeft, ChevronRight, Calendar as CalendarIcon } from 'lucide-react';

interface InventoryViewProps {
  inventory: InventoryItem[];
  movements: InventoryMovement[];
  onUpdate: (id: string, delta: number) => void;
}

const InventoryView: React.FC<InventoryViewProps> = ({ inventory, movements, onUpdate }) => {
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);

  // Navegação de dias
  const changeDate = (days: number) => {
    const current = new Date(selectedDate + 'T12:00:00'); // Evita problemas de fuso horário
    current.setDate(current.getDate() + days);
    setSelectedDate(current.toISOString().split('T')[0]);
  };

  // Calcular saídas da data selecionada por produto
  const filteredOutputs = useMemo(() => {
    const map: Record<string, number> = {};

    movements.forEach(m => {
      const movementDate = new Date(m.date).toISOString().split('T')[0];
      if (movementDate === selectedDate) {
        map[m.itemId] = (map[m.itemId] || 0) + m.quantity;
      }
    });
    return map;
  }, [movements, selectedDate]);

  const isToday = selectedDate === new Date().toISOString().split('T')[0];
  const formattedDisplayDate = new Date(selectedDate + 'T12:00:00').toLocaleDateString('pt-BR', {
    day: '2-digit',
    month: 'long',
  });

  return (
    <div className="space-y-6 animate-fadeIn">
      <div>
        <h2 className="text-xl font-bold text-slate-800">Controle de Estoque</h2>
        <p className="text-slate-500 text-sm">Gerencie seus insumos em tempo real.</p>
      </div>

      {/* Seção de Saídas Filtrável */}
      <div className="bg-blue-600 rounded-3xl text-white shadow-lg overflow-hidden relative">
        <div className="p-5 relative z-10">
          <div className="flex justify-between items-center mb-4">
            <h3 className="text-[10px] font-black opacity-80 flex items-center gap-2 uppercase tracking-widest">
              <History size={14} /> Saídas por Dia
            </h3>
            <div className="flex items-center bg-white/10 rounded-full px-2 py-1 backdrop-blur-md border border-white/20">
              <button onClick={() => changeDate(-1)} className="p-1 hover:bg-white/20 rounded-full transition-colors">
                <ChevronLeft size={16} />
              </button>
              <div className="flex items-center gap-2 px-2">
                <input 
                  type="date" 
                  value={selectedDate} 
                  onChange={(e) => setSelectedDate(e.target.value)}
                  className="bg-transparent text-[10px] font-bold focus:outline-none appearance-none cursor-pointer uppercase"
                />
              </div>
              <button 
                onClick={() => changeDate(1)} 
                disabled={isToday}
                className={`p-1 rounded-full transition-colors ${isToday ? 'opacity-30' : 'hover:bg-white/20'}`}
              >
                <ChevronRight size={16} />
              </button>
            </div>
          </div>

          <div className="mb-4">
            <span className="text-2xl font-black block">
              {isToday ? 'Hoje' : formattedDisplayDate}
            </span>
            <span className="text-[10px] opacity-70 font-bold uppercase tracking-tighter">
              {Object.values(filteredOutputs).length > 0 ? 'Total de movimentações registradas' : 'Sem saídas nesta data'}
            </span>
          </div>

          <div className="grid grid-cols-2 gap-3">
            {inventory.map(item => (
              <div key={item.id} className="bg-white/10 border border-white/10 p-3 rounded-2xl backdrop-blur-sm">
                <span className="text-[9px] opacity-70 font-bold truncate block mb-1">{item.name}</span>
                <span className="text-lg font-black">{filteredOutputs[item.id] || 0} <span className="text-[10px] font-normal opacity-60">{item.unit}</span></span>
              </div>
            ))}
          </div>
        </div>
        <History size={120} className="absolute -right-8 -bottom-8 opacity-10" />
      </div>

      {/* Lista de Produtos para Gerenciamento */}
      <div className="space-y-3">
        <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider px-1">Produtos em Estoque</h3>
        {inventory.map(item => {
          const isLow = item.quantity <= item.minThreshold;
          return (
            <div key={item.id} className={`p-4 rounded-2xl bg-white border shadow-sm flex flex-col gap-3 transition-all ${isLow ? 'border-red-200 ring-1 ring-red-50' : 'border-slate-100'}`}>
              <div className="flex justify-between items-start">
                <div className="flex items-center gap-2">
                  <div className={`w-2 h-2 rounded-full ${isLow ? 'bg-red-500' : 'bg-green-500'}`}></div>
                  <span className="font-bold text-slate-800 text-sm">{item.name}</span>
                </div>
                <div className="flex flex-col items-end">
                  <span className={`px-3 py-1 rounded-full text-[10px] font-black ${isLow ? 'bg-red-100 text-red-700' : 'bg-blue-50 text-blue-700'}`}>
                    {item.quantity} {item.unit}
                  </span>
                  {isLow && <span className="text-[8px] text-red-500 font-bold mt-1 uppercase">Abaixo do mínimo</span>}
                </div>
              </div>

              <div className="flex gap-2">
                <button 
                  onClick={() => onUpdate(item.id, -1)}
                  className="flex-1 bg-slate-50 py-3 rounded-xl text-slate-600 hover:bg-slate-100 active:scale-95 transition-all flex justify-center border border-slate-100"
                >
                  <Minus size={18} />
                </button>
                <button 
                  onClick={() => onUpdate(item.id, 1)}
                  className="flex-1 bg-blue-600 py-3 rounded-xl text-white hover:bg-blue-700 active:scale-95 transition-all flex justify-center shadow-md shadow-blue-200"
                >
                  <Plus size={18} />
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

