import React, { useState, useMemo } from 'react';
import { BusinessState, Transaction, InventoryMovement } from '../types';
import AIAdvisor from './AIAdvisor';
import { 
  History, 
  Package, 
  Sparkles, 
  ArrowUpRight, 
  ArrowDownLeft, 
  Landmark,
  Calendar,
  Filter
} from 'lucide-react';

interface ReportsViewProps {
  state: BusinessState;
}

type ReportTab = 'transactions' | 'inventory' | 'ai';

const ReportsView: React.FC<ReportsViewProps> = ({ state }) => {
  const [activeTab, setActiveTab] = useState<ReportTab>('transactions');
  const [filterType, setFilterType] = useState<'all' | 'sale' | 'expense' | 'investment'>('all');

  const filteredTransactions = useMemo(() => {
    return state.transactions
      .filter(t => filterType === 'all' || t.type === filterType)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [state.transactions, filterType]);

  const inventorySummary = useMemo(() => {
    const summary: Record<string, { totalOut: number; name: string; unit: string }> = {};
    state.inventory.forEach(item => {
      summary[item.id] = { totalOut: 0, name: item.name, unit: item.unit };
    });
    state.inventoryMovements.forEach(m => {
      if (summary[m.itemId]) {
        summary[m.itemId].totalOut += m.quantity;
      }
    });
    return Object.values(summary).sort((a, b) => b.totalOut - a.totalOut);
  }, [state.inventory, state.inventoryMovements]);

  const recentMovements = useMemo(() => {
    return [...state.inventoryMovements].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [state.inventoryMovements]);

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex flex-col gap-1">
        <h2 className="text-2xl font-black text-slate-800 tracking-tight">Relatórios</h2>
        <p className="text-slate-500 text-sm">Visão geral do desempenho da Agua Cristalina.</p>
      </div>

      {/* Tabs */}
      <div className="flex bg-slate-200/50 p-1 rounded-2xl">
        <button 
          onClick={() => setActiveTab('transactions')}
          className={`flex-1 py-3 rounded-xl text-xs font-bold transition-all flex items-center justify-center gap-2 ${activeTab === 'transactions' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}
        >
          <History size={16} /> Histórico
        </button>
        <button 
          onClick={() => setActiveTab('inventory')}
          className={`flex-1 py-3 rounded-xl text-xs font-bold transition-all flex items-center justify-center gap-2 ${activeTab === 'inventory' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}
        >
          <Package size={16} /> Estoque
        </button>
        <button 
          onClick={() => setActiveTab('ai')}
          className={`flex-1 py-3 rounded-xl text-xs font-bold transition-all flex items-center justify-center gap-2 ${activeTab === 'ai' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}
        >
          <Sparkles size={16} /> IA
        </button>
      </div>

      {activeTab === 'transactions' && (
        <div className="space-y-4">
          <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1">
            {(['all', 'sale', 'expense', 'investment'] as const).map(type => (
              <button
                key={type}
                onClick={() => setFilterType(type)}
                className={`px-4 py-2 rounded-full text-[10px] font-bold whitespace-nowrap transition-all border ${
                  filterType === type 
                  ? 'bg-blue-600 text-white border-blue-600 shadow-md' 
                  : 'bg-white text-slate-500 border-slate-200'
                }`}
              >
                {type === 'all' ? 'TUDO' : type === 'sale' ? 'VENDAS' : type === 'expense' ? 'SAÍDAS' : 'INVESTIMENTOS'}
              </button>
            ))}
          </div>

          <div className="space-y-3">
            {filteredTransactions.length === 0 ? (
              <div className="bg-white p-12 rounded-3xl border-2 border-dashed border-slate-200 text-center text-slate-400 text-sm">
                Nenhuma transação encontrada.
              </div>
            ) : (
              filteredTransactions.map(t => (
                <div key={t.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className={`p-2 rounded-xl ${
                      t.type === 'sale' ? 'bg-green-50 text-green-600' : 
                      t.type === 'expense' ? 'bg-red-50 text-red-600' : 
                      'bg-amber-50 text-amber-600'
                    }`}>
                      {t.type === 'sale' ? <ArrowUpRight size={18} /> : 
                       t.type === 'expense' ? <ArrowDownLeft size={18} /> : 
                       <Landmark size={18} />}
                    </div>
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-800 text-sm">{t.category}</span>
                      <span className="text-[10px] text-slate-400 flex items-center gap-1">
                        <Calendar size={10} /> {new Date(t.date).toLocaleDateString()} • {t.description || 'Geral'}
                      </span>
                    </div>
                  </div>
                  <div className="text-right">
                    <span className={`font-black text-sm ${
                      t.type === 'sale' ? 'text-green-600' : 
                      t.type === 'expense' ? 'text-red-600' : 
                      'text-amber-600'
                    }`}>
                      {t.type === 'sale' ? '+' : '-'} {t.amount.toLocaleString()} Kz
                    </span>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {activeTab === 'inventory' && (
        <div className="space-y-6">
          <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Resumo Geral de Saídas</h3>
            <div className="space-y-4">
              {inventorySummary.map(item => (
                <div key={item.name} className="flex flex-col gap-1">
                  <div className="flex justify-between items-center text-xs">
                    <span className="font-bold text-slate-700">{item.name}</span>
                    <span className="font-black text-blue-600">{item.totalOut} {item.unit} saíram</span>
                  </div>
                  <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
                    <div 
                      className="bg-blue-500 h-full rounded-full transition-all duration-1000"
                      style={{ width: `${Math.min(100, (item.totalOut / 100) * 100)}%` }}
                    ></div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="space-y-3">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest px-1">Log de Movimentações</h3>
            {recentMovements.length === 0 ? (
              <div className="bg-white p-12 rounded-3xl border-2 border-dashed border-slate-200 text-center text-slate-400 text-sm">
                Nenhum movimento registrado.
              </div>
            ) : (
              recentMovements.map(m => (
                <div key={m.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className="p-2 rounded-xl bg-slate-50 text-slate-400">
                      <ArrowDownLeft size={16} />
                    </div>
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-800 text-sm">{m.itemName}</span>
                      <span className="text-[10px] text-slate-400 flex items-center gap-1">
                        <Calendar size={10} /> {new Date(m.date).toLocaleString()}
                      </span>
                    </div>
                  </div>
                  <span className="font-black text-slate-800 text-sm">
                    {m.quantity} un
                  </span>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {activeTab === 'ai' && (
        <AIAdvisor state={state} />
      )}
    </div>
  );
};

export default ReportsView;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import TransactionForm from './components/TransactionForm';
import InventoryView from './components/InventoryView';
import ReportsView from './components/ReportsView';
import { BusinessState, ViewType, Transaction, InventoryItem, InventoryMovement } from './types';
import { INITIAL_INVENTORY } from './constants';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [state, setState] = useState<BusinessState>(() => {
    const saved = localStorage.getItem('agua_cristalina_state');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (!parsed.inventoryMovements) parsed.inventoryMovements = [];
      return parsed;
    }
    return {
      transactions: [],
      inventory: INITIAL_INVENTORY,
      inventoryMovements: []
    };
  });

  useEffect(() => {
    localStorage.setItem('agua_cristalina_state', JSON.stringify(state));
  }, [state]);

  const handleAddTransaction = (newT: Omit<Transaction, 'id'>) => {
    const transaction: Transaction = {
      ...newT,
      id: Math.random().toString(36).substr(2, 9)
    };

    setState(prev => {
      return {
        ...prev,
        transactions: [...prev.transactions, transaction]
      };
    });
  };

  const updateInventory = (id: string, delta: number) => {
    setState(prev => {
      const item = prev.inventory.find(i => i.id === id);
      const newMovements = [...prev.inventoryMovements];

      if (delta < 0 && item) {
        const movement: InventoryMovement = {
          id: Math.random().toString(36).substr(2, 9),
          itemId: id,
          itemName: item.name,
          quantity: Math.abs(delta),
          date: new Date().toISOString()
        };
        newMovements.push(movement);
      }

      return {
        ...prev,
        inventory: prev.inventory.map(item => 
          item.id === id ? { ...item, quantity: Math.max(0, item.quantity + delta) } : item
        ),
        inventoryMovements: newMovements
      };
    });
  };

  const renderContent = () => {
    switch (activeView) {
      case 'dashboard':
        return <Dashboard state={state} />;
      case 'sales':
        return <TransactionForm type="sale" onAdd={handleAddTransaction} transactions={state.transactions} />;
      case 'expenses':
        return <TransactionForm type="expense" onAdd={handleAddTransaction} transactions={state.transactions} />;
      case 'inventory':
        return <InventoryView inventory={state.inventory} movements={state.inventoryMovements} onUpdate={updateInventory} />;
      case 'reports':
        return <ReportsView state={state} />;
      default:
        return <Dashboard state={state} />;
    }
  };

  return (
    <Layout activeView={activeView} setActiveView={setActiveView}>
      <div className="pb-8">
        {renderContent()}
      </div>
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Transaction, TransactionType } from '../types';
import { Plus, X, Calendar, TrendingDown, Landmark, Info, ChevronLeft, ChevronRight } from 'lucide-react';
import { SALE_CATEGORIES, EXPENSE_CATEGORIES, INVESTMENT_CATEGORIES } from '../constants';

interface TransactionFormProps {
  type: TransactionType;
  onAdd: (transaction: Omit<Transaction, 'id'>) => void;
  transactions: Transaction[];
}

const TransactionForm: React.FC<TransactionFormProps> = ({ type, onAdd, transactions }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [amount, setAmount] = useState('');
  const [subType, setSubType] = useState<'expense' | 'investment'>(type === 'sale' ? 'expense' : type as any);
  const [category, setCategory] = useState(type === 'sale' ? 'Total Diário' : '');
  const [description, setDescription] = useState('');
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);

  const activeType = type === 'sale' ? 'sale' : subType;
  const categories = activeType === 'sale' ? ['Total Diário', ...SALE_CATEGORIES] : 
                    activeType === 'expense' ? EXPENSE_CATEGORIES : 
                    INVESTMENT_CATEGORIES;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !category) return;

    onAdd({
      date: new Date().toISOString(),
      type: activeType as TransactionType,
      category,
      amount: parseFloat(amount),
      description: activeType === 'sale' ? (description || 'Venda consolidada do dia') : description,
      quantity: 1
    });

    setAmount('');
    setCategory(activeType === 'sale' ? 'Total Diário' : '');
    setDescription('');
    setIsOpen(false);
  };

  const totalInvested = useMemo(() => transactions.filter(t => t.type === 'investment').reduce((sum, t) => sum + t.amount, 0), [transactions]);
  const totalExpenses = useMemo(() => transactions.filter(t => t.type === 'expense').reduce((sum, t) => sum + t.amount, 0), [transactions]);

  const changeDate = (days: number) => {
    const current = new Date(selectedDate + 'T12:00:00');
    current.setDate(current.getDate() + days);
    setSelectedDate(current.toISOString().split('T')[0]);
  };

  const isToday = selectedDate === new Date().toISOString().split('T')[0];

  const groupedSales = useMemo(() => {
    if (type !== 'sale') return null;
    const groups: Record<string, { total: number, count: number, date: string }> = {};

    // Filtra as transações pela data selecionada
    transactions
      .filter(t => t.type === 'sale')
      .filter(t => new Date(t.date).toISOString().split('T')[0] === selectedDate)
      .forEach(t => {
        const dateStr = new Date(t.date).toLocaleDateString('pt-BR');
        if (!groups[dateStr]) groups[dateStr] = { total: 0, count: 0, date: t.date };
        groups[dateStr].total += t.amount;
        groups[dateStr].count += 1;
      });
    return Object.entries(groups).sort((a, b) => new Date(b[1].date).getTime() - new Date(a[1].date).getTime());
  }, [transactions, type, selectedDate]);

  const filteredTransactions = transactions.filter(t => t.type === activeType).reverse();

  return (
    <div className="space-y-4 animate-fadeIn">
      <div className="flex flex-col gap-4">
        <div className="flex items-center justify-between">
          <h2 className="text-xl font-black text-slate-800 tracking-tight">
            {type === 'sale' ? 'Vendas Diárias' : 'Gestão Financeira'}
          </h2>
          <button 
            onClick={() => setIsOpen(true)} 
            className="bg-blue-600 text-white p-3 rounded-full shadow-lg shadow-blue-200 active:scale-95 transition-all"
          >
            <Plus size={24} />
          </button>
        </div>

        {/* Filtro de Data para Vendas */}
        {type === 'sale' && (
          <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center justify-between">
            <button 
              onClick={() => changeDate(-1)} 
              className="p-2 text-slate-400 hover:text-blue-600 transition-colors"
            >
              <ChevronLeft size={20} />
            </button>
            <div className="flex flex-col items-center">
              <div className="relative">
                <input 
                  type="date" 
                  value={selectedDate} 
                  onChange={(e) => setSelectedDate(e.target.value)}
                  className="text-sm font-bold text-slate-800 focus:outline-none bg-transparent cursor-pointer text-center"
                />
              </div>
              <span className="text-[10px] text-blue-600 font-black uppercase tracking-widest mt-0.5">
                {isToday ? 'HOJE' : new Date(selectedDate + 'T12:00:00').toLocaleDateString('pt-BR', { weekday: 'long' })}
              </span>
            </div>
            <button 
              onClick={() => changeDate(1)} 
              disabled={isToday}
              className={`p-2 transition-colors ${isToday ? 'text-slate-100' : 'text-slate-400 hover:text-blue-600'}`}
            >
              <ChevronRight size={20} />
            </button>
          </div>
        )}

        {type !== 'sale' && (
          <div className="flex bg-slate-200/50 p-1 rounded-2xl">
            <button onClick={() => setSubType('expense')} className={`flex-1 py-3 px-4 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${subType === 'expense' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><TrendingDown size={14} /> Saídas</button>
            <button onClick={() => setSubType('investment')} className={`flex-1 py-3 px-4 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${subType === 'investment' ? 'bg-white text-amber-600 shadow-sm' : 'text-slate-500'}`}><Landmark size={14} /> Investimentos</button>
          </div>
        )}
      </div>

      {type !== 'sale' && (
        <div className={`p-5 rounded-3xl border flex flex-col gap-1 shadow-sm transition-all ${subType === 'investment' ? 'bg-amber-50 border-amber-100' : 'bg-red-50 border-red-100'}`}>
          <div className="flex items-center gap-2 text-slate-500 text-[10px] font-black uppercase tracking-widest opacity-70"><Info size={12} /> {subType === 'investment' ? 'Investimento Total' : 'Total de Saídas'}</div>
          <div className={`text-2xl font-black ${subType === 'investment' ? 'text-amber-700' : 'text-red-700'}`}>{(subType === 'investment' ? totalInvested : totalExpenses).toLocaleString()} Kz</div>
        </div>
      )}

      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-[32px] p-8 shadow-2xl animate-scaleIn">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-black text-slate-800 tracking-tight">{activeType === 'sale' ? 'Lançar Venda' : activeType === 'expense' ? 'Nova Saída' : 'Novo Investimento'}</h3>
              <button onClick={() => setIsOpen(false)} className="text-slate-300 hover:text-slate-500"><X size={28} /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-5">
              <div>
                <label className="block text-[10px] font-black text-slate-400 mb-1.5 uppercase tracking-widest">Categoria</label>
                <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-4 text-slate-700 font-semibold focus:ring-2 focus:ring-blue-100 focus:outline-none appearance-none" required>
                  <option value="">Selecione...</option>
                  {categories.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 mb-1.5 uppercase tracking-widest">Valor (Kz)</label>
                <input type="number" step="0.01" value={amount} onChange={e => setAmount(e.target.value)} placeholder="0,00" className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-4 text-slate-800 text-2xl font-black focus:ring-2 focus:ring-blue-100 focus:outline-none" required />
              </div>
              <button type="submit" className={`w-full text-white font-black py-5 rounded-2xl shadow-xl transition-all active:scale-95 ${activeType === 'investment' ? 'bg-amber-600 shadow-amber-100' : 'bg-blue-600 shadow-blue-100'}`}>SALVAR REGISTRO</button>
            </form>
          </div>
        </div>
      )}

      <div className="space-y-3">
        {activeType === 'sale' ? (
          groupedSales && groupedSales.length > 0 ? (
            groupedSales.map(([dateStr, data]) => (
              <div key={dateStr} className="bg-white p-5 rounded-3xl shadow-sm border border-slate-100 flex items-center justify-between transition-all hover:border-blue-100">
                <div className="flex items-center gap-4">
                  <div className="bg-blue-50 p-3 rounded-2xl text-blue-600 shadow-sm shadow-blue-50">
                    <Calendar size={22} />
                  </div>
                  <div className="flex flex-col">
                    <span className="font-black text-slate-800 text-base tracking-tight">{dateStr}</span>
                    <span className="text-[10px] text-slate-400 uppercase font-black tracking-widest">{data.count} LANÇAMENTOS</span>
                  </div>
                </div>
                <div className="flex flex-col items-end">
                  <span className="font-black text-blue-600 text-lg">+ {data.total.toLocaleString()} Kz</span>
                </div>
              </div>
            ))
          ) : (
            <div className="bg-slate-50/50 p-12 rounded-[32px] border-2 border-dashed border-slate-200 text-center flex flex-col items-center gap-3">
              <Calendar size={40} className="text-slate-200" />
              <p className="text-slate-400 text-xs font-bold uppercase tracking-widest italic leading-relaxed">
                Nenhuma venda registrada<br/>para esta data.
              </p>
            </div>
          )
        ) : (
          filteredTransactions.map(t => (
            <div key={t.id} className="bg-white p-5 rounded-3xl shadow-sm border border-slate-100 flex items-center justify-between transition-all hover:border-red-50">
              <div className="flex items-center gap-4">
                <div className={`p-3 rounded-2xl ${activeType === 'investment' ? 'bg-amber-50 text-amber-600 shadow-amber-50' : 'bg-red-50 text-red-600 shadow-red-50'}`}>
                  {activeType === 'investment' ? <Landmark size={22} /> : <TrendingDown size={22} />}
                </div>
                <div className="flex flex-col">
                  <span className="font-black text-slate-800 text-base tracking-tight">{t.category}</span>
                  <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{new Date(t.date).toLocaleDateString('pt-BR')}</span>
                </div>
              </div>
              <div className="flex flex-col items-end">
                <span className={`font-black text-lg ${activeType === 'investment' ? 'text-amber-600' : 'text-red-500'}`}>
                  - {t.amount.toLocaleString()} Kz
                </span>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default TransactionForm;

import React, { useMemo, useState } from 'react';
import { InventoryItem, InventoryMovement } from '../types';
import { Plus, Minus, AlertCircle, History, ChevronLeft, ChevronRight, X, ArrowDownRight } from 'lucide-react';

interface InventoryViewProps {
  inventory: InventoryItem[];
  movements: InventoryMovement[];
  onUpdate: (id: string, delta: number) => void;
}

const InventoryView: React.FC<InventoryViewProps> = ({ inventory, movements, onUpdate }) => {
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
  const [outflowModal, setOutflowModal] = useState<{ isOpen: boolean; itemId: string; itemName: string } | null>(null);
  const [outflowAmount, setOutflowAmount] = useState('');

  // Navegação de dias
  const changeDate = (days: number) => {
    const current = new Date(selectedDate + 'T12:00:00'); 
    current.setDate(current.getDate() + days);
    setSelectedDate(current.toISOString().split('T')[0]);
  };

  // Calcular saídas da data selecionada por produto
  const filteredOutputs = useMemo(() => {
    const map: Record<string, number> = {};

