export type TransactionType = 'sale' | 'expense' | 'investment';

export interface Transaction {
  id: string;
  date: string;
  type: TransactionType;
  category: string;
  amount: number;
  description: string;
  quantity?: number;
}

export interface InventoryItem {
  id: string;
  name: string;
  quantity: number;
  unit: string;
  minThreshold: number;
}

export interface InventoryMovement {
  id: string;
  itemId: string;
  itemName: string;
  quantity: number;
  date: string; // ISO string
}

export interface PHRecord {
  id: string;
  date: string;
  value: number;
  status: 'Ideal' | 'Alerta' | 'Crítico';
}

export interface BusinessState {
  transactions: Transaction[];
  inventory: InventoryItem[];
  inventoryMovements: InventoryMovement[];
  phRecords: PHRecord[];
}

export type ViewType = 'dashboard' | 'sales' | 'expenses' | 'inventory' | 'reports';

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import TransactionForm from './components/TransactionForm';
import InventoryView from './components/InventoryView';
import ReportsView from './components/ReportsView';
import { BusinessState, ViewType, Transaction, InventoryItem, InventoryMovement, PHRecord } from './types';
import { INITIAL_INVENTORY } from './constants';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [state, setState] = useState<BusinessState>(() => {
    const saved = localStorage.getItem('agua_cristalina_state');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (!parsed.inventoryMovements) parsed.inventoryMovements = [];
      if (!parsed.phRecords) parsed.phRecords = [];
      return parsed;
    }
    return {
      transactions: [],
      inventory: INITIAL_INVENTORY,
      inventoryMovements: [],
      phRecords: []
    };
  });

  useEffect(() => {
    localStorage.setItem('agua_cristalina_state', JSON.stringify(state));
  }, [state]);

  const handleAddTransaction = (newT: Omit<Transaction, 'id'>) => {
    const transaction: Transaction = {
      ...newT,
      id: Math.random().toString(36).substr(2, 9)
    };

    setState(prev => ({
      ...prev,
      transactions: [...prev.transactions, transaction]
    }));
  };

  const handleAddPHRecord = (value: number) => {
    let status: 'Ideal' | 'Alerta' | 'Crítico' = 'Ideal';
    if (value < 6.5 || value > 8.5) status = 'Crítico';
    else if (value < 7.0 || value > 8.0) status = 'Alerta';

    const record: PHRecord = {
      id: Math.random().toString(36).substr(2, 9),
      date: new Date().toISOString(),
      value,
      status
    };

    setState(prev => ({
      ...prev,
      phRecords: [record, ...prev.phRecords]
    }));
  };

  const updateInventory = (id: string, delta: number) => {
    setState(prev => {
      const item = prev.inventory.find(i => i.id === id);
      const newMovements = [...prev.inventoryMovements];

      if (delta < 0 && item) {
        const movement: InventoryMovement = {
          id: Math.random().toString(36).substr(2, 9),
          itemId: id,
          itemName: item.name,
          quantity: Math.abs(delta),
          date: new Date().toISOString()
        };
        newMovements.push(movement);
      }

      return {
        ...prev,
        inventory: prev.inventory.map(item => 
          item.id === id ? { ...item, quantity: Math.max(0, item.quantity + delta) } : item
        ),
        inventoryMovements: newMovements
      };
    });
  };

  const renderContent = () => {
    switch (activeView) {
      case 'dashboard':
        return <Dashboard state={state} />;
      case 'sales':
        return <TransactionForm type="sale" onAdd={handleAddTransaction} transactions={state.transactions} />;
      case 'expenses':
        return <TransactionForm type="expense" onAdd={handleAddTransaction} transactions={state.transactions} />;
      case 'inventory':
        return <InventoryView inventory={state.inventory} movements={state.inventoryMovements} onUpdate={updateInventory} />;
      case 'reports':
        return <ReportsView state={state} onAddPH={handleAddPHRecord} />;
      default:
        return <Dashboard state={state} />;
    }
  };

  return (
    <Layout activeView={activeView} setActiveView={setActiveView}>
      <div className="pb-8">
        {renderContent()}
      </div>
    </Layout>
  );
};

