            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Histórico de Qualidade</h3>
            {state.phRecords.length === 0 ? (
              <div className="bg-slate-50 border-2 border-dashed border-slate-200 rounded-3xl p-10 text-center text-slate-300 text-xs font-bold uppercase italic tracking-widest">Nada registrado</div>
            ) : (
              state.phRecords.map(r => (
                <div key={r.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between transition-all hover:scale-[1.01]">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-xl flex items-center justify-center font-black text-lg" style={{ backgroundColor: `${COLORS[r.status]}15`, color: COLORS[r.status] }}>
                      {r.value.toFixed(1)}
                    </div>
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-800 text-sm">pH Medido</span>
                      <span className="text-[10px] text-slate-400 flex items-center gap-1 uppercase tracking-tighter">
                        <Calendar size={10} /> {new Date(r.date).toLocaleDateString()} às {new Date(r.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </span>
                    </div>
                  </div>
                  <span className="px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest" style={{ backgroundColor: `${COLORS[r.status]}15`, color: COLORS[r.status] }}>
                    {r.status}
                  </span>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {activeTab === 'ai' && (
        <AIAdvisor state={state} />
      )}
    </div>
  );
};

export default ReportsView;

import React, { useState, useMemo } from 'react';
import { BusinessState, PHRecord } from '../types';
import AIAdvisor from './AIAdvisor';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell, Legend, AreaChart, Area
} from 'recharts';
import { 
  History, 
  Package, 
  Sparkles, 
  ArrowUpRight, 
  ArrowDownLeft, 
  Landmark,
  Calendar,
  Droplet,
  Plus,
  ChevronDown,
  ChevronLeft,
  ChevronRight,
  Zap,
  TrendingUp
} from 'lucide-react';

interface ReportsViewProps {
  state: BusinessState;
  onAddPH: (value: number) => void;
}

type ReportTab = 'transactions' | 'inventory' | 'quality' | 'ai';

const COLORS = {
  Ideal: '#22c55e',   // green-500
  Alerta: '#f59e0b',  // amber-500
  Crítico: '#ef4444', // red-500
};

const ReportsView: React.FC<ReportsViewProps> = ({ state, onAddPH }) => {
  const [activeTab, setActiveTab] = useState<ReportTab>('transactions');
  const [filterType, setFilterType] = useState<'all' | 'sale' | 'expense' | 'investment'>('all');
  const [phValue, setPhValue] = useState('');
  const [showPHForm, setShowPHForm] = useState(false);
  const [qualityDate, setQualityDate] = useState(new Date().toISOString().split('T')[0]);

  // Navegação de data para qualidade
  const changeQualityDate = (days: number) => {
    const current = new Date(qualityDate + 'T12:00:00');
    current.setDate(current.getDate() + days);
    setQualityDate(current.toISOString().split('T')[0]);
  };

  const isToday = qualityDate === new Date().toISOString().split('T')[0];

  // Dados para Gráfico de Vendas por Categoria (Mês Atual)
  const salesChartData = useMemo(() => {
    const now = new Date();
    const categories: Record<string, number> = {};

    state.transactions.forEach(t => {
      const d = new Date(t.date);
      if (t.type === 'sale' && d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear()) {
        categories[t.category] = (categories[t.category] || 0) + t.amount;
      }
    });

    return Object.entries(categories)
      .map(([name, total]) => ({ name, total }))
      .sort((a, b) => b.total - a.total);
  }, [state.transactions]);

  // Filtragem de registros de pH por data selecionada
  const filteredPhRecords = useMemo(() => {
    return state.phRecords.filter(r => 
      new Date(r.date).toISOString().split('T')[0] === qualityDate
    );
  }, [state.phRecords, qualityDate]);

  // Cálculo da média diária de pH
  const dailyPhAverage = useMemo(() => {
    if (filteredPhRecords.length === 0) return null;
    const sum = filteredPhRecords.reduce((acc, r) => acc + r.value, 0);
    return sum / filteredPhRecords.length;
  }, [filteredPhRecords]);

  // Histórico de Médias Diárias para o Gráfico de Tendência
  const phTrendData = useMemo(() => {
    const dayGroups: Record<string, { sum: number, count: number }> = {};

    state.phRecords.forEach(r => {
      const dateKey = new Date(r.date).toISOString().split('T')[0];
      if (!dayGroups[dateKey]) dayGroups[dateKey] = { sum: 0, count: 0 };
      dayGroups[dateKey].sum += r.value;
      dayGroups[dateKey].count += 1;
    });

    return Object.entries(dayGroups)
      .map(([date, data]) => ({
        date: new Date(date + 'T12:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
        avg: parseFloat((data.sum / data.count).toFixed(2)),
        rawDate: date
      }))
      .sort((a, b) => new Date(a.rawDate).getTime() - new Date(b.rawDate).getTime())
      .slice(-7); // Últimos 7 dias com registros
  }, [state.phRecords]);

  // Dados para Gráfico de Pizza do pH (Baseado na data selecionada)
  const phPieData = useMemo(() => {
    const counts = { Ideal: 0, Alerta: 0, Crítico: 0 };
    filteredPhRecords.forEach(r => {
      counts[r.status]++;
    });
    return Object.entries(counts)
      .filter(([_, value]) => value > 0)
      .map(([name, value]) => ({ name, value }));
  }, [filteredPhRecords]);

  const filteredTransactions = useMemo(() => {
    return state.transactions
      .filter(t => filterType === 'all' || t.type === filterType)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [state.transactions, filterType]);

  const getAverageStatusColor = (val: number | null) => {
    if (!val) return 'bg-slate-400';
    if (val < 6.5 || val > 8.5) return 'bg-red-500';
    if (val < 7.0 || val > 8.0) return 'bg-amber-500';
    return 'bg-emerald-600';
  };

  const handlePHSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const val = parseFloat(phValue);
    if (!isNaN(val)) {
      onAddPH(val);
      setPhValue('');
      setShowPHForm(false);
      setQualityDate(new Date().toISOString().split('T')[0]);
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex flex-col gap-1">
        <h2 className="text-2xl font-black text-slate-800 tracking-tight">Relatórios</h2>
        <p className="text-slate-500 text-sm">Visão geral do desempenho e qualidade.</p>
      </div>

      <div className="flex bg-slate-200/50 p-1 rounded-2xl overflow-x-auto no-scrollbar">
        <button onClick={() => setActiveTab('transactions')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'transactions' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><History size={14} /> Histórico</button>
        <button onClick={() => setActiveTab('inventory')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'inventory' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><Package size={14} /> Estoque</button>
        <button onClick={() => setActiveTab('quality')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'quality' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><Droplet size={14} /> Qualidade</button>
        <button onClick={() => setActiveTab('ai')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'ai' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><Sparkles size={14} /> IA</button>
      </div>

      {activeTab === 'transactions' && (
        <div className="space-y-6">
          <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Vendas por Categoria (Mês Atual)</h3>
            <div className="h-64 w-full">
              {salesChartData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={salesChartData} layout="vertical" margin={{ left: -20, right: 20 }}>
                    <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f1f5f9" />
                    <XAxis type="number" hide />
                    <YAxis dataKey="name" type="category" width={100} tick={{ fontSize: 10, fontWeight: 700, fill: '#64748b' }} />
                    <Tooltip cursor={{ fill: '#f8fafc' }} formatter={(value: number) => `${value.toLocaleString()} Kz`} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }} />
                    <Bar dataKey="total" fill="#3b82f6" radius={[0, 8, 8, 0]} barSize={20} />
                  </BarChart>
                </ResponsiveContainer>
              ) : <div className="h-full flex items-center justify-center text-slate-300 text-xs italic">Sem vendas este mês.</div>}
            </div>
          </div>
          <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1">
            {(['all', 'sale', 'expense', 'investment'] as const).map(type => (
              <button key={type} onClick={() => setFilterType(type)} className={`px-4 py-2 rounded-full text-[10px] font-bold whitespace-nowrap transition-all border ${filterType === type ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-slate-500 border-slate-200'}`}>{type === 'all' ? 'TUDO' : type === 'sale' ? 'VENDAS' : type === 'expense' ? 'SAÍDAS' : 'INVESTIMENTOS'}</button>
            ))}
          </div>
          <div className="space-y-3">
            {filteredTransactions.map(t => (
              <div key={t.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className={`p-2 rounded-xl ${t.type === 'sale' ? 'bg-green-50 text-green-600' : t.type === 'expense' ? 'bg-red-50 text-red-600' : 'bg-amber-50 text-amber-600'}`}>
                    {t.type === 'sale' ? <ArrowUpRight size={18} /> : t.type === 'expense' ? <ArrowDownLeft size={18} /> : <Landmark size={18} />}
                  </div>
                  <div className="flex flex-col"><span className="font-bold text-slate-800 text-sm">{t.category}</span><span className="text-[10px] text-slate-400 flex items-center gap-1"><Calendar size={10} /> {new Date(t.date).toLocaleDateString()}</span></div>
                </div>
                <span className={`font-black text-sm ${t.type === 'sale' ? 'text-green-600' : 'text-red-600'}`}>{t.type === 'sale' ? '+' : '-'} {t.amount.toLocaleString()} Kz</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'quality' && (
        <div className="space-y-6 animate-fadeIn">
          {/* Filtro de Data para Qualidade */}
          <div className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center justify-between">
            <button onClick={() => changeQualityDate(-1)} className="p-2 text-slate-400 hover:text-blue-600 transition-colors"><ChevronLeft size={20} /></button>
            <div className="flex flex-col items-center">
              <input type="date" value={qualityDate} onChange={(e) => setQualityDate(e.target.value)} className="text-sm font-black text-slate-800 focus:outline-none bg-transparent cursor-pointer text-center" />
              <span className="text-[10px] text-blue-600 font-black uppercase tracking-widest mt-0.5">{isToday ? 'HOJE' : new Date(qualityDate + 'T12:00:00').toLocaleDateString('pt-BR', { weekday: 'short' })}</span>
            </div>
            <button onClick={() => changeQualityDate(1)} disabled={isToday} className={`p-2 transition-colors ${isToday ? 'text-slate-100' : 'text-slate-400 hover:text-blue-600'}`}><ChevronRight size={20} /></button>
          </div>

          {/* Card de Média Diária reativo */}
          <div className={`${getAverageStatusColor(dailyPhAverage)} p-6 rounded-[32px] text-white shadow-xl relative overflow-hidden transition-colors duration-500`}>
            <div className="relative z-10">
              <span className="text-[10px] font-black opacity-70 uppercase tracking-widest flex items-center gap-2 mb-1"><Zap size={14} /> Média do Dia Selecionado</span>
              <div className="flex items-baseline gap-2">
                <span className="text-4xl font-black">{dailyPhAverage ? dailyPhAverage.toFixed(2) : '--'}</span>
                <span className="text-xl font-bold opacity-60">pH</span>
              </div>
              <p className="text-[10px] font-medium opacity-80 mt-2 italic">{filteredPhRecords.length} medições em {new Date(qualityDate + 'T12:00:00').toLocaleDateString('pt-BR')}</p>
            </div>
            <Droplet size={100} className="absolute -right-6 -bottom-6 opacity-10" />
          </div>

          {/* Gráfico de Tendência (Média por Dia) */}
          <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2"><TrendingUp size={14} /> Tendência de Médias Diárias</h3>
            <div className="h-48 w-full">
              {phTrendData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={phTrendData}>
                    <defs>
                      <linearGradient id="colorPh" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#10b981" stopOpacity={0.1}/>
                        <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="date" tick={{fontSize: 9, fontWeight: 700, fill: '#94a3b8'}} />
                    <YAxis domain={[5, 9]} hide />
                    <Tooltip contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }} />
                    <Area type="monotone" dataKey="avg" stroke="#10b981" strokeWidth={3} fillOpacity={1} fill="url(#colorPh)" name="Média pH" />
                  </AreaChart>
                </ResponsiveContainer>
              ) : <div className="h-full flex items-center justify-center text-slate-300 text-xs italic">Sem dados históricos.</div>}
            </div>
          </div>

          <div className="bg-blue-600 p-6 rounded-[32px] text-white shadow-xl shadow-blue-100">
            {!showPHForm ? (
              <button onClick={() => setShowPHForm(true)} className="w-full flex items-center justify-between group">
                <div className="flex flex-col items-start"><span className="text-[10px] font-black opacity-70 uppercase tracking-widest mb-1">Qualidade da Água</span><span className="text-xl font-black">Registrar Novo pH</span></div>
                <div className="bg-white/20 p-3 rounded-2xl group-active:scale-90 transition-transform"><Plus size={24} /></div>
              </button>
            ) : (
              <form onSubmit={handlePHSubmit} className="space-y-4 animate-scaleIn">
                <div className="flex justify-between items-center mb-2"><span className="text-xs font-black uppercase tracking-widest">Nova Medição</span><button type="button" onClick={() => setShowPHForm(false)} className="opacity-60"><ChevronDown size={20} /></button></div>
                <div className="relative">
                  <input type="number" step="0.1" value={phValue} onChange={e => setPhValue(e.target.value)} placeholder="7.5" className="w-full bg-white/10 border border-white/20 rounded-2xl px-6 py-5 text-3xl font-black text-white focus:outline-none focus:ring-2 focus:ring-white/40 placeholder:text-white/30" autoFocus required />
                  <span className="absolute right-6 top-1/2 -translate-y-1/2 text-white/50 font-black text-xl italic uppercase">pH</span>
                </div>
                <button type="submit" className="w-full bg-white text-blue-700 font-black py-4 rounded-2xl shadow-lg active:scale-95 transition-all">SALVAR REGISTRO</button>
              </form>
            )}
          </div>

          <div className="space-y-3">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Registros de {new Date(qualityDate + 'T12:00:00').toLocaleDateString('pt-BR')}</h3>
            {filteredPhRecords.length === 0 ? (
              <div className="bg-slate-50 border-2 border-dashed border-slate-200 rounded-3xl p-10 text-center text-slate-300 text-xs font-bold uppercase italic tracking-widest">Nada encontrado</div>
            ) : (
              filteredPhRecords.map(r => (
                <div key={r.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between transition-all hover:scale-[1.01]">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-xl flex items-center justify-center font-black text-lg" style={{ backgroundColor: `${COLORS[r.status]}15`, color: COLORS[r.status] }}>{r.value.toFixed(1)}</div>
                    <div className="flex flex-col"><span className="font-bold text-slate-800 text-sm">pH Medido</span><span className="text-[10px] text-slate-400 flex items-center gap-1 uppercase tracking-tighter"><Calendar size={10} /> {new Date(r.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span></div>
                  </div>
                  <span className="px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest" style={{ backgroundColor: `${COLORS[r.status]}15`, color: COLORS[r.status] }}>{r.status}</span>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {activeTab === 'ai' && <AIAdvisor state={state} />}
      {activeTab === 'inventory' && (
        <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
          <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Uso de Insumos</h3>
          <div className="space-y-4">
            {state.inventory.map(item => {
              const totalOut = state.inventoryMovements.filter(m => m.itemId === item.id).reduce((sum, m) => sum + m.quantity, 0);
              return (
                <div key={item.id} className="flex flex-col gap-1">
                  <div className="flex justify-between items-center text-xs"><span className="font-bold text-slate-700">{item.name}</span><span className="font-black text-blue-600">{totalOut} {item.unit} saíram</span></div>
                  <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden"><div className="bg-blue-500 h-full rounded-full" style={{ width: `${Math.min(100, (totalOut / 100) * 100)}%` }}></div></div>
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
};

export default ReportsView;

export type TransactionType = 'sale' | 'expense' | 'investment';

export interface Transaction {
  id: string;
  date: string;
  type: TransactionType;
  category: string;
  amount: number;
  description: string;
  quantity?: number;
}

export interface InventoryItem {
  id: string;
  name: string;
  quantity: number;
  unit: string;
  minThreshold: number;
}

export interface InventoryMovement {
  id: string;
  itemId: string;
  itemName: string;
  quantity: number;
  date: string; // ISO string
}

export interface PHRecord {
  id: string;
  date: string;
  value: number;
  status: 'Ideal' | 'Alerta' | 'Crítico';
}

export interface AppNotification {
  id: string;
  title: string;
  message: string;
  type: 'warning' | 'info' | 'danger';
  date: string;
  read: boolean;
}

export interface BusinessState {
  transactions: Transaction[];
  inventory: InventoryItem[];
  inventoryMovements: InventoryMovement[];
  phRecords: PHRecord[];
  notifications: AppNotification[];
}

export type ViewType = 'dashboard' | 'sales' | 'expenses' | 'inventory' | 'reports';

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import TransactionForm from './components/TransactionForm';
import InventoryView from './components/InventoryView';
import ReportsView from './components/ReportsView';
import NotificationToast from './components/NotificationToast';
import { BusinessState, ViewType, Transaction, InventoryItem, InventoryMovement, PHRecord, AppNotification } from './types';
import { INITIAL_INVENTORY } from './constants';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [toast, setToast] = useState<AppNotification | null>(null);
  const [state, setState] = useState<BusinessState>(() => {
    const saved = localStorage.getItem('agua_cristalina_state');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (!parsed.inventoryMovements) parsed.inventoryMovements = [];
      if (!parsed.phRecords) parsed.phRecords = [];
      if (!parsed.notifications) parsed.notifications = [];
      return parsed;
    }
    return {
      transactions: [],
      inventory: INITIAL_INVENTORY,
      inventoryMovements: [],
      phRecords: [],
      notifications: []
    };
  });

  useEffect(() => {
    localStorage.setItem('agua_cristalina_state', JSON.stringify(state));
  }, [state]);

  const addNotification = (title: string, message: string, type: 'warning' | 'info' | 'danger') => {
    const newNotif: AppNotification = {
      id: Math.random().toString(36).substr(2, 9),
      title,
      message,
      type,
      date: new Date().toISOString(),
      read: false
    };

    setState(prev => ({
      ...prev,
      notifications: [newNotif, ...prev.notifications].slice(0, 50) // Limite de 50 notificações
    }));

    setToast(newNotif);
    setTimeout(() => setToast(null), 5000);
  };

  const markAllNotificationsAsRead = () => {
    setState(prev => ({
      ...prev,
      notifications: prev.notifications.map(n => ({ ...n, read: true }))
    }));
  };

  const handleAddTransaction = (newT: Omit<Transaction, 'id'>) => {
    const transaction: Transaction = {
      ...newT,
      id: Math.random().toString(36).substr(2, 9)
    };

    setState(prev => ({
      ...prev,
      transactions: [...prev.transactions, transaction]
    }));
  };

  const handleAddPHRecord = (value: number) => {
    let status: 'Ideal' | 'Alerta' | 'Crítico' = 'Ideal';
    if (value < 6.5 || value > 8.5) status = 'Crítico';
    else if (value < 7.0 || value > 8.0) status = 'Alerta';

    const record: PHRecord = {
      id: Math.random().toString(36).substr(2, 9),
      date: new Date().toISOString(),
      value,
      status
    };

    setState(prev => ({
      ...prev,
      phRecords: [record, ...prev.phRecords]
    }));

    if (status === 'Crítico') {
      addNotification('Qualidade Crítica', `O pH medido (${value}) está fora dos padrões de segurança!`, 'danger');
    }
  };

  const updateInventory = (id: string, delta: number) => {
    setState(prev => {
      const item = prev.inventory.find(i => i.id === id);
      if (!item) return prev;

      const newQuantity = Math.max(0, item.quantity + delta);
      const newMovements = [...prev.inventoryMovements];

      if (delta < 0) {
        newMovements.push({
          id: Math.random().toString(36).substr(2, 9),
          itemId: id,
          itemName: item.name,
          quantity: Math.abs(delta),
          date: new Date().toISOString()
        });
      }

      // Alerta de estoque baixo
      if (newQuantity <= item.minThreshold && item.quantity > item.minThreshold) {
        // Disparar notificação apenas se cruzou o limite agora
        setTimeout(() => {
          addNotification(
            'Estoque Baixo!', 
            `O item "${item.name}" atingiu o limite crítico (${newQuantity} ${item.unit} restantes).`, 
            'warning'
          );
        }, 100);
      }

      return {
        ...prev,
        inventory: prev.inventory.map(i => 
          i.id === id ? { ...i, quantity: newQuantity } : i
        ),
        inventoryMovements: newMovements
      };
    });
  };

  const renderContent = () => {
    switch (activeView) {
      case 'dashboard':
        return <Dashboard state={state} />;
      case 'sales':
        return <TransactionForm type="sale" onAdd={handleAddTransaction} transactions={state.transactions} />;
      case 'expenses':
        return <TransactionForm type="expense" onAdd={handleAddTransaction} transactions={state.transactions} />;
      case 'inventory':
        return <InventoryView inventory={state.inventory} movements={state.inventoryMovements} onUpdate={updateInventory} />;
      case 'reports':
        return <ReportsView state={state} onAddPH={handleAddPHRecord} />;
      default:
        return <Dashboard state={state} />;
    }
  };

  return (
    <Layout 
      activeView={activeView} 
      setActiveView={setActiveView} 
      notifications={state.notifications}
      onMarkRead={markAllNotificationsAsRead}
    >
      <div className="pb-8">
        {renderContent()}
      </div>
      {toast && <NotificationToast notification={toast} onClose={() => setToast(null)} />}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { ViewType, AppNotification } from '../types';
import { NAV_ITEMS } from '../constants';
import { Bell, X, Calendar, AlertTriangle, Info, AlertCircle } from 'lucide-react';

interface LayoutProps {
