        <div className="fixed inset-0 z-50 flex justify-end">
          <div className="absolute inset-0 bg-black/20 backdrop-blur-sm" onClick={() => setShowNotifications(false)} />
          <div className="relative w-4/5 h-full bg-white shadow-2xl animate-slideInRight flex flex-col">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
