            </div>
            <div className="flex-1 overflow-y-auto p-4 space-y-3 no-scrollbar">
              {notifications.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-slate-300 space-y-2 italic text-xs">
                  <Bell size={40} className="opacity-20" />
                  <p>Nenhuma notificação por enquanto.</p>
                </div>
              ) : (
                notifications.map(n => (
                  <div key={n.id} className={`p-4 rounded-2xl border flex gap-3 transition-all ${n.read ? 'bg-white border-slate-100 opacity-60' : 'bg-blue-50/50 border-blue-100 ring-1 ring-blue-50'}`}>
                    <div className="mt-1">{getIcon(n.type)}</div>
                    <div className="flex flex-col gap-1">
                      <span className="font-bold text-slate-800 text-xs">{n.title}</span>
                      <p className="text-[10px] text-slate-600 leading-tight">{n.message}</p>
                      <span className="text-[8px] text-slate-400 font-black uppercase mt-1 flex items-center gap-1">
                        <Calendar size={8} /> {new Date(n.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
