              activeView === item.id ? 'text-blue-600 scale-110' : 'text-slate-400'
            }`}
          >
            <div className={`p-1 rounded-lg ${activeView === item.id ? 'bg-blue-50' : 'bg-transparent'}`}>
              {item.icon}
            </div>
            <span className="text-[10px] font-semibold">{item.label}</span>
