export default Layout;

import React from 'react';
import { AppNotification } from '../types';
import { AlertTriangle, AlertCircle, Info, X } from 'lucide-react';

interface NotificationToastProps {
  notification: AppNotification;
  onClose: () => void;
}

const NotificationToast: React.FC<NotificationToastProps> = ({ notification, onClose }) => {
  const getStyle = () => {
    switch(notification.type) {
      case 'danger': return 'bg-red-600 text-white shadow-red-100';
      case 'warning': return 'bg-amber-500 text-white shadow-amber-100';
      default: return 'bg-blue-600 text-white shadow-blue-100';
    }
  };

  const getIcon = () => {
    switch(notification.type) {
      case 'danger': return <AlertCircle size={20} />;
      case 'warning': return <AlertTriangle size={20} />;
      default: return <Info size={20} />;
    }
  };

  return (
    <div className={`fixed top-20 left-4 right-4 z-[100] animate-slideInDown p-4 rounded-2xl shadow-2xl flex items-center justify-between gap-3 ${getStyle()}`}>
      <div className="flex items-center gap-3">
        <div className="bg-white/20 p-2 rounded-xl">
          {getIcon()}
        </div>
        <div className="flex flex-col">
          <span className="font-black text-xs uppercase tracking-tight">{notification.title}</span>
          <p className="text-[10px] opacity-90 font-medium leading-tight">{notification.message}</p>
        </div>
      </div>
      <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors">
        <X size={20} />
      </button>
    </div>
  );
};

export default NotificationToast;

import React, { useState, useMemo } from 'react';
import { BusinessState, PHRecord } from '../types';
import AIAdvisor from './AIAdvisor';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  AreaChart, Area
} from 'recharts';
import { 
  History, 
  Package, 
  Sparkles, 
  ArrowUpRight, 
  ArrowDownLeft, 
  Landmark,
  Calendar,
  Droplet,
  Plus,
  ChevronDown,
  ChevronLeft,
  ChevronRight,
  Clock
} from 'lucide-react';

interface ReportsViewProps {
  state: BusinessState;
  onAddPH: (value: number) => void;
}

type ReportTab = 'transactions' | 'inventory' | 'quality' | 'ai';

const COLORS = {
  Ideal: '#22c55e',   // green-500
  Alerta: '#f59e0b',  // amber-500
  Crítico: '#ef4444', // red-500
};

const ReportsView: React.FC<ReportsViewProps> = ({ state, onAddPH }) => {
  const [activeTab, setActiveTab] = useState<ReportTab>('transactions');
  const [filterType, setFilterType] = useState<'all' | 'sale' | 'expense' | 'investment'>('all');
  const [phValue, setPhValue] = useState('');
  const [showPHForm, setShowPHForm] = useState(false);
  const [qualityDate, setQualityDate] = useState(new Date().toISOString().split('T')[0]);

  // Navegação de data para qualidade
  const changeQualityDate = (days: number) => {
    const current = new Date(qualityDate + 'T12:00:00');
    current.setDate(current.getDate() + days);
    setQualityDate(current.toISOString().split('T')[0]);
  };

  const isToday = qualityDate === new Date().toISOString().split('T')[0];

  // Dados para Gráfico de Vendas por Categoria (Mês Atual)
  const salesChartData = useMemo(() => {
    const now = new Date();
    const categories: Record<string, number> = {};

    state.transactions.forEach(t => {
      const d = new Date(t.date);
      if (t.type === 'sale' && d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear()) {
        categories[t.category] = (categories[t.category] || 0) + t.amount;
      }
    });

    return Object.entries(categories)
      .map(([name, total]) => ({ name, total }))
      .sort((a, b) => b.total - a.total);
  }, [state.transactions]);

  // Filtragem de registros de pH por data selecionada
  const filteredPhRecords = useMemo(() => {
    return state.phRecords
      .filter(r => new Date(r.date).toISOString().split('T')[0] === qualityDate)
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [state.phRecords, qualityDate]);

  // Dados para Gráfico de PH por Hora
  const hourlyPhData = useMemo(() => {
    return filteredPhRecords.map(r => ({
      time: new Date(r.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      value: r.value,
      status: r.status
    }));
  }, [filteredPhRecords]);

  const filteredTransactions = useMemo(() => {
    return state.transactions
      .filter(t => filterType === 'all' || t.type === filterType)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [state.transactions, filterType]);

  const handlePHSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const val = parseFloat(phValue);
    if (!isNaN(val)) {
      onAddPH(val);
      setPhValue('');
      setShowPHForm(false);
      setQualityDate(new Date().toISOString().split('T')[0]);
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex flex-col gap-1">
        <h2 className="text-2xl font-black text-slate-800 tracking-tight">Relatórios</h2>
        <p className="text-slate-500 text-sm">Visão geral do desempenho e qualidade.</p>
      </div>

      <div className="flex bg-slate-200/50 p-1 rounded-2xl overflow-x-auto no-scrollbar">
        <button onClick={() => setActiveTab('transactions')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'transactions' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><History size={14} /> Histórico</button>
        <button onClick={() => setActiveTab('inventory')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'inventory' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><Package size={14} /> Estoque</button>
        <button onClick={() => setActiveTab('quality')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'quality' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><Droplet size={14} /> Qualidade</button>
        <button onClick={() => setActiveTab('ai')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'ai' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><Sparkles size={14} /> IA</button>
      </div>

      {activeTab === 'transactions' && (
        <div className="space-y-6">
          <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Vendas por Categoria (Mês Atual)</h3>
            <div className="h-64 w-full">
              {salesChartData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={salesChartData} layout="vertical" margin={{ left: -20, right: 20 }}>
                    <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f1f5f9" />
                    <XAxis type="number" hide />
                    <YAxis dataKey="name" type="category" width={100} tick={{ fontSize: 10, fontWeight: 700, fill: '#64748b' }} />
                    <Tooltip cursor={{ fill: '#f8fafc' }} formatter={(value: number) => `${value.toLocaleString()} Kz`} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }} />
                    <Bar dataKey="total" fill="#3b82f6" radius={[0, 8, 8, 0]} barSize={20} />
                  </BarChart>
                </ResponsiveContainer>
              ) : <div className="h-full flex items-center justify-center text-slate-300 text-xs italic">Sem vendas este mês.</div>}
            </div>
          </div>
          <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1">
            {(['all', 'sale', 'expense', 'investment'] as const).map(type => (
              <button key={type} onClick={() => setFilterType(type)} className={`px-4 py-2 rounded-full text-[10px] font-bold whitespace-nowrap transition-all border ${filterType === type ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-slate-500 border-slate-200'}`}>{type === 'all' ? 'TUDO' : type === 'sale' ? 'VENDAS' : type === 'expense' ? 'SAÍDAS' : 'INVESTIMENTOS'}</button>
            ))}
          </div>
          <div className="space-y-3">
            {filteredTransactions.map(t => (
              <div key={t.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className={`p-2 rounded-xl ${t.type === 'sale' ? 'bg-green-50 text-green-600' : t.type === 'expense' ? 'bg-red-50 text-red-600' : 'bg-amber-50 text-amber-600'}`}>
                    {t.type === 'sale' ? <ArrowUpRight size={18} /> : t.type === 'expense' ? <ArrowDownLeft size={18} /> : <Landmark size={18} />}
                  </div>
                  <div className="flex flex-col"><span className="font-bold text-slate-800 text-sm">{t.category}</span><span className="text-[10px] text-slate-400 flex items-center gap-1"><Calendar size={10} /> {new Date(t.date).toLocaleDateString()}</span></div>
                </div>
                <span className={`font-black text-sm ${t.type === 'sale' ? 'text-green-600' : 'text-red-600'}`}>{t.type === 'sale' ? '+' : '-'} {t.amount.toLocaleString()} Kz</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'quality' && (
        <div className="space-y-6 animate-fadeIn">
          {/* Filtro de Data para Qualidade */}
          <div className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center justify-between">
            <button onClick={() => changeQualityDate(-1)} className="p-2 text-slate-400 hover:text-blue-600 transition-colors"><ChevronLeft size={20} /></button>
            <div className="flex flex-col items-center">
              <input type="date" value={qualityDate} onChange={(e) => setQualityDate(e.target.value)} className="text-sm font-black text-slate-800 focus:outline-none bg-transparent cursor-pointer text-center" />
              <span className="text-[10px] text-blue-600 font-black uppercase tracking-widest mt-0.5">{isToday ? 'HOJE' : new Date(qualityDate + 'T12:00:00').toLocaleDateString('pt-BR', { weekday: 'short' })}</span>
            </div>
            <button onClick={() => changeQualityDate(1)} disabled={isToday} className={`p-2 transition-colors ${isToday ? 'text-slate-100' : 'text-slate-400 hover:text-blue-600'}`}><ChevronRight size={20} /></button>
          </div>

          {/* Gráfico de PH por Hora (Substituindo a Média Diária) */}
          <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm space-y-4">
            <div className="flex items-center justify-between">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Clock size={14} /> Ciclo de Qualidade (pH / Hora)</h3>
              {hourlyPhData.length > 0 && (
                <span className="text-[10px] font-black text-blue-600 bg-blue-50 px-2 py-1 rounded-full">{hourlyPhData.length} leituras</span>
              )}
            </div>

            <div className="h-56 w-full">
              {hourlyPhData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={hourlyPhData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                    <defs>
                      <linearGradient id="colorPhTime" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.2}/>
                        <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="time" tick={{fontSize: 9, fontWeight: 700, fill: '#94a3b8'}} />
                    <YAxis domain={[5.5, 9.5]} hide />
                    <Tooltip 
                      contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }}
                      formatter={(value: number) => [`${value} pH`, 'Nível']}
                    />
                    <Area 
                      type="monotone" 
                      dataKey="value" 
                      stroke="#3b82f6" 
                      strokeWidth={4} 
                      fillOpacity={1} 
                      fill="url(#colorPhTime)" 
                      animationDuration={1500}
                    />
                  </AreaChart>
                </ResponsiveContainer>
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-slate-300 gap-2 border-2 border-dashed border-slate-100 rounded-2xl">
                   <Droplet size={32} className="opacity-20" />
                   <span className="text-[10px] font-black uppercase tracking-widest italic">Sem dados horários</span>
                </div>
              )}
            </div>
          </div>

          <div className="bg-blue-600 p-6 rounded-[32px] text-white shadow-xl shadow-blue-100">
            {!showPHForm ? (
              <button onClick={() => setShowPHForm(true)} className="w-full flex items-center justify-between group">
                <div className="flex flex-col items-start"><span className="text-[10px] font-black opacity-70 uppercase tracking-widest mb-1">Análise de Campo</span><span className="text-xl font-black">Lançar Novo pH</span></div>
                <div className="bg-white/20 p-3 rounded-2xl group-active:scale-90 transition-transform"><Plus size={24} /></div>
              </button>
            ) : (
              <form onSubmit={handlePHSubmit} className="space-y-4 animate-scaleIn">
                <div className="flex justify-between items-center mb-2"><span className="text-xs font-black uppercase tracking-widest">Registrar Medição</span><button type="button" onClick={() => setShowPHForm(false)} className="opacity-60"><ChevronDown size={20} /></button></div>
                <div className="relative">
                  <input type="number" step="0.1" value={phValue} onChange={e => setPhValue(e.target.value)} placeholder="7.5" className="w-full bg-white/10 border border-white/20 rounded-2xl px-6 py-5 text-3xl font-black text-white focus:outline-none focus:ring-2 focus:ring-white/40 placeholder:text-white/30" autoFocus required />
                  <span className="absolute right-6 top-1/2 -translate-y-1/2 text-white/50 font-black text-xl italic uppercase">pH</span>
                </div>
                <button type="submit" className="w-full bg-white text-blue-700 font-black py-4 rounded-2xl shadow-lg active:scale-95 transition-all">SALVAR AGORA</button>
              </form>
            )}
          </div>

          <div className="space-y-3">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Linha do Tempo: {new Date(qualityDate + 'T12:00:00').toLocaleDateString('pt-BR')}</h3>
            {filteredPhRecords.length === 0 ? (
              <div className="bg-slate-50 border-2 border-dashed border-slate-200 rounded-3xl p-10 text-center text-slate-300 text-xs font-bold uppercase italic tracking-widest">Nenhuma leitura registrada</div>
            ) : (
              [...filteredPhRecords].reverse().map(r => (
                <div key={r.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between transition-all hover:scale-[1.01]">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-xl flex items-center justify-center font-black text-lg" style={{ backgroundColor: `${COLORS[r.status]}15`, color: COLORS[r.status] }}>{r.value.toFixed(1)}</div>
                    <div className="flex flex-col"><span className="font-bold text-slate-800 text-sm">Leitura de pH</span><span className="text-[10px] text-slate-400 flex items-center gap-1 uppercase tracking-tighter font-black"><Clock size={10} /> {new Date(r.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span></div>
                  </div>
                  <span className="px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest" style={{ backgroundColor: `${COLORS[r.status]}15`, color: COLORS[r.status] }}>{r.status}</span>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {activeTab === 'ai' && <AIAdvisor state={state} />}
      {activeTab === 'inventory' && (
        <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
          <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Uso de Insumos</h3>
          <div className="space-y-4">
            {state.inventory.map(item => {
              const totalOut = state.inventoryMovements.filter(m => m.itemId === item.id).reduce((sum, m) => sum + m.quantity, 0);
              return (
                <div key={item.id} className="flex flex-col gap-1">
                  <div className="flex justify-between items-center text-xs"><span className="font-bold text-slate-700">{item.name}</span><span className="font-black text-blue-600">{totalOut} {item.unit} saíram</span></div>
                  <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden"><div className="bg-blue-500 h-full rounded-full" style={{ width: `${Math.min(100, (totalOut / 100) * 100)}%` }}></div></div>
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
};

export default ReportsView;

import React, { useState, useMemo } from 'react';
import { BusinessState, Transaction, PHRecord } from '../types';
import AIAdvisor from './AIAdvisor';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  AreaChart, Area, ReferenceLine, ReferenceArea
} from 'recharts';
import { 
  History, 
  Package, 
  Sparkles, 
  ArrowUpRight, 
  ArrowDownLeft, 
  Landmark,
  Calendar,
  Droplet,
  Plus,
  ChevronDown,
  ChevronLeft,
  ChevronRight,
  Clock,
  TrendingUp,
  TrendingDown
} from 'lucide-react';

interface ReportsViewProps {
  state: BusinessState;
  onAddPH: (value: number) => void;
}

type ReportTab = 'transactions' | 'inventory' | 'quality' | 'ai';

const COLORS = {
  Ideal: '#22c55e',   // green-500
  Alerta: '#f59e0b',  // amber-500
  Crítico: '#ef4444', // red-500
};

const ReportsView: React.FC<ReportsViewProps> = ({ state, onAddPH }) => {
  const [activeTab, setActiveTab] = useState<ReportTab>('transactions');
  const [filterType, setFilterType] = useState<'all' | 'sale' | 'expense' | 'investment'>('all');
  const [phValue, setPhValue] = useState('');
  const [showPHForm, setShowPHForm] = useState(false);
  const [qualityDate, setQualityDate] = useState(new Date().toISOString().split('T')[0]);

  // Navegação de data para qualidade
  const changeQualityDate = (days: number) => {
    const current = new Date(qualityDate + 'T12:00:00');
    current.setDate(current.getDate() + days);
    setQualityDate(current.toISOString().split('T')[0]);
  };

  const isToday = qualityDate === new Date().toISOString().split('T')[0];

  // Dados para Gráfico de Vendas por Categoria (Mês Atual)
  const salesChartData = useMemo(() => {
    const now = new Date();
    const categories: Record<string, number> = {};

    state.transactions.forEach(t => {
      const d = new Date(t.date);
      if (t.type === 'sale' && d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear()) {
        categories[t.category] = (categories[t.category] || 0) + t.amount;
      }
    });

    return Object.entries(categories)
      .map(([name, total]) => ({ name, total }))
      .sort((a, b) => b.total - a.total);
  }, [state.transactions]);

  // Agrupamento de transações por data com resumos
  const groupedTransactions = useMemo(() => {
    const groups: Record<string, { 
      date: string, 
      sales: number, 
      expenses: number, 
      investments: number,
      items: Transaction[] 
    }> = {};

    state.transactions
      .filter(t => filterType === 'all' || t.type === filterType)
      .forEach(t => {
        const dateKey = new Date(t.date).toISOString().split('T')[0];
        if (!groups[dateKey]) {
          groups[dateKey] = { 
            date: dateKey, 
            sales: 0, 
            expenses: 0, 
            investments: 0, 
            items: [] 
          };
        }
        if (t.type === 'sale') groups[dateKey].sales += t.amount;
        else if (t.type === 'expense') groups[dateKey].expenses += t.amount;
        else if (t.type === 'investment') groups[dateKey].investments += t.amount;
        groups[dateKey].items.push(t);
      });

    return Object.values(groups).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [state.transactions, filterType]);

  // Filtragem de registros de pH por data selecionada
  const filteredPhRecords = useMemo(() => {
    return state.phRecords
      .filter(r => new Date(r.date).toISOString().split('T')[0] === qualityDate)
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [state.phRecords, qualityDate]);

  // Dados para Gráfico de PH por Hora
  const hourlyPhData = useMemo(() => {
    return filteredPhRecords.map(r => ({
      time: new Date(r.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      value: r.value,
      status: r.status
    }));
  }, [filteredPhRecords]);

  const handlePHSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const val = parseFloat(phValue);
    if (!isNaN(val)) {
      onAddPH(val);
      setPhValue('');
      setShowPHForm(false);
      setQualityDate(new Date().toISOString().split('T')[0]);
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn pb-12">
      <div className="flex flex-col gap-1">
        <h2 className="text-2xl font-black text-slate-800 tracking-tight">Relatórios</h2>
        <p className="text-slate-500 text-sm">Desempenho financeiro e controle de qualidade.</p>
      </div>

      <div className="flex bg-slate-200/50 p-1 rounded-2xl overflow-x-auto no-scrollbar">
        <button onClick={() => setActiveTab('transactions')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'transactions' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><History size={14} /> Histórico</button>
        <button onClick={() => setActiveTab('inventory')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'inventory' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><Package size={14} /> Estoque</button>
        <button onClick={() => setActiveTab('quality')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'quality' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><Droplet size={14} /> Qualidade</button>
        <button onClick={() => setActiveTab('ai')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'ai' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><Sparkles size={14} /> IA</button>
      </div>

      {activeTab === 'transactions' && (
        <div className="space-y-6">
          <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2"><TrendingUp size={12} /> Desempenho por Categoria (Mês Atual)</h3>
            <div className="h-64 w-full">
              {salesChartData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={salesChartData} layout="vertical" margin={{ left: -20, right: 20 }}>
                    <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f1f5f9" />
                    <XAxis type="number" hide />
                    <YAxis dataKey="name" type="category" width={100} tick={{ fontSize: 10, fontWeight: 700, fill: '#64748b' }} />
                    <Tooltip cursor={{ fill: '#f8fafc' }} formatter={(value: number) => `${value.toLocaleString()} Kz`} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }} />
                    <Bar dataKey="total" fill="#3b82f6" radius={[0, 8, 8, 0]} barSize={20} />
                  </BarChart>
                </ResponsiveContainer>
              ) : <div className="h-full flex items-center justify-center text-slate-300 text-xs italic">Sem vendas este mês.</div>}
            </div>
          </div>

          <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1">
            {(['all', 'sale', 'expense', 'investment'] as const).map(type => (
              <button key={type} onClick={() => setFilterType(type)} className={`px-4 py-2 rounded-full text-[10px] font-bold whitespace-nowrap transition-all border ${filterType === type ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-slate-500 border-slate-200'}`}>{type === 'all' ? 'TUDO' : type === 'sale' ? 'VENDAS' : type === 'expense' ? 'SAÍDAS' : 'INVESTIMENTOS'}</button>
            ))}
          </div>

          <div className="space-y-6">
            {groupedTransactions.map(group => (
              <div key={group.date} className="space-y-3">
                <div className="flex items-center justify-between px-1">
                  <div className="flex flex-col">
                    <span className="text-xs font-black text-slate-800">{new Date(group.date + 'T12:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: 'long', weekday: 'short' })}</span>
                  </div>
                  <div className="flex gap-2">
                    {group.sales > 0 && <span className="text-[9px] font-black text-green-600 bg-green-50 px-2 py-1 rounded-lg">+{group.sales.toLocaleString()}</span>}
                    {group.expenses > 0 && <span className="text-[9px] font-black text-red-600 bg-red-50 px-2 py-1 rounded-lg">-{group.expenses.toLocaleString()}</span>}
                    {group.investments > 0 && <span className="text-[9px] font-black text-amber-600 bg-amber-50 px-2 py-1 rounded-lg">-{group.investments.toLocaleString()}</span>}
                  </div>
                </div>

                <div className="space-y-2">
                  {group.items.reverse().map(t => (
                    <div key={t.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between transition-all hover:scale-[1.01]">
                      <div className="flex items-center gap-3">
                        <div className={`p-2 rounded-xl ${t.type === 'sale' ? 'bg-green-50 text-green-600' : t.type === 'expense' ? 'bg-red-50 text-red-600' : 'bg-amber-50 text-amber-600'}`}>
                          {t.type === 'sale' ? <ArrowUpRight size={16} /> : t.type === 'expense' ? <ArrowDownLeft size={16} /> : <Landmark size={16} />}
                        </div>
                        <div className="flex flex-col">
                          <span className="font-bold text-slate-800 text-sm leading-none mb-1">{t.category}</span>
                          <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">{new Date(t.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                        </div>
                      </div>
                      <span className={`font-black text-sm ${t.type === 'sale' ? 'text-green-600' : 'text-red-600'}`}>
                        {t.type === 'sale' ? '+' : '-'} {t.amount.toLocaleString()} Kz
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'quality' && (
        <div className="space-y-6 animate-fadeIn">
          {/* Filtro de Data para Qualidade */}
          <div className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center justify-between">
            <button onClick={() => changeQualityDate(-1)} className="p-2 text-slate-400 hover:text-blue-600 transition-colors"><ChevronLeft size={20} /></button>
            <div className="flex flex-col items-center">
              <input type="date" value={qualityDate} onChange={(e) => setQualityDate(e.target.value)} className="text-sm font-black text-slate-800 focus:outline-none bg-transparent cursor-pointer text-center" />
              <span className="text-[10px] text-blue-600 font-black uppercase tracking-widest mt-0.5">{isToday ? 'HOJE' : new Date(qualityDate + 'T12:00:00').toLocaleDateString('pt-BR', { weekday: 'short' })}</span>
            </div>
            <button onClick={() => changeQualityDate(1)} disabled={isToday} className={`p-2 transition-colors ${isToday ? 'text-slate-100' : 'text-slate-400 hover:text-blue-600'}`}><ChevronRight size={20} /></button>
          </div>

          {/* Gráfico de PH por Hora com UX melhorado */}
          <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm space-y-4">
            <div className="flex items-center justify-between">
              <div className="flex flex-col">
                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Clock size={14} /> Ciclo de Purificação</h3>
                <span className="text-[8px] font-bold text-slate-300 uppercase tracking-widest">Ideal: 7.0 - 8.0 pH</span>
              </div>
              {hourlyPhData.length > 0 && (
                <div className="flex items-center gap-1 bg-green-50 px-2 py-1 rounded-lg">
                  <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                  <span className="text-[9px] font-black text-green-700 uppercase">{hourlyPhData.length} Pontos</span>
                </div>
              )}
            </div>

            <div className="h-64 w-full relative">
              {hourlyPhData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={hourlyPhData} margin={{ top: 10, right: 5, left: -25, bottom: 0 }}>
                    <defs>
                      <linearGradient id="colorPhTime" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.3}/>
                        <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis 
                      dataKey="time" 
                      tick={{fontSize: 9, fontWeight: 700, fill: '#94a3b8'}} 
                      axisLine={false}
                      tickLine={false}
                    />
                    <YAxis 
                      domain={[5, 10]} 
                      ticks={[6, 7, 8, 9]}
                      tick={{fontSize: 9, fontWeight: 700, fill: '#94a3b8'}}
                      axisLine={false}
                      tickLine={false}
                    />
                    <Tooltip 
                      contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)', padding: '12px' }}
                      formatter={(value: number) => [`${value} pH`, 'Nível']}
                      labelStyle={{ fontWeight: '800', fontSize: '10px', color: '#64748b', marginBottom: '4px' }}
                    />
                    {/* Faixa Ideal */}
                    <ReferenceArea y1={7} y2={8} fill="#22c55e" fillOpacity={0.05} />
                    {/* Linhas de Alerta */}
                    <ReferenceLine y={6.5} stroke="#f59e0b" strokeDasharray="3 3" label={{ position: 'right', value: 'Min', fill: '#f59e0b', fontSize: 8, fontWeight: 'bold' }} />
                    <ReferenceLine y={8.5} stroke="#f59e0b" strokeDasharray="3 3" label={{ position: 'right', value: 'Max', fill: '#f59e0b', fontSize: 8, fontWeight: 'bold' }} />

                    <Area 
                      type="monotone" 
                      dataKey="value" 
                      stroke="#3b82f6" 
                      strokeWidth={4} 
                      fillOpacity={1} 
                      fill="url(#colorPhTime)" 
                      animationDuration={1500}
                      dot={{ r: 4, fill: '#3b82f6', strokeWidth: 2, stroke: '#fff' }}
                      activeDot={{ r: 6, strokeWidth: 0 }}
                    />
                  </AreaChart>
                </ResponsiveContainer>
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-slate-300 gap-2 border-2 border-dashed border-slate-100 rounded-2xl">
                   <Droplet size={32} className="opacity-20" />
                   <span className="text-[10px] font-black uppercase tracking-widest italic">Sem dados registrados</span>
                </div>
              )}
            </div>
          </div>

          <div className="bg-blue-600 p-6 rounded-[32px] text-white shadow-xl shadow-blue-100">
            {!showPHForm ? (
              <button onClick={() => setShowPHForm(true)} className="w-full flex items-center justify-between group">
                <div className="flex flex-col items-start"><span className="text-[10px] font-black opacity-70 uppercase tracking-widest mb-1">Qualidade de Água</span><span className="text-xl font-black">Lançar Novo pH</span></div>
                <div className="bg-white/20 p-3 rounded-2xl group-active:scale-90 transition-transform"><Plus size={24} /></div>
              </button>
            ) : (
              <form onSubmit={handlePHSubmit} className="space-y-4 animate-scaleIn">
                <div className="flex justify-between items-center mb-2"><span className="text-xs font-black uppercase tracking-widest">Registrar Medição</span><button type="button" onClick={() => setShowPHForm(false)} className="opacity-60"><ChevronDown size={20} /></button></div>
                <div className="relative">
                  <input type="number" step="0.1" value={phValue} onChange={e => setPhValue(e.target.value)} placeholder="7.5" className="w-full bg-white/10 border border-white/20 rounded-2xl px-6 py-5 text-3xl font-black text-white focus:outline-none focus:ring-2 focus:ring-white/40 placeholder:text-white/30" autoFocus required />
                  <span className="absolute right-6 top-1/2 -translate-y-1/2 text-white/50 font-black text-xl italic uppercase">pH</span>
                </div>
                <button type="submit" className="w-full bg-white text-blue-700 font-black py-4 rounded-2xl shadow-lg active:scale-95 transition-all">SALVAR AGORA</button>
              </form>
            )}
          </div>

          <div className="space-y-3">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Linha do Tempo: {new Date(qualityDate + 'T12:00:00').toLocaleDateString('pt-BR')}</h3>
            {filteredPhRecords.length === 0 ? (
              <div className="bg-slate-50 border-2 border-dashed border-slate-200 rounded-3xl p-10 text-center text-slate-300 text-xs font-bold uppercase italic tracking-widest">Nenhuma leitura</div>
            ) : (
              [...filteredPhRecords].reverse().map(r => (
                <div key={r.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between transition-all hover:scale-[1.01]">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-xl flex items-center justify-center font-black text-lg" style={{ backgroundColor: `${COLORS[r.status]}15`, color: COLORS[r.status] }}>{r.value.toFixed(1)}</div>
                    <div className="flex flex-col"><span className="font-bold text-slate-800 text-sm">Leitura de pH</span><span className="text-[10px] text-slate-400 flex items-center gap-1 uppercase tracking-tighter font-black"><Clock size={10} /> {new Date(r.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span></div>
                  </div>
                  <span className="px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest" style={{ backgroundColor: `${COLORS[r.status]}15`, color: COLORS[r.status] }}>{r.status}</span>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {activeTab === 'ai' && <AIAdvisor state={state} />}

      {activeTab === 'inventory' && (
        <div className="space-y-6">
          <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2"><Package size={14} /> Uso de Insumos</h3>
            <div className="space-y-6">
              {state.inventory.map(item => {
                const totalOut = state.inventoryMovements.filter(m => m.itemId === item.id).reduce((sum, m) => sum + m.quantity, 0);
                const percent = Math.min(100, (totalOut / (totalOut + item.quantity || 1)) * 100);
                return (
                  <div key={item.id} className="flex flex-col gap-2">
                    <div className="flex justify-between items-end">
                      <div className="flex flex-col">
                        <span className="font-black text-slate-700 text-sm">{item.name}</span>
                        <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">Disponível: {item.quantity} {item.unit}</span>
                      </div>
                      <span className="font-black text-blue-600 text-xs">{totalOut} {item.unit} consumidos</span>
                    </div>
                    <div className="w-full bg-slate-100 h-2.5 rounded-full overflow-hidden">
                      <div className={`h-full rounded-full transition-all duration-1000 ${item.quantity <= item.minThreshold ? 'bg-red-500' : 'bg-blue-500'}`} style={{ width: `${percent}%` }}></div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ReportsView;

import React, { useState, useMemo } from 'react';
import { BusinessState, Transaction, PHRecord } from '../types';
import AIAdvisor from './AIAdvisor';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  AreaChart, Area, ReferenceLine, ReferenceArea
} from 'recharts';
import { 
  History, 
  Package, 
  Sparkles, 
  ArrowUpRight, 
  ArrowDownLeft, 
  Landmark,
  Calendar,
  Droplet,
  Plus,
  ChevronDown,
  ChevronLeft,
  ChevronRight,
  Clock,
  TrendingUp,
  TrendingDown
} from 'lucide-react';

interface ReportsViewProps {
  state: BusinessState;
  onAddPH: (value: number) => void;
}

type ReportTab = 'transactions' | 'inventory' | 'quality' | 'ai';

const COLORS = {
  Ideal: '#22c55e',   // green-500
  Alerta: '#f59e0b',  // amber-500
  Crítico: '#ef4444', // red-500
};

const ReportsView: React.FC<ReportsViewProps> = ({ state, onAddPH }) => {
  const [activeTab, setActiveTab] = useState<ReportTab>('transactions');
  const [filterType, setFilterType] = useState<'all' | 'sale' | 'expense' | 'investment'>('all');
  const [phValue, setPhValue] = useState('');
  const [showPHForm, setShowPHForm] = useState(false);
  const [qualityDate, setQualityDate] = useState(new Date().toISOString().split('T')[0]);

  // Navegação de data para qualidade
  const changeQualityDate = (days: number) => {
    const current = new Date(qualityDate + 'T12:00:00');
    current.setDate(current.getDate() + days);
    setQualityDate(current.toISOString().split('T')[0]);
  };

  const isToday = qualityDate === new Date().toISOString().split('T')[0];

  // Agrupamento de transações por data com resumos diários
  const groupedTransactions = useMemo(() => {
    const groups: Record<string, { 
      date: string, 
      sales: number, 
      expenses: number, 
      investments: number,
      items: Transaction[] 
    }> = {};

    state.transactions
      .filter(t => filterType === 'all' || t.type === filterType)
      .forEach(t => {
        const dateKey = new Date(t.date).toISOString().split('T')[0];
        if (!groups[dateKey]) {
          groups[dateKey] = { 
            date: dateKey, 
            sales: 0, 
            expenses: 0, 
            investments: 0, 
            items: [] 
          };
        }
        if (t.type === 'sale') groups[dateKey].sales += t.amount;
        else if (t.type === 'expense') groups[dateKey].expenses += t.amount;
        else if (t.type === 'investment') groups[dateKey].investments += t.amount;
        groups[dateKey].items.push(t);
      });

    return Object.values(groups).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [state.transactions, filterType]);

  // Filtragem de registros de pH por data selecionada
  const filteredPhRecords = useMemo(() => {
    return state.phRecords
      .filter(r => new Date(r.date).toISOString().split('T')[0] === qualityDate)
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [state.phRecords, qualityDate]);

  // Dados para Gráfico de PH por Hora
  const hourlyPhData = useMemo(() => {
    return filteredPhRecords.map(r => ({
      time: new Date(r.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      value: r.value,
      status: r.status
    }));
  }, [filteredPhRecords]);

  const handlePHSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const val = parseFloat(phValue);
    if (!isNaN(val)) {
      onAddPH(val);
      setPhValue('');
      setShowPHForm(false);
      setQualityDate(new Date().toISOString().split('T')[0]);
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn pb-12">
      <div className="flex flex-col gap-1">
        <h2 className="text-2xl font-black text-slate-800 tracking-tight">Relatórios</h2>
        <p className="text-slate-500 text-sm">Controle financeiro e análise de qualidade.</p>
      </div>

      <div className="flex bg-slate-200/50 p-1 rounded-2xl overflow-x-auto no-scrollbar">
