import { GoogleGenAI } from "@google/genai";
import { BusinessState } from "../types";

export const getBusinessInsights = async (state: BusinessState, type: 'daily' | 'monthly' = 'daily'): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const salesTotal = state.transactions
    .filter(t => t.type === 'sale')
    .reduce((acc, t) => acc + t.amount, 0);

  const expensesTotal = state.transactions
    .filter(t => t.type === 'expense')
    .reduce((acc, t) => acc + t.amount, 0);

  const investmentTotal = state.transactions
    .filter(t => t.type === 'investment')
    .reduce((acc, t) => acc + t.amount, 0);

  const netProfit = salesTotal - expensesTotal - investmentTotal;

  const contextPrompt = `
    Você é o consultor estratégico da "Agua Cristalina", uma loja de água purificada em Luanda, Angola.
    DADOS FINANCEIROS ATUAIS (Kz):
    - Faturamento: ${salesTotal.toLocaleString()} Kz
    - Despesas Operacionais: ${expensesTotal.toLocaleString()} Kz
    - Investimentos: ${investmentTotal.toLocaleString()} Kz
    - Lucro Líquido: ${netProfit.toLocaleString()} Kz
    - Estoque: ${state.inventory.map(i => `${i.name} (${i.quantity}${i.unit})`).join(', ')}
    - Qualidade (pH médio): ${state.phRecords.length > 0 ? (state.phRecords.reduce((a,b) => a + b.value, 0) / state.phRecords.length).toFixed(1) : 'Sem dados'}
  `;

  const requestPrompt = type === 'monthly' 
    ? `Com base nestes dados, elabore um RELATÓRIO ESTRATÉGICO MENSAL. 
       Inclua:
       1. Diagnóstico da Saúde do Negócio (Considere sazonalidade e inflação em Angola).
       2. SUGESTÃO DE NOVOS PRODUTOS ou Serviços (ex: águas saborizadas, gelo gourmet, planos de assinatura).
       3. ESTRATÉGIAS DE MARKETING para aumentar a fidelização (Redes sociais, parcerias, branding).
       4. Otimização de Custos e Expansão.
       Use um tom executivo, motivador e focado em lucro.`
    : `Forneça uma análise rápida do desempenho atual.
       1. Insight de Vendas e Margem.
       2. Alerta de Estoque ou Qualidade.
       3. Uma dica prática para aplicar amanhã na loja.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: contextPrompt + "\n\n" + requestPrompt,
      config: { temperature: 0.8, topP: 0.95 }
    });
    return response.text || "Desculpe, não consegui gerar a análise agora.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Erro ao conectar com a consultoria IA. Verifique sua conexão.";
  }
};

