export const sendChatMessage = async (state: BusinessState, history: ChatMessage[], newMessage: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const systemInstruction = getContextPrompt(state) + "\nResponda às dúvidas do dono da loja sobre os dados acima ou estratégias de negócio.";

  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: { 
        systemInstruction,
        temperature: 0.8
      }
    });

    // Enviamos a mensagem (o histórico é gerenciado pelo componente para simplicidade visual, 
    // mas aqui poderíamos iterar sendMessage se quiséssemos manter o histórico no SDK)
    const response = await chat.sendMessage({ message: newMessage });
    return response.text || "Não entendi sua pergunta.";
  } catch (error) {
    console.error(error);
    return "Erro no chat. Tente novamente.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { BusinessState } from '../types';
import { getBusinessInsights, sendChatMessage, ChatMessage } from '../services/geminiService';
