            {isTyping && (
              <div className="flex justify-start">
                <div className="bg-slate-100 p-4 rounded-3xl rounded-tl-none flex gap-1">
                  <div className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce"></div>
                  <div className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                  <div className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                </div>
              </div>
            )}
          </div>

          <form onSubmit={handleSendMessage} className="flex-shrink-0 bg-white p-2 rounded-3xl border border-slate-200 flex gap-2">
            <input 
              value={userInput}
              onChange={e => setUserInput(e.target.value)}
              placeholder="Pergunte sobre vendas ou estoque..."
              className="flex-1 bg-transparent px-4 py-3 text-xs font-bold text-slate-800 focus:outline-none"
            />
            <button 
              type="submit"
              disabled={isTyping}
              className="bg-blue-600 text-white p-3 rounded-2xl active:scale-90 transition-transform disabled:opacity-50"
            >
              <Send size={18} />
            </button>
          </form>
        </div>
      )}
    </div>
  );
};

export default AIAdvisor;

import React, { useState, useMemo } from 'react';
import { BusinessState, Transaction, PHRecord } from '../types';
import AIAdvisor from './AIAdvisor';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  AreaChart, Area, ReferenceLine, ReferenceArea
} from 'recharts';
import { 
  History, 
  Package, 
  Sparkles, 
  ArrowUpRight, 
  ArrowDownLeft, 
  Landmark,
  Calendar,
  Droplet,
  Plus,
  ChevronDown,
  ChevronLeft,
  ChevronRight,
  Clock,
  TrendingUp,
  BarChart3,
  CircleDollarSign
} from 'lucide-react';

interface ReportsViewProps {
  state: BusinessState;
  onAddPH: (value: number) => void;
}

type ReportTab = 'transactions' | 'inventory' | 'quality' | 'ai';

const COLORS = {
  Ideal: '#22c55e',   // green-500
  Alerta: '#f59e0b',  // amber-500
  Crítico: '#ef4444', // red-500
};

const ReportsView: React.FC<ReportsViewProps> = ({ state, onAddPH }) => {
  const [activeTab, setActiveTab] = useState<ReportTab>('transactions');
  const [filterType, setFilterType] = useState<'all' | 'sale' | 'expense' | 'investment'>('all');
  const [phValue, setPhValue] = useState('');
  const [showPHForm, setShowPHForm] = useState(false);
  const [qualityDate, setQualityDate] = useState(new Date().toISOString().split('T')[0]);

  // Navegação de data para qualidade
  const changeQualityDate = (days: number) => {
    const current = new Date(qualityDate + 'T12:00:00');
    current.setDate(current.getDate() + days);
    setQualityDate(current.toISOString().split('T')[0]);
  };

  const isToday = qualityDate === new Date().toISOString().split('T')[0];

  // Estatísticas Mensais
  const monthlyStats = useMemo(() => {
    const now = new Date();
    const currentMonth = now.getMonth();
    const currentYear = now.getFullYear();
    const daysInMonth = now.getDate(); // Dias transcorridos até hoje no mês

    const monthlySales = state.transactions.filter(t => {
      const d = new Date(t.date);
      return t.type === 'sale' && d.getMonth() === currentMonth && d.getFullYear() === currentYear;
    });

    const totalSales = monthlySales.reduce((sum, t) => sum + t.amount, 0);
    const avgDaily = daysInMonth > 0 ? totalSales / daysInMonth : 0;

    const categories: Record<string, number> = {};
    monthlySales.forEach(t => {
      categories[t.category] = (categories[t.category] || 0) + t.amount;
    });

    const bestCategory = Object.entries(categories).sort((a, b) => b[1] - a[1])[0]?.[0] || 'N/A';

    return {
      totalSales,
      avgDaily,
      bestCategory,
      monthName: new Intl.DateTimeFormat('pt-BR', { month: 'long' }).format(now)
    };
  }, [state.transactions]);

  // Agrupamento de transações por data com resumos diários
  const groupedTransactions = useMemo(() => {
    const groups: Record<string, { 
      date: string, 
      sales: number, 
      expenses: number, 
      investments: number,
      items: Transaction[] 
    }> = {};

    state.transactions
      .filter(t => filterType === 'all' || t.type === filterType)
      .forEach(t => {
        const dateKey = new Date(t.date).toISOString().split('T')[0];
        if (!groups[dateKey]) {
          groups[dateKey] = { 
            date: dateKey, 
            sales: 0, 
            expenses: 0, 
            investments: 0, 
            items: [] 
          };
        }
        if (t.type === 'sale') groups[dateKey].sales += t.amount;
        else if (t.type === 'expense') groups[dateKey].expenses += t.amount;
        else if (t.type === 'investment') groups[dateKey].investments += t.amount;
        groups[dateKey].items.push(t);
      });

    return Object.values(groups).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [state.transactions, filterType]);

  // Filtragem de registros de pH por data selecionada
  const filteredPhRecords = useMemo(() => {
    return state.phRecords
      .filter(r => new Date(r.date).toISOString().split('T')[0] === qualityDate)
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [state.phRecords, qualityDate]);

  // Dados para Gráfico de PH por Hora
  const hourlyPhData = useMemo(() => {
    return filteredPhRecords.map(r => ({
      time: new Date(r.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      value: r.value,
      status: r.status
    }));
  }, [filteredPhRecords]);

  const handlePHSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const val = parseFloat(phValue);
    if (!isNaN(val)) {
      onAddPH(val);
      setPhValue('');
      setShowPHForm(false);
      setQualityDate(new Date().toISOString().split('T')[0]);
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn pb-12">
      <div className="flex flex-col gap-1">
        <h2 className="text-2xl font-black text-slate-800 tracking-tight">Relatórios</h2>
        <p className="text-slate-500 text-sm">Controle financeiro e análise de qualidade.</p>
      </div>

      <div className="flex bg-slate-200/50 p-1 rounded-2xl overflow-x-auto no-scrollbar">
        <button onClick={() => setActiveTab('transactions')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'transactions' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><History size={14} /> Histórico</button>
        <button onClick={() => setActiveTab('inventory')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'inventory' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><Package size={14} /> Estoque</button>
        <button onClick={() => setActiveTab('quality')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'quality' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><Droplet size={14} /> Qualidade</button>
        <button onClick={() => setActiveTab('ai')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'ai' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><Sparkles size={14} /> IA</button>
      </div>

      {activeTab === 'transactions' && (
        <div className="space-y-6">
          {/* Novo Resumo Mensal */}
          <div className="bg-gradient-to-br from-blue-600 to-indigo-700 p-6 rounded-[32px] text-white shadow-xl shadow-blue-100 relative overflow-hidden">
            <div className="relative z-10 space-y-4">
              <div className="flex items-center justify-between">
                <span className="text-[10px] font-black uppercase tracking-widest opacity-80">Resumo de {monthlyStats.monthName}</span>
                <div className="bg-white/20 p-2 rounded-xl">
                  <TrendingUp size={16} />
                </div>
              </div>

              <div className="space-y-1">
                <span className="text-[10px] font-black opacity-70 uppercase tracking-widest">Faturamento Total</span>
                <h3 className="text-3xl font-black">{monthlyStats.totalSales.toLocaleString()} Kz</h3>
              </div>

              <div className="grid grid-cols-2 gap-4 pt-2">
                <div className="bg-white/10 p-3 rounded-2xl backdrop-blur-sm border border-white/10">
                  <div className="flex items-center gap-2 mb-1">
                    <BarChart3 size={12} className="opacity-70" />
                    <span className="text-[8px] font-black uppercase tracking-widest opacity-70">Top Categoria</span>
                  </div>
                  <span className="text-[11px] font-black truncate block">{monthlyStats.bestCategory}</span>
                </div>
                <div className="bg-white/10 p-3 rounded-2xl backdrop-blur-sm border border-white/10">
                  <div className="flex items-center gap-2 mb-1">
                    <CircleDollarSign size={12} className="opacity-70" />
                    <span className="text-[8px] font-black uppercase tracking-widest opacity-70">Média Diária</span>
                  </div>
                  <span className="text-[11px] font-black">{Math.round(monthlyStats.avgDaily).toLocaleString()} Kz</span>
                </div>
              </div>
            </div>
            <Sparkles size={140} className="absolute -right-12 -bottom-12 text-white opacity-5" />
          </div>

          <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1">
            {(['all', 'sale', 'expense', 'investment'] as const).map(type => (
              <button key={type} onClick={() => setFilterType(type)} className={`px-4 py-2 rounded-full text-[10px] font-bold whitespace-nowrap transition-all border ${filterType === type ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-slate-500 border-slate-200'}`}>{type === 'all' ? 'TUDO' : type === 'sale' ? 'VENDAS' : type === 'expense' ? 'SAÍDAS' : 'INVESTIMENTOS'}</button>
            ))}
          </div>

          <div className="space-y-8">
            {groupedTransactions.map(group => (
              <div key={group.date} className="space-y-3">
                {/* Cabeçalho do Dia com Resumo */}
                <div className="sticky top-0 bg-slate-50/90 backdrop-blur-md py-2 z-10 flex flex-col gap-2">
                  <span className="text-xs font-black text-slate-400 uppercase tracking-widest px-1">
                    {new Date(group.date + 'T12:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: 'long', weekday: 'short' })}
                  </span>
                  <div className="grid grid-cols-3 gap-2">
                    <div className="bg-white p-2 rounded-xl border border-slate-100 flex flex-col items-center">
                      <span className="text-[8px] font-black text-slate-400 uppercase">Vendas</span>
                      <span className="text-[10px] font-black text-green-600">+{group.sales.toLocaleString()}</span>
                    </div>
                    <div className="bg-white p-2 rounded-xl border border-slate-100 flex flex-col items-center">
                      <span className="text-[8px] font-black text-slate-400 uppercase">Saídas</span>
                      <span className="text-[10px] font-black text-red-600">-{group.expenses.toLocaleString()}</span>
                    </div>
                    <div className="bg-white p-2 rounded-xl border border-slate-100 flex flex-col items-center">
                      <span className="text-[8px] font-black text-slate-400 uppercase">Invest.</span>
                      <span className="text-[10px] font-black text-amber-600">-{group.investments.toLocaleString()}</span>
                    </div>
                  </div>
                </div>

                <div className="space-y-2">
                  {group.items.reverse().map(t => (
                    <div key={t.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between transition-all active:scale-95">
                      <div className="flex items-center gap-3">
                        <div className={`p-2 rounded-xl ${t.type === 'sale' ? 'bg-green-50 text-green-600' : t.type === 'expense' ? 'bg-red-50 text-red-600' : 'bg-amber-50 text-amber-600'}`}>
                          {t.type === 'sale' ? <ArrowUpRight size={16} /> : t.type === 'expense' ? <ArrowDownLeft size={16} /> : <Landmark size={16} />}
                        </div>
                        <div className="flex flex-col">
                          <span className="font-bold text-slate-800 text-sm mb-0.5 leading-none">{t.category}</span>
                          <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">{new Date(t.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                        </div>
                      </div>
                      <span className={`font-black text-sm ${t.type === 'sale' ? 'text-green-600' : 'text-red-600'}`}>
                        {t.type === 'sale' ? '+' : '-'} {t.amount.toLocaleString()} Kz
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'quality' && (
        <div className="space-y-6 animate-fadeIn">
          {/* Seletor de Data */}
          <div className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center justify-between">
            <button onClick={() => changeQualityDate(-1)} className="p-2 text-slate-400 hover:text-blue-600 transition-colors"><ChevronLeft size={20} /></button>
            <div className="flex flex-col items-center">
              <input type="date" value={qualityDate} onChange={(e) => setQualityDate(e.target.value)} className="text-sm font-black text-slate-800 focus:outline-none bg-transparent cursor-pointer text-center" />
              <span className="text-[10px] text-blue-600 font-black uppercase tracking-widest mt-0.5">{isToday ? 'HOJE' : new Date(qualityDate + 'T12:00:00').toLocaleDateString('pt-BR', { weekday: 'short' })}</span>
            </div>
            <button onClick={() => changeQualityDate(1)} disabled={isToday} className={`p-2 transition-colors ${isToday ? 'text-slate-100' : 'text-slate-400 hover:text-blue-600'}`}><ChevronRight size={20} /></button>
          </div>

          {/* Gráfico de Qualidade */}
          <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm space-y-4">
            <div className="flex items-center justify-between">
              <div className="flex flex-col">
                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Clock size={14} /> Ciclo de Purificação</h3>
                <span className="text-[8px] font-bold text-slate-300 uppercase tracking-widest">Alvo: 7.2 - 7.8 pH</span>
              </div>
            </div>

            <div className="h-64 w-full relative">
              {hourlyPhData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={hourlyPhData} margin={{ top: 20, right: 10, left: -25, bottom: 0 }}>
                    <defs>
                      <linearGradient id="colorPhTime" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.4}/>
                        <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis 
                      dataKey="time" 
                      tick={{fontSize: 9, fontWeight: 700, fill: '#94a3b8'}} 
                      axisLine={false}
                      tickLine={false}
                    />
                    <YAxis 
                      domain={[5.5, 9.5]} 
                      ticks={[6, 7, 8, 9]}
                      tick={{fontSize: 9, fontWeight: 700, fill: '#94a3b8'}}
                      axisLine={false}
                      tickLine={false}
                    />
                    <Tooltip 
                      contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)', padding: '12px' }}
                      formatter={(value: number) => [`${value} pH`, 'Leitura']}
                      labelStyle={{ fontWeight: '800', fontSize: '10px', color: '#64748b', marginBottom: '4px' }}
                    />

                    {/* Faixa de Segurança Ideal */}
                    <ReferenceArea y1={7} y2={8} fill="#22c55e" fillOpacity={0.08} />

                    {/* Linhas de Limite Crítico */}
                    <ReferenceLine y={6.5} stroke="#f59e0b" strokeDasharray="5 5" strokeWidth={1} label={{ position: 'right', value: 'Min', fill: '#f59e0b', fontSize: 8, fontWeight: '900' }} />
                    <ReferenceLine y={8.5} stroke="#f59e0b" strokeDasharray="5 5" strokeWidth={1} label={{ position: 'right', value: 'Max', fill: '#f59e0b', fontSize: 8, fontWeight: '900' }} />

                    <Area 
                      type="monotone" 
                      dataKey="value" 
                      stroke="#2563eb" 
                      strokeWidth={3} 
                      fillOpacity={1} 
                      fill="url(#colorPhTime)" 
                      animationDuration={1500}
                      dot={{ r: 4, fill: '#2563eb', strokeWidth: 2, stroke: '#fff' }}
                      activeDot={{ r: 6, strokeWidth: 0 }}
                    />
                  </AreaChart>
                </ResponsiveContainer>
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-slate-300 gap-2 border-2 border-dashed border-slate-100 rounded-2xl bg-slate-50/30">
                   <Droplet size={32} className="opacity-20" />
                   <span className="text-[10px] font-black uppercase tracking-widest italic">Sem leituras registradas</span>
                </div>
              )}
            </div>
          </div>

          {/* Botão de Lançamento */}
          <div className="bg-blue-600 p-6 rounded-[32px] text-white shadow-xl shadow-blue-100">
            {!showPHForm ? (
              <button onClick={() => setShowPHForm(true)} className="w-full flex items-center justify-between group">
                <div className="flex flex-col items-start">
                  <span className="text-[10px] font-black opacity-70 uppercase tracking-widest mb-1">Qualidade de Água</span>
                  <span className="text-xl font-black">Lançar Novo pH</span>
                </div>
                <div className="bg-white/20 p-3 rounded-2xl group-active:scale-90 transition-transform"><Plus size={24} /></div>
              </button>
            ) : (
              <form onSubmit={handlePHSubmit} className="space-y-4 animate-scaleIn">
                <div className="flex justify-between items-center mb-2">
                  <span className="text-xs font-black uppercase tracking-widest">Registrar Medição</span>
                  <button type="button" onClick={() => setShowPHForm(false)} className="opacity-60"><ChevronDown size={20} /></button>
                </div>
                <div className="relative">
                  <input 
                    type="number" 
                    step="0.1" 
                    value={phValue} 
                    onChange={e => setPhValue(e.target.value)} 
                    placeholder="7.5" 
                    className="w-full bg-white/10 border border-white/20 rounded-2xl px-6 py-5 text-3xl font-black text-white focus:outline-none focus:ring-2 focus:ring-white/40 placeholder:text-white/30" 
                    autoFocus 
                    required 
                  />
                  <span className="absolute right-6 top-1/2 -translate-y-1/2 text-white/50 font-black text-xl italic uppercase">pH</span>
                </div>
                <button type="submit" className="w-full bg-white text-blue-700 font-black py-4 rounded-2xl shadow-lg active:scale-95 transition-all">SALVAR AGORA</button>
              </form>
            )}
          </div>

          <div className="space-y-3">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Linha do Tempo</h3>
            {filteredPhRecords.length === 0 ? (
              <div className="bg-slate-50 border-2 border-dashed border-slate-200 rounded-3xl p-10 text-center text-slate-300 text-xs font-bold uppercase italic tracking-widest">Nenhuma leitura registrada</div>
            ) : (
              [...filteredPhRecords].reverse().map(r => (
                <div key={r.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between transition-all active:scale-[0.98]">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-xl flex items-center justify-center font-black text-lg" style={{ backgroundColor: `${COLORS[r.status]}15`, color: COLORS[r.status] }}>
                      {r.value.toFixed(1)}
                    </div>
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-800 text-sm">Leitura de pH</span>
                      <span className="text-[10px] text-slate-400 flex items-center gap-1 uppercase tracking-tighter font-black">
                        <Clock size={10} /> {new Date(r.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </span>
                    </div>
                  </div>
                  <span className="px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest" style={{ backgroundColor: `${COLORS[r.status]}15`, color: COLORS[r.status] }}>
                    {r.status}
                  </span>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {activeTab === 'inventory' && (
        <div className="space-y-6">
          <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2"><Package size={14} /> Consumo de Materiais</h3>
            <div className="space-y-6">
              {state.inventory.map(item => {
                const totalOut = state.inventoryMovements.filter(m => m.itemId === item.id).reduce((sum, m) => sum + m.quantity, 0);
                const percent = Math.min(100, (totalOut / (totalOut + item.quantity || 1)) * 100);
                return (
                  <div key={item.id} className="flex flex-col gap-2">
                    <div className="flex justify-between items-end">
                      <div className="flex flex-col">
                        <span className="font-black text-slate-700 text-sm">{item.name}</span>
                        <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">Disponível: {item.quantity} {item.unit}</span>
                      </div>
                      <span className="font-black text-blue-600 text-xs">{totalOut} {item.unit} consumidos</span>
                    </div>
                    <div className="w-full bg-slate-100 h-2.5 rounded-full overflow-hidden">
                      <div className={`h-full rounded-full transition-all duration-1000 ${item.quantity <= item.minThreshold ? 'bg-red-500' : 'bg-blue-500'}`} style={{ width: `${percent}%` }}></div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      )}

      {activeTab === 'ai' && <AIAdvisor state={state} />}
    </div>
  );
};

