};

const CustomPHTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    const data = payload[0].payload;
    const statusColor = COLORS[data.status as keyof typeof COLORS];
    return (
      <div className="bg-white p-4 rounded-2xl shadow-2xl border border-slate-50 flex flex-col gap-2 min-w-[120px] animate-scaleIn">
        <div className="flex items-center justify-between border-b border-slate-50 pb-2 mb-1">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{label}</span>
          <Clock size={10} className="text-slate-300" />
        </div>
        <div className="flex items-center justify-between gap-4">
          <div className="flex flex-col">
            <span className="text-2xl font-black text-slate-800 leading-none">{data.value.toFixed(1)}</span>
            <span className="text-[8px] text-slate-400 font-black uppercase tracking-widest">pH Atual</span>
          </div>
          <div 
            className="px-2 py-1 rounded-lg text-[9px] font-black uppercase tracking-tighter"
            style={{ backgroundColor: `${statusColor}15`, color: statusColor }}
          >
            {data.status}
          </div>
        </div>
      </div>
    );
  }
  return null;
};

const ReportsView: React.FC<ReportsViewProps> = ({ state, onAddPH }) => {
  const [activeTab, setActiveTab] = useState<ReportTab>('transactions');
