interface InventoryViewProps {
  inventory: InventoryItem[];
  movements: InventoryMovement[];
  onUpdate: (id: string, delta: number) => void;
  onAddItem: (item: Omit<InventoryItem, 'id'>) => void;
}

const InventoryView: React.FC<InventoryViewProps> = ({ inventory, movements, onUpdate, onAddItem }) => {
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
  const [outflowModal, setOutflowModal] = useState<{ isOpen: boolean; itemId: string; itemName: string } | null>(null);
  const [newItemModal, setNewItemModal] = useState(false);
  const [outflowAmount, setOutflowAmount] = useState('');

  // Estados para novo item
  const [newName, setNewName] = useState('');
  const [newUnit, setNewUnit] = useState('un');
  const [newMin, setNewMin] = useState('10');
  const [newInitial, setNewInitial] = useState('0');
  const [newPrice, setNewPrice] = useState('0');

  const inventoryValue = useMemo(() => {
    return inventory.reduce((sum, item) => sum + (item.quantity * item.price), 0);
  }, [inventory]);

  const changeDate = (days: number) => {
    const current = new Date(selectedDate + 'T12:00:00'); 
    current.setDate(current.getDate() + days);
    setSelectedDate(current.toISOString().split('T')[0]);
  };

  const filteredOutputs = useMemo(() => {
    const map: Record<string, number> = {};
    movements.forEach(m => {
      const movementDate = new Date(m.date).toISOString().split('T')[0];
      if (movementDate === selectedDate) {
        map[m.itemId] = (map[m.itemId] || 0) + m.quantity;
      }
    });
    return map;
  }, [movements, selectedDate]);

  const handleManualOutflow = (e: React.FormEvent) => {
    e.preventDefault();
    const amount = parseInt(outflowAmount);
    if (outflowModal && !isNaN(amount) && amount > 0) {
      onUpdate(outflowModal.itemId, -amount);
      setOutflowModal(null);
      setOutflowAmount('');
    }
  };

  const handleCreateItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName) return;
    onAddItem({
      name: newName,
      unit: newUnit,
      minThreshold: parseInt(newMin) || 0,
      quantity: parseInt(newInitial) || 0,
      price: parseFloat(newPrice) || 0
    });
    setNewItemModal(false);
    setNewName('');
    setNewInitial('0');
    setNewPrice('0');
  };

  const isToday = selectedDate === new Date().toISOString().split('T')[0];

  return (
    <div className="space-y-6 animate-fadeIn pb-10">
      <div className="flex items-center justify-between">
        <div className="flex flex-col gap-1">
