          </div>

          <div className="pb-2">
            <h4 className="text-3xl font-black">{inventoryValue.toLocaleString()} Kz</h4>
          </div>

          <div className="pt-2 border-t border-white/10 flex justify-between items-center">
            <div className="flex items-center gap-2">
               <History size={14} className="opacity-60" />
               <span className="text-[10px] font-black uppercase tracking-tight opacity-70">Resumo de Saídas</span>
            </div>
            <div className="flex items-center bg-white/10 rounded-full px-2 py-0.5 backdrop-blur-md border border-white/20">
              <button onClick={() => changeDate(-1)} className="p-1 hover:bg-white/20 rounded-full transition-colors">
                <ChevronLeft size={14} />
              </button>
              <span className="text-[9px] font-black uppercase tracking-tighter px-2">
                {isToday ? 'Hoje' : new Date(selectedDate + 'T12:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: 'short' })}
              </span>
              <button 
                onClick={() => changeDate(1)} 
                disabled={isToday}
                className={`p-1 rounded-full transition-colors ${isToday ? 'opacity-30' : 'hover:bg-white/20'}`}
              >
                <ChevronRight size={14} />
              </button>
            </div>
          </div>
        </div>
        <CircleDollarSign size={160} className="absolute -right-12 -bottom-12 text-white opacity-5" />
      </div>

      <div className="space-y-4">
        <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Itens no Catálogo</h3>
        {inventory.map(item => {
          const isLow = item.quantity <= item.minThreshold;
          return (
            <div key={item.id} className={`p-5 rounded-3xl bg-white border shadow-sm flex flex-col gap-4 transition-all ${isLow ? 'border-red-200 ring-1 ring-red-50' : 'border-slate-100'}`}>
              <div className="flex justify-between items-start">
                <div className="flex flex-col">
                  <span className="font-black text-slate-800 text-base tracking-tight leading-tight mb-1">{item.name}</span>
                  <div className="flex items-center gap-2">
                    <span className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">Mín: {item.minThreshold} {item.unit}</span>
                    <span className="w-1 h-1 rounded-full bg-slate-200"></span>
                    <span className="text-[10px] text-blue-600 font-black uppercase tracking-wider">{item.price.toLocaleString()} Kz/{item.unit}</span>
                  </div>
                </div>
                <div className="flex flex-col items-end">
                  <span className={`px-4 py-1.5 rounded-2xl text-[11px] font-black shadow-sm ${isLow ? 'bg-red-500 text-white shadow-red-100' : 'bg-blue-50 text-blue-700'}`}>
                    {item.quantity} {item.unit}
                  </span>
                  <span className="text-[8px] text-slate-400 font-black uppercase mt-1 tracking-widest">Total: {(item.quantity * item.price).toLocaleString()} Kz</span>
                </div>
