              <div className="flex gap-2">
                <button 
                  onClick={() => setOutflowModal({ isOpen: true, itemId: item.id, itemName: item.name })}
                  className="flex-[2] bg-red-50 text-red-600 py-3.5 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-red-100 active:scale-95 transition-all flex items-center justify-center gap-2 border border-red-100"
                >
                  <ArrowDownRight size={16} /> Registrar Saída
                </button>
                <button 
                  onClick={() => onUpdate(item.id, 1)}
                  className="flex-1 bg-slate-50 py-3.5 rounded-2xl text-slate-600 hover:bg-slate-100 active:scale-95 transition-all flex justify-center border border-slate-100"
                >
                  <Plus size={18} />
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {/* Modal Novo Item */}
      {newItemModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-black/40 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-[32px] p-8 shadow-2xl animate-scaleIn">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-black text-slate-800 tracking-tight">Novo Produto</h3>
              <button onClick={() => setNewItemModal(false)} className="text-slate-300 hover:text-slate-500"><X size={28} /></button>
            </div>
            <form onSubmit={handleCreateItem} className="space-y-4">
              <div>
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block mb-1">Nome do Item</label>
                <input value={newName} onChange={e => setNewName(e.target.value)} placeholder="Ex: Galões 5L" className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 text-sm font-bold" required />
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block mb-1">Unidade</label>
                  <input value={newUnit} onChange={e => setNewUnit(e.target.value)} placeholder="un, kg, L" className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 text-sm font-bold" required />
                </div>
                <div>
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block mb-1">Estoque Mín.</label>
                  <input type="number" value={newMin} onChange={e => setNewMin(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 text-sm font-bold" required />
