                  <input type="number" value={newInitial} onChange={e => setNewInitial(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 text-sm font-bold" />
                </div>
                <div>
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block mb-1">Preço Unit. (Kz)</label>
                  <input type="number" step="0.01" value={newPrice} onChange={e => setNewPrice(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 text-sm font-bold" required />
