              <button type="submit" className="w-full bg-blue-600 text-white font-black py-4 rounded-2xl shadow-lg shadow-blue-50 active:scale-95 transition-all mt-4">CRIAR ITEM</button>
            </form>
          </div>
        </div>
      )}

      {/* Modal Saída */}
      {outflowModal?.isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-black/40 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-[32px] p-8 shadow-2xl animate-scaleIn">
            <div className="flex justify-between items-center mb-6 text-center w-full">
              <div className="w-full">
                <h3 className="text-xl font-black text-slate-800">Registrar Saída</h3>
