                const percent = Math.min(100, (totalOut / (totalOut + item.quantity || 1)) * 100);
                return (
                  <div key={item.id} className="flex flex-col gap-2">
                    <div className="flex justify-between items-end">
                      <div className="flex flex-col">
                        <span className="font-black text-slate-700 text-sm">{item.name}</span>
                        <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">Disponível: {item.quantity} {item.unit}</span>
                      </div>
                      <span className="font-black text-blue-600 text-xs">{totalOut} {item.unit} consumidos</span>
                    </div>
                    <div className="w-full bg-slate-100 h-2.5 rounded-full overflow-hidden">
                      <div className={`h-full rounded-full transition-all duration-1000 ${item.quantity <= item.minThreshold ? 'bg-red-500' : 'bg-blue-500'}`} style={{ width: `${percent}%` }}></div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      )}

      {activeTab === 'ai' && <AIAdvisor state={state} />}
    </div>
  );
};

export default ReportsView;

import React, { useState, useMemo } from 'react';
import { Transaction, TransactionType } from '../types';
import { Plus, X, Calendar, TrendingDown, Landmark, Info, ChevronLeft, ChevronRight, Edit3, List } from 'lucide-react';
import { SALE_CATEGORIES, EXPENSE_CATEGORIES, INVESTMENT_CATEGORIES } from '../constants';

interface TransactionFormProps {
  type: TransactionType;
  onAdd: (transaction: Omit<Transaction, 'id'>) => void;
  transactions: Transaction[];
}

const TransactionForm: React.FC<TransactionFormProps> = ({ type, onAdd, transactions }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [amount, setAmount] = useState('');
  const [subType, setSubType] = useState<'expense' | 'investment'>(type === 'sale' ? 'expense' : type as any);
  const [category, setCategory] = useState(type === 'sale' ? 'Total Diário' : '');
  const [customCategory, setCustomCategory] = useState('');
  const [isCustomCategory, setIsCustomCategory] = useState(false);
  const [description, setDescription] = useState('');
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);

  const activeType = type === 'sale' ? 'sale' : subType;
  const categories = activeType === 'sale' ? ['Total Diário', ...SALE_CATEGORIES] : 
                    activeType === 'expense' ? EXPENSE_CATEGORIES : 
                    INVESTMENT_CATEGORIES;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalCategory = isCustomCategory ? customCategory : category;

    if (!amount || !finalCategory) return;

    onAdd({
      date: new Date().toISOString(),
      type: activeType as TransactionType,
      category: finalCategory,
      amount: parseFloat(amount),
      description: activeType === 'sale' ? (description || 'Venda consolidada do dia') : description,
      quantity: 1
    });

    setAmount('');
    setCategory(activeType === 'sale' ? 'Total Diário' : '');
    setCustomCategory('');
    setIsCustomCategory(false);
    setDescription('');
    setIsOpen(false);
  };

  const totalInvested = useMemo(() => transactions.filter(t => t.type === 'investment').reduce((sum, t) => sum + t.amount, 0), [transactions]);
  const totalExpenses = useMemo(() => transactions.filter(t => t.type === 'expense').reduce((sum, t) => sum + t.amount, 0), [transactions]);

  const changeDate = (days: number) => {
    const current = new Date(selectedDate + 'T12:00:00');
    current.setDate(current.getDate() + days);
    setSelectedDate(current.toISOString().split('T')[0]);
  };

  const isToday = selectedDate === new Date().toISOString().split('T')[0];

  const groupedSales = useMemo(() => {
    if (type !== 'sale') return null;
    const groups: Record<string, { total: number, count: number, date: string }> = {};

    transactions
      .filter(t => t.type === 'sale')
      .filter(t => new Date(t.date).toISOString().split('T')[0] === selectedDate)
      .forEach(t => {
        const dateStr = new Date(t.date).toLocaleDateString('pt-BR');
        if (!groups[dateStr]) groups[dateStr] = { total: 0, count: 0, date: t.date };
        groups[dateStr].total += t.amount;
        groups[dateStr].count += 1;
      });
    return Object.entries(groups).sort((a, b) => new Date(b[1].date).getTime() - new Date(a[1].date).getTime());
  }, [transactions, type, selectedDate]);

  const filteredTransactions = transactions.filter(t => t.type === activeType).reverse();

  const toggleCategoryMode = () => {
    setIsCustomCategory(!isCustomCategory);
    setCategory('');
    setCustomCategory('');
  };

  return (
    <div className="space-y-4 animate-fadeIn">
      <div className="flex flex-col gap-4">
        <div className="flex items-center justify-between">
          <h2 className="text-xl font-black text-slate-800 tracking-tight">
            {type === 'sale' ? 'Vendas Diárias' : 'Gestão Financeira'}
          </h2>
          <button 
            onClick={() => setIsOpen(true)} 
            className="bg-blue-600 text-white p-3 rounded-full shadow-lg shadow-blue-200 active:scale-95 transition-all"
          >
            <Plus size={24} />
          </button>
        </div>

        {type === 'sale' && (
          <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center justify-between">
            <button 
              onClick={() => changeDate(-1)} 
              className="p-2 text-slate-400 hover:text-blue-600 transition-colors"
            >
              <ChevronLeft size={20} />
            </button>
            <div className="flex flex-col items-center">
              <div className="relative">
                <input 
                  type="date" 
                  value={selectedDate} 
                  onChange={(e) => setSelectedDate(e.target.value)}
                  className="text-sm font-bold text-slate-800 focus:outline-none bg-transparent cursor-pointer text-center"
                />
              </div>
              <span className="text-[10px] text-blue-600 font-black uppercase tracking-widest mt-0.5">
                {isToday ? 'HOJE' : new Date(selectedDate + 'T12:00:00').toLocaleDateString('pt-BR', { weekday: 'long' })}
              </span>
            </div>
            <button 
              onClick={() => changeDate(1)} 
              disabled={isToday}
              className={`p-2 transition-colors ${isToday ? 'text-slate-100' : 'text-slate-400 hover:text-blue-600'}`}
            >
              <ChevronRight size={20} />
            </button>
          </div>
        )}

        {type !== 'sale' && (
          <div className="flex bg-slate-200/50 p-1 rounded-2xl">
            <button onClick={() => setSubType('expense')} className={`flex-1 py-3 px-4 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${subType === 'expense' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><TrendingDown size={14} /> Saídas</button>
            <button onClick={() => setSubType('investment')} className={`flex-1 py-3 px-4 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${subType === 'investment' ? 'bg-white text-amber-600 shadow-sm' : 'text-slate-500'}`}><Landmark size={14} /> Investimentos</button>
          </div>
        )}
      </div>

      {type !== 'sale' && (
        <div className={`p-5 rounded-3xl border flex flex-col gap-1 shadow-sm transition-all ${subType === 'investment' ? 'bg-amber-50 border-amber-100' : 'bg-red-50 border-red-100'}`}>
          <div className="flex items-center gap-2 text-slate-500 text-[10px] font-black uppercase tracking-widest opacity-70"><Info size={12} /> {subType === 'investment' ? 'Investimento Total' : 'Total de Saídas'}</div>
          <div className={`text-2xl font-black ${subType === 'investment' ? 'text-amber-700' : 'text-red-700'}`}>{(subType === 'investment' ? totalInvested : totalExpenses).toLocaleString()} Kz</div>
        </div>
      )}

      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-[32px] p-8 shadow-2xl animate-scaleIn">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-black text-slate-800 tracking-tight">{activeType === 'sale' ? 'Lançar Venda' : activeType === 'expense' ? 'Nova Saída' : 'Novo Investimento'}</h3>
              <button onClick={() => setIsOpen(false)} className="text-slate-300 hover:text-slate-500"><X size={28} /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-5">
              <div>
                <div className="flex items-center justify-between mb-1.5">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Categoria</label>
                  {activeType === 'investment' && (
                    <button 
                      type="button" 
                      onClick={toggleCategoryMode}
                      className="text-[9px] font-black text-blue-600 bg-blue-50 px-2 py-1 rounded-lg flex items-center gap-1 hover:bg-blue-100 transition-colors"
                    >
                      {isCustomCategory ? <><List size={10}/> Ver Lista</> : <><Edit3 size={10}/> Personalizar</>}
                    </button>
                  )}
                </div>

                {isCustomCategory ? (
                  <input 
                    autoFocus
                    type="text" 
                    value={customCategory} 
                    onChange={e => setCustomCategory(e.target.value)} 
                    placeholder="Nome da categoria..." 
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-4 text-slate-800 font-semibold focus:ring-2 focus:ring-blue-100 focus:outline-none" 
                    required 
                  />
                ) : (
                  <select 
                    value={category} 
                    onChange={e => setCategory(e.target.value)} 
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-4 text-slate-700 font-semibold focus:ring-2 focus:ring-blue-100 focus:outline-none appearance-none" 
                    required
                  >
                    <option value="">Selecione...</option>
                    {categories.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                )}
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-400 mb-1.5 uppercase tracking-widest">Valor (Kz)</label>
                <input type="number" step="0.01" value={amount} onChange={e => setAmount(e.target.value)} placeholder="0,00" className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-4 text-slate-800 text-2xl font-black focus:ring-2 focus:ring-blue-100 focus:outline-none" required />
              </div>
              <button type="submit" className={`w-full text-white font-black py-5 rounded-2xl shadow-xl transition-all active:scale-95 ${activeType === 'investment' ? 'bg-amber-600 shadow-amber-100' : 'bg-blue-600 shadow-blue-100'}`}>SALVAR REGISTRO</button>
            </form>
          </div>
        </div>
      )}

      <div className="space-y-3">
        {activeType === 'sale' ? (
          groupedSales && groupedSales.length > 0 ? (
            groupedSales.map(([dateStr, data]) => (
              <div key={dateStr} className="bg-white p-5 rounded-3xl shadow-sm border border-slate-100 flex items-center justify-between transition-all hover:border-blue-100">
                <div className="flex items-center gap-4">
                  <div className="bg-blue-50 p-3 rounded-2xl text-blue-600 shadow-sm shadow-blue-50">
                    <Calendar size={22} />
                  </div>
                  <div className="flex flex-col">
                    <span className="font-black text-slate-800 text-base tracking-tight">{dateStr}</span>
                    <span className="text-[10px] text-slate-400 uppercase font-black tracking-widest">{data.count} LANÇAMENTOS</span>
                  </div>
                </div>
                <div className="flex flex-col items-end">
                  <span className="font-black text-blue-600 text-lg">+ {data.total.toLocaleString()} Kz</span>
                </div>
              </div>
            ))
          ) : (
            <div className="bg-slate-50/50 p-12 rounded-[32px] border-2 border-dashed border-slate-200 text-center flex flex-col items-center gap-3">
              <Calendar size={40} className="text-slate-200" />
              <p className="text-slate-400 text-xs font-bold uppercase tracking-widest italic leading-relaxed">
                Nenhuma venda registrada<br/>para esta data.
              </p>
            </div>
          )
        ) : (
          filteredTransactions.map(t => (
            <div key={t.id} className="bg-white p-5 rounded-3xl shadow-sm border border-slate-100 flex items-center justify-between transition-all hover:border-red-50">
              <div className="flex items-center gap-4">
                <div className={`p-3 rounded-2xl ${activeType === 'investment' ? 'bg-amber-50 text-amber-600 shadow-amber-50' : 'bg-red-50 text-red-600 shadow-red-50'}`}>
                  {activeType === 'investment' ? <Landmark size={22} /> : <TrendingDown size={22} />}
                </div>
                <div className="flex flex-col">
                  <span className="font-black text-slate-800 text-base tracking-tight">{t.category}</span>
                  <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{new Date(t.date).toLocaleDateString('pt-BR')}</span>
                </div>
              </div>
              <div className="flex flex-col items-end">
                <span className={`font-black text-lg ${activeType === 'investment' ? 'text-amber-600' : 'text-red-500'}`}>
                  - {t.amount.toLocaleString()} Kz
                </span>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default TransactionForm;

import React, { useState, useMemo } from 'react';
import { BusinessState, Transaction, PHRecord } from '../types';
import AIAdvisor from './AIAdvisor';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  AreaChart, Area, ReferenceLine, ReferenceArea, Label
} from 'recharts';
import { 
  History, 
  Package, 
  Sparkles, 
  ArrowUpRight, 
  ArrowDownLeft, 
  Landmark,
  Calendar,
  Droplet,
  Plus,
  ChevronDown,
  ChevronLeft,
  ChevronRight,
  Clock,
  TrendingUp,
  BarChart3,
  CircleDollarSign,
  AlertCircle,
  FastForward,
  ShieldCheck
} from 'lucide-react';

interface ReportsViewProps {
  state: BusinessState;
  onAddPH: (value: number) => void;
}

type ReportTab = 'transactions' | 'inventory' | 'quality' | 'ai';

const COLORS = {
  Ideal: '#22c55e',   // green-500
  Alerta: '#f59e0b',  // amber-500
  Crítico: '#ef4444', // red-500
};

// Tooltip customizado com UX aprimorada
const CustomPHTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    const data = payload[0].payload;
    const statusColor = COLORS[data.status as keyof typeof COLORS];

    return (
      <div className="bg-white p-4 rounded-3xl shadow-2xl border border-slate-100 flex flex-col gap-3 min-w-[140px] animate-scaleIn ring-4 ring-black/5">
        <div className="flex items-center justify-between border-b border-slate-50 pb-2">
          <div className="flex items-center gap-1.5 text-slate-400">
            <Clock size={12} />
            <span className="text-[10px] font-black uppercase tracking-widest">{label}</span>
          </div>
        </div>

        <div className="flex flex-col gap-1">
          <div className="flex items-baseline gap-1">
            <span className="text-3xl font-black text-slate-800 leading-none">{data.value.toFixed(1)}</span>
            <span className="text-[10px] text-slate-400 font-bold">pH</span>
          </div>
          <div 
            className="inline-flex items-center gap-1 px-2 py-0.5 rounded-lg text-[9px] font-black uppercase tracking-tighter w-fit"
            style={{ backgroundColor: `${statusColor}15`, color: statusColor }}
          >
            <div className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: statusColor }}></div>
            {data.status}
          </div>
        </div>
      </div>
    );
  }
  return null;
};

const ReportsView: React.FC<ReportsViewProps> = ({ state, onAddPH }) => {
  const [activeTab, setActiveTab] = useState<ReportTab>('transactions');
  const [filterType, setFilterType] = useState<'all' | 'sale' | 'expense' | 'investment'>('all');
  const [phValue, setPhValue] = useState('');
  const [showPHForm, setShowPHForm] = useState(false);
  const [qualityDate, setQualityDate] = useState(new Date().toISOString().split('T')[0]);
  const [showFlashSummary, setShowFlashSummary] = useState(false);
  const [flashOffset, setFlashOffset] = useState(1); // 1 = ontem, 2 = 2 dias atrás, etc.

  const changeQualityDate = (days: number) => {
    const current = new Date(qualityDate + 'T12:00:00');
    current.setDate(current.getDate() + days);
    setQualityDate(current.toISOString().split('T')[0]);
  };

  const isToday = qualityDate === new Date().toISOString().split('T')[0];

  const monthlyStats = useMemo(() => {
    const now = new Date();
    const currentMonth = now.getMonth();
    const currentYear = now.getFullYear();
    const daysInMonth = now.getDate();

    const monthlySales = state.transactions.filter(t => {
      const d = new Date(t.date);
      return t.type === 'sale' && d.getMonth() === currentMonth && d.getFullYear() === currentYear;
    });

    const totalSales = monthlySales.reduce((sum, t) => sum + t.amount, 0);
    const avgDaily = daysInMonth > 0 ? totalSales / daysInMonth : 0;

    const categories: Record<string, number> = {};
    monthlySales.forEach(t => {
      categories[t.category] = (categories[t.category] || 0) + t.amount;
    });

    const bestCategory = Object.entries(categories).sort((a, b) => b[1] - a[1])[0]?.[0] || 'N/A';

    return {
      totalSales,
      avgDaily,
      bestCategory,
      monthName: new Intl.DateTimeFormat('pt-BR', { month: 'long' }).format(now)
    };
  }, [state.transactions]);

  const flashStats = useMemo(() => {
    const targetDate = new Date();
    targetDate.setDate(targetDate.getDate() - flashOffset);
    const dateKey = targetDate.toISOString().split('T')[0];

    const dayTransactions = state.transactions.filter(t => 
      new Date(t.date).toISOString().split('T')[0] === dateKey
    );

    let label = '';
    if (flashOffset === 1) label = 'Ontem';
    else label = `${flashOffset} dias atrás`;

    return {
      sales: dayTransactions.filter(t => t.type === 'sale').reduce((sum, t) => sum + t.amount, 0),
      expenses: dayTransactions.filter(t => t.type === 'expense').reduce((sum, t) => sum + t.amount, 0),
      investments: dayTransactions.filter(t => t.type === 'investment').reduce((sum, t) => sum + t.amount, 0),
      dateStr: targetDate.toLocaleDateString('pt-BR', { day: '2-digit', month: 'short' }),
      relativeLabel: label
    };
  }, [state.transactions, flashOffset]);

  const groupedTransactions = useMemo(() => {
    const groups: Record<string, { 
      date: string, 
      sales: number, 
      expenses: number, 
      investments: number,
      items: Transaction[] 
    }> = {};

    state.transactions
      .filter(t => filterType === 'all' || t.type === filterType)
      .forEach(t => {
        const dateKey = new Date(t.date).toISOString().split('T')[0];
        if (!groups[dateKey]) {
          groups[dateKey] = { 
            date: dateKey, 
            sales: 0, 
            expenses: 0, 
            investments: 0, 
            items: [] 
          };
        }
        if (t.type === 'sale') groups[dateKey].sales += t.amount;
        else if (t.type === 'expense') groups[dateKey].expenses += t.amount;
        else if (t.type === 'investment') groups[dateKey].investments += t.amount;
        groups[dateKey].items.push(t);
      });

    return Object.values(groups).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [state.transactions, filterType]);

  const filteredPhRecords = useMemo(() => {
    return state.phRecords
      .filter(r => new Date(r.date).toISOString().split('T')[0] === qualityDate)
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [state.phRecords, qualityDate]);

  const hourlyPhData = useMemo(() => {
    return filteredPhRecords.map(r => ({
      time: new Date(r.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      value: r.value,
      status: r.status
    }));
  }, [filteredPhRecords]);

  const handlePHSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const val = parseFloat(phValue);
    if (!isNaN(val)) {
      onAddPH(val);
      setPhValue('');
      setShowPHForm(false);
      setQualityDate(new Date().toISOString().split('T')[0]);
    }
  };

  const adjustFlashOffset = (e: React.MouseEvent, delta: number) => {
    e.stopPropagation();
    const newVal = flashOffset + delta;
    if (newVal >= 1 && newVal <= 7) {
      setFlashOffset(newVal);
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn pb-12">
      <div className="flex flex-col gap-1">
        <h2 className="text-2xl font-black text-slate-800 tracking-tight">Relatórios</h2>
        <p className="text-slate-500 text-sm">Análise estratégica e controle de pureza.</p>
      </div>

      <div className="flex bg-slate-200/50 p-1 rounded-2xl overflow-x-auto no-scrollbar">
        <button onClick={() => setActiveTab('transactions')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'transactions' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><History size={14} /> Histórico</button>
        <button onClick={() => setActiveTab('inventory')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'inventory' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><Package size={14} /> Estoque</button>
        <button onClick={() => setActiveTab('quality')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'quality' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><Droplet size={14} /> Qualidade</button>
        <button onClick={() => setActiveTab('ai')} className={`flex-none px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'ai' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><Sparkles size={14} /> IA</button>
      </div>

      {activeTab === 'transactions' && (
        <div className="space-y-6">
          <div className="bg-gradient-to-br from-blue-600 to-indigo-700 p-6 rounded-[32px] text-white shadow-xl shadow-blue-100 relative overflow-hidden">
            <div className="relative z-10 space-y-4">
              <div className="flex items-center justify-between">
                <span className="text-[10px] font-black uppercase tracking-widest opacity-80">Resumo de {monthlyStats.monthName}</span>
                <div className="bg-white/20 p-2 rounded-xl">
                  <TrendingUp size={16} />
                </div>
              </div>

              <div className="space-y-1">
                <span className="text-[10px] font-black opacity-70 uppercase tracking-widest">Faturamento Total</span>
                <h3 className="text-3xl font-black">{monthlyStats.totalSales.toLocaleString()} Kz</h3>
              </div>

              <div className="grid grid-cols-2 gap-4 pt-2">
                <div className="bg-white/10 p-3 rounded-2xl backdrop-blur-sm border border-white/10">
                  <div className="flex items-center gap-2 mb-1">
                    <BarChart3 size={12} className="opacity-70" />
                    <span className="text-[8px] font-black uppercase tracking-widest opacity-70">Top Categoria</span>
                  </div>
                  <span className="text-[11px] font-black truncate block">{monthlyStats.bestCategory}</span>
                </div>
                <div className="bg-white/10 p-3 rounded-2xl backdrop-blur-sm border border-white/10">
                  <div className="flex items-center gap-2 mb-1">
                    <CircleDollarSign size={12} className="opacity-70" />
                    <span className="text-[8px] font-black uppercase tracking-widest opacity-70">Média Diária</span>
                  </div>
                  <span className="text-[11px] font-black">{Math.round(monthlyStats.avgDaily).toLocaleString()} Kz</span>
                </div>
              </div>
            </div>
            <Sparkles size={140} className="absolute -right-12 -bottom-12 text-white opacity-5" />
          </div>

          <div className="px-1">
            <button 
              onClick={() => setShowFlashSummary(!showFlashSummary)}
              className="w-full flex items-center justify-between bg-white p-4 rounded-2xl border border-slate-100 shadow-sm active:scale-[0.98] transition-all"
            >
              <div className="flex items-center gap-3">
                <div className="bg-amber-50 p-2 rounded-xl text-amber-600">
                  <FastForward size={18} />
                </div>
                <div className="flex flex-col items-start text-left">
                  <span className="text-xs font-black text-slate-800 tracking-tight">
                    Flash de {flashStats.relativeLabel} ({flashStats.dateStr})
                  </span>
                  <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">Histórico de até 7 dias</span>
                </div>
              </div>

              <div className="flex items-center gap-4">
                {showFlashSummary && (
                  <div className="flex items-center bg-slate-100 rounded-lg p-0.5 border border-slate-200">
                    <button 
                      onClick={(e) => adjustFlashOffset(e, 1)} 
                      disabled={flashOffset === 7}
                      className={`p-1 rounded-md transition-all ${flashOffset === 7 ? 'text-slate-300' : 'text-slate-600 hover:bg-white'}`}
                    >
                      <ChevronLeft size={16} />
                    </button>
                    <button 
                      onClick={(e) => adjustFlashOffset(e, -1)} 
                      disabled={flashOffset === 1}
                      className={`p-1 rounded-md transition-all ${flashOffset === 1 ? 'text-slate-300' : 'text-slate-600 hover:bg-white'}`}
                    >
                      <ChevronRight size={16} />
                    </button>
                  </div>
                )}
                <ChevronDown size={18} className={`text-slate-300 transition-transform duration-300 ${showFlashSummary ? 'rotate-180' : ''}`} />
              </div>
            </button>

            {showFlashSummary && (
              <div className="grid grid-cols-3 gap-2 mt-2 animate-slideInDown">
                <div className="bg-green-50/50 p-3 rounded-2xl border border-green-100 flex flex-col items-center">
                  <span className="text-[8px] font-black text-green-700 uppercase mb-1">Vendas</span>
                  <span className="text-xs font-black text-green-700">+{flashStats.sales.toLocaleString()}</span>
                </div>
                <div className="bg-red-50/50 p-3 rounded-2xl border border-red-100 flex flex-col items-center">
                  <span className="text-[8px] font-black text-red-700 uppercase mb-1">Saídas</span>
                  <span className="text-xs font-black text-red-700">-{flashStats.expenses.toLocaleString()}</span>
                </div>
                <div className="bg-amber-50/50 p-3 rounded-2xl border border-amber-100 flex flex-col items-center">
                  <span className="text-[8px] font-black text-amber-700 uppercase mb-1">Invest.</span>
                  <span className="text-xs font-black text-amber-700">-{flashStats.investments.toLocaleString()}</span>
                </div>
              </div>
            )}
          </div>

          <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1">
            {(['all', 'sale', 'expense', 'investment'] as const).map(type => (
              <button key={type} onClick={() => setFilterType(type)} className={`px-4 py-2 rounded-full text-[10px] font-bold whitespace-nowrap transition-all border ${filterType === type ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-slate-500 border-slate-200'}`}>{type === 'all' ? 'TUDO' : type === 'sale' ? 'VENDAS' : type === 'expense' ? 'SAÍDAS' : 'INVESTIMENTOS'}</button>
            ))}
          </div>

          <div className="space-y-8">
            {groupedTransactions.map(group => (
              <div key={group.date} className="space-y-3">
                <div className="sticky top-0 bg-slate-50/90 backdrop-blur-md py-2 z-10 flex flex-col gap-2">
                  <span className="text-xs font-black text-slate-400 uppercase tracking-widest px-1">
                    {new Date(group.date + 'T12:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: 'long', weekday: 'short' })}
                  </span>
                  <div className="grid grid-cols-3 gap-2">
                    <div className="bg-white p-2 rounded-xl border border-slate-100 flex flex-col items-center">
                      <span className="text-[8px] font-black text-slate-400 uppercase">Vendas</span>
                      <span className="text-[10px] font-black text-green-600">+{group.sales.toLocaleString()}</span>
                    </div>
                    <div className="bg-white p-2 rounded-xl border border-slate-100 flex flex-col items-center">
                      <span className="text-[8px] font-black text-slate-400 uppercase">Saídas</span>
                      <span className="text-[10px] font-black text-red-600">-{group.expenses.toLocaleString()}</span>
                    </div>
                    <div className="bg-white p-2 rounded-xl border border-slate-100 flex flex-col items-center">
                      <span className="text-[8px] font-black text-slate-400 uppercase">Invest.</span>
                      <span className="text-[10px] font-black text-amber-600">-{group.investments.toLocaleString()}</span>
                    </div>
                  </div>
                </div>
                <div className="space-y-2">
                  {group.items.reverse().map(t => (
                    <div key={t.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between transition-all active:scale-95">
                      <div className="flex items-center gap-3">
                        <div className={`p-2 rounded-xl ${t.type === 'sale' ? 'bg-green-50 text-green-600' : t.type === 'expense' ? 'bg-red-50 text-red-600' : 'bg-amber-50 text-amber-600'}`}>
                          {t.type === 'sale' ? <ArrowUpRight size={16} /> : t.type === 'expense' ? <ArrowDownLeft size={16} /> : <Landmark size={16} />}
                        </div>
                        <div className="flex flex-col">
                          <span className="font-bold text-slate-800 text-sm mb-0.5 leading-none">{t.category}</span>
                          <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">{new Date(t.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                        </div>
                      </div>
                      <span className={`font-black text-sm ${t.type === 'sale' ? 'text-green-600' : 'text-red-600'}`}>
                        {t.type === 'sale' ? '+' : '-'} {t.amount.toLocaleString()} Kz
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'quality' && (
        <div className="space-y-6 animate-fadeIn">
          {/* Calendário de Navegação */}
          <div className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center justify-between">
            <button onClick={() => changeQualityDate(-1)} className="p-2 text-slate-400 hover:text-blue-600 transition-colors"><ChevronLeft size={20} /></button>
            <div className="flex flex-col items-center">
              <input type="date" value={qualityDate} onChange={(e) => setQualityDate(e.target.value)} className="text-sm font-black text-slate-800 focus:outline-none bg-transparent cursor-pointer text-center" />
              <span className="text-[10px] text-blue-600 font-black uppercase tracking-widest mt-0.5">{isToday ? 'HOJE' : new Date(qualityDate + 'T12:00:00').toLocaleDateString('pt-BR', { weekday: 'short' })}</span>
            </div>
            <button onClick={() => changeQualityDate(1)} disabled={isToday} className={`p-2 transition-colors ${isToday ? 'text-slate-100' : 'text-slate-400 hover:text-blue-600'}`}><ChevronRight size={20} /></button>
          </div>

          {/* Gráfico de Monitoramento de pH */}
          <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm space-y-6">
            <div className="flex items-center justify-between">
              <div className="flex flex-col">
                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><ShieldCheck size={14} className="text-blue-500" /> Índice de Purificação</h3>
                <span className="text-[11px] font-black text-slate-800">Monitoramento Contínuo</span>
              </div>
              <div className="bg-emerald-50 px-3 py-1 rounded-full flex items-center gap-1.5 border border-emerald-100">
                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
                <span className="text-[8px] font-black text-emerald-600 uppercase">Qualidade Ativa</span>
              </div>
            </div>

            <div className="h-72 w-full relative">
              {hourlyPhData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={hourlyPhData} margin={{ top: 20, right: 10, left: -25, bottom: 0 }}>
