          </div>
          <div className="flex flex-col">
            <h1 className="font-extrabold text-xl tracking-tight text-slate-900 leading-none">Agua Cristalina</h1>
            <span className="text-[10px] text-blue-600 font-extrabold uppercase tracking-[0.2em] mt-1 opacity-80">Premium Pure</span>
          </div>
        </div>

        <button 
          onClick={handleOpenNotifications}
          className="relative p-3 rounded-2xl bg-white/80 shadow-sm text-slate-500 hover:text-blue-600 transition-all active:scale-90 border border-white/50"
        >
          <Bell size={22} />
          {unreadCount > 0 && (
            <span className="absolute top-2 right-2 w-5 h-5 bg-red-500 text-white text-[9px] font-black flex items-center justify-center rounded-full border-2 border-white shadow-md">
              {unreadCount}
            </span>
          )}
        </button>
      </header>

      {/* Notifications Drawer */}
      {showNotifications && (
        <div className="fixed inset-0 z-50 flex justify-end">
          <div className="absolute inset-0 bg-slate-900/20 backdrop-blur-md" onClick={() => setShowNotifications(false)} />
          <div className="relative w-4/5 h-full bg-white/90 backdrop-blur-xl shadow-2xl animate-slideInRight flex flex-col border-l border-white/40">
            <div className="p-8 border-b border-slate-100 flex items-center justify-between">
              <h3 className="font-black text-slate-900 text-xl tracking-tight">Alertas</h3>
              <button onClick={() => setShowNotifications(false)} className="text-slate-400 p-1 rounded-full hover:bg-slate-100"><X size={24} /></button>
            </div>
            <div className="flex-1 overflow-y-auto p-6 space-y-4 no-scrollbar">
              {notifications.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-slate-300 space-y-4 italic text-sm">
                  <div className="p-6 bg-slate-50 rounded-full">
                    <Bell size={48} className="opacity-10" />
                  </div>
                  <p>Sem alertas ativos</p>
                </div>
              ) : (
                notifications.map(n => (
                  <div key={n.id} className={`p-5 rounded-3xl border flex gap-4 transition-all shadow-sm ${n.read ? 'bg-white/50 border-slate-100 opacity-60' : 'bg-white border-blue-100 ring-2 ring-blue-500/5'}`}>
                    <div className="mt-1">{getIcon(n.type)}</div>
                    <div className="flex flex-col gap-1.5">
                      <span className="font-extrabold text-slate-900 text-sm leading-tight">{n.title}</span>
                      <p className="text-[11px] text-slate-600 font-medium leading-relaxed">{n.message}</p>
                      <span className="text-[9px] text-slate-400 font-bold uppercase mt-2 flex items-center gap-1.5">
                        <Calendar size={10} /> {new Date(n.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </span>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      )}

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto px-6 pt-2 pb-32 no-scrollbar z-10">
        {children}
      </main>

      {/* Floating Bottom Navigation */}
      <div className="fixed bottom-6 left-0 right-0 max-w-md mx-auto px-6 z-30">
        <nav className="glass-card rounded-[32px] flex justify-around items-center py-4 px-3 shadow-2xl shadow-blue-500/10">
          {NAV_ITEMS.map((item) => {
            const isActive = activeView === item.id;
            return (
              <button
                key={item.id}
                onClick={() => setActiveView(item.id)}
                className={`flex flex-col items-center gap-1.5 transition-all duration-300 ${
                  isActive ? 'text-blue-600 scale-105' : 'text-slate-400 hover:text-slate-600'
                }`}
              >
                <div className={`p-3 rounded-2xl transition-all ${
                  isActive ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/30' : 'bg-transparent'
                }`}>
                  {React.cloneElement(item.icon as React.ReactElement, { size: 22 })}
                </div>
                <span className={`text-[9px] font-extrabold uppercase tracking-widest ${isActive ? 'opacity-100' : 'opacity-0'}`}>
                  {item.label}
                </span>
              </button>
            );
          })}
        </nav>
      </div>
    </div>
  );
};

export default Layout;

import React, { useMemo } from 'react';
import { ResponsiveContainer, XAxis, YAxis, Tooltip, CartesianGrid, AreaChart, Area, BarChart, Bar } from 'recharts';
import { BusinessState } from '../types';
import { TrendingUp, TrendingDown, Wallet, BarChart3, Calendar, Sparkles } from 'lucide-react';

interface DashboardProps {
  state: BusinessState;
}

const Dashboard: React.FC<DashboardProps> = ({ state }) => {
  const sales = state.transactions.filter(t => t.type === 'sale').reduce((sum, t) => sum + t.amount, 0);
  const expenses = state.transactions.filter(t => t.type === 'expense').reduce((sum, t) => sum + t.amount, 0);
  const investments = state.transactions.filter(t => t.type === 'investment').reduce((sum, t) => sum + t.amount, 0);

  const balance = sales - expenses - investments;

  const dailyTrends = useMemo(() => {
    const now = new Date();
    const daysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();
    const data = [];
    const salesMap: Record<number, number> = {};

    state.transactions
      .filter(t => t.type === 'sale')
      .forEach(t => {
        const d = new Date(t.date);
        if (d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear()) {
          const day = d.getDate();
          salesMap[day] = (salesMap[day] || 0) + t.amount;
        }
      });

    for (let i = 1; i <= daysInMonth; i++) {
      data.push({ day: i, total: salesMap[i] || 0 });
    }
    return data;
  }, [state.transactions]);

  const salesByCategory = state.transactions
    .filter(t => t.type === 'sale')
    .reduce((acc, t) => {
      acc[t.category] = (acc[t.category] || 0) + t.amount;
      return acc;
    }, {} as Record<string, number>);

  const topSalesData = Object.entries(salesByCategory)
    .map(([name, value]) => ({ name, value }))
    .sort((a, b) => (Number(b.value) - Number(a.value)))
    .slice(0, 5);

  const currentMonthName = new Intl.DateTimeFormat('pt-BR', { month: 'long' }).format(new Date());

  return (
    <div className="space-y-6 animate-premium pb-10">
      {/* Wallet Summary Card */}
      <div className="glass-card p-6 rounded-[40px] relative overflow-hidden">
        <div className="relative z-10">
          <div className="flex justify-between items-start mb-6">
            <div className="flex flex-col">
              <span className="text-[10px] font-black text-blue-600 uppercase tracking-[0.2em] mb-1">Lucro Líquido Real</span>
              <span className={`text-4xl font-black tracking-tight ${balance >= 0 ? 'text-slate-900' : 'text-red-600'}`}>
                {balance.toLocaleString()} Kz
              </span>
            </div>
            <div className="bg-blue-600 p-4 rounded-3xl text-white shadow-xl shadow-blue-500/40">
              <Wallet size={28} />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="bg-emerald-50/60 p-4 rounded-3xl border border-emerald-100/50">
              <div className="flex items-center gap-2 mb-1.5">
                <TrendingUp size={14} className="text-emerald-600" />
                <span className="text-[9px] font-extrabold text-emerald-600 uppercase tracking-widest">Entradas</span>
              </div>
              <span className="text-lg font-black text-slate-800">{sales.toLocaleString()} Kz</span>
            </div>
            <div className="bg-rose-50/60 p-4 rounded-3xl border border-rose-100/50">
              <div className="flex items-center gap-2 mb-1.5">
                <TrendingDown size={14} className="text-rose-600" />
                <span className="text-[9px] font-extrabold text-rose-600 uppercase tracking-widest">Saídas</span>
              </div>
              <span className="text-lg font-black text-slate-800">{(expenses + investments).toLocaleString()} Kz</span>
            </div>
          </div>
        </div>
        <Sparkles className="absolute -right-6 -bottom-6 w-32 h-32 text-blue-500/10" />
      </div>

      {/* Main Trends Chart */}
      <div className="glass-card p-6 rounded-[40px]">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-slate-900 font-extrabold text-base tracking-tight flex items-center gap-2">
            <Calendar size={20} className="text-blue-500" />
            Vendas Diárias
          </h3>
          <span className="bg-blue-50 text-blue-600 text-[10px] font-black px-3 py-1 rounded-full uppercase">{currentMonthName}</span>
        </div>
        <div className="h-56 w-full">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={dailyTrends}>
              <defs>
                <linearGradient id="colorTotal" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#2563eb" stopOpacity={0.3}/>
                  <stop offset="95%" stopColor="#2563eb" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(0,0,0,0.05)" />
              <XAxis dataKey="day" tick={{fontSize: 10, fontWeight: 700, fill: '#94a3b8'}} axisLine={false} tickLine={false} />
              <YAxis hide />
              <Tooltip 
                contentStyle={{ borderRadius: '24px', border: 'none', boxShadow: '0 20px 40px rgba(0,0,0,0.1)', background: 'rgba(255,255,255,0.9)' }}
                itemStyle={{ color: '#1e293b', fontWeight: 800, fontSize: '12px' }}
                labelStyle={{ color: '#64748b', fontWeight: 600, fontSize: '10px' }}
              />
              <Area type="monotone" dataKey="total" stroke="#2563eb" strokeWidth={4} fillOpacity={1} fill="url(#colorTotal)" animationDuration={2000} />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-6">
        {/* Categories Bar Chart */}
        <div className="glass-card p-6 rounded-[40px]">
          <h3 className="text-slate-900 font-extrabold text-base tracking-tight mb-6 flex items-center gap-2">
            <BarChart3 size={20} className="text-blue-500" />
            Categorias em Alta
          </h3>
          <div className="h-52 w-full">
            {topSalesData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={topSalesData} layout="vertical" margin={{ left: -10, right: 20 }}>
                  <XAxis type="number" hide />
                  <YAxis dataKey="name" type="category" width={100} tick={{ fontSize: 10, fontWeight: 800, fill: '#475569' }} axisLine={false} tickLine={false} />
                  <Tooltip 
                    cursor={{ fill: 'rgba(0,0,0,0.03)' }}
                    contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 10px 20px rgba(0,0,0,0.05)' }}
                  />
                  <Bar dataKey="value" fill="#3b82f6" radius={[0, 10, 10, 0]} barSize={20} animationDuration={1500} />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-slate-300 gap-3">
                <BarChart3 size={32} className="opacity-20" />
                <span className="text-[10px] font-bold uppercase tracking-widest">Sem vendas registradas</span>
              </div>
            )}
          </div>
        </div>

        {/* Low Stock Alerts */}
        <div className="glass-card p-6 rounded-[40px]">
          <h3 className="text-slate-900 font-extrabold text-sm tracking-tight mb-4 uppercase opacity-60">Status de Insumos</h3>
          <div className="space-y-4">
            {state.inventory.filter(i => i.quantity <= i.minThreshold).length === 0 ? (
              <div className="flex items-center gap-3 p-4 bg-emerald-50/50 rounded-3xl border border-emerald-100">
                <div className="w-2 h-2 rounded-full bg-emerald-500"></div>
                <p className="text-emerald-700 text-[10px] font-black uppercase tracking-widest italic">Todo o estoque está conforme.</p>
              </div>
            ) : (
              state.inventory
                .filter(i => i.quantity <= i.minThreshold)
                .map(item => (
                  <div key={item.id} className="flex items-center justify-between p-4 bg-rose-50/50 rounded-3xl border border-rose-100 group">
                    <div className="flex flex-col">
                      <span className="text-slate-900 text-xs font-extrabold">{item.name}</span>
                      <span className="text-[9px] text-rose-600 font-black uppercase mt-0.5 tracking-tighter">Estoque Crítico</span>
                    </div>
                    <span className="bg-rose-500 text-white text-[10px] px-4 py-1.5 rounded-2xl font-black shadow-lg shadow-rose-200">
                      {item.quantity} {item.unit}
                    </span>
                  </div>
                ))
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Transaction, TransactionType } from '../types';
import { Plus, X, Calendar, TrendingDown, Landmark, Info, ChevronLeft, ChevronRight, Edit3, List, ShoppingCart } from 'lucide-react';
import { SALE_CATEGORIES, EXPENSE_CATEGORIES, INVESTMENT_CATEGORIES } from '../constants';

interface TransactionFormProps {
  type: TransactionType;
  onAdd: (transaction: Omit<Transaction, 'id'>) => void;
  transactions: Transaction[];
}

const TransactionForm: React.FC<TransactionFormProps> = ({ type, onAdd, transactions }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [amount, setAmount] = useState('');
  const [subType, setSubType] = useState<'expense' | 'investment'>(type === 'sale' ? 'expense' : type as any);
  const [category, setCategory] = useState(type === 'sale' ? 'Total Diário' : '');
  const [customCategory, setCustomCategory] = useState('');
  const [isCustomCategory, setIsCustomCategory] = useState(false);
  const [description, setDescription] = useState('');
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);

  const activeType = type === 'sale' ? 'sale' : subType;
  const categories = activeType === 'sale' ? ['Total Diário', ...SALE_CATEGORIES] : 
                    activeType === 'expense' ? EXPENSE_CATEGORIES : 
                    INVESTMENT_CATEGORIES;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalCategory = isCustomCategory ? customCategory : category;

    if (!amount || !finalCategory) return;

    onAdd({
      date: new Date().toISOString(),
      type: activeType as TransactionType,
      category: finalCategory,
      amount: parseFloat(amount),
      description: activeType === 'sale' ? (description || 'Venda consolidada do dia') : description,
      quantity: 1
    });

    setAmount('');
    setCategory(activeType === 'sale' ? 'Total Diário' : '');
    setCustomCategory('');
    setIsCustomCategory(false);
    setDescription('');
    setIsOpen(false);
  };

  const totalInvested = useMemo(() => transactions.filter(t => t.type === 'investment').reduce((sum, t) => sum + t.amount, 0), [transactions]);
  const totalExpenses = useMemo(() => transactions.filter(t => t.type === 'expense').reduce((sum, t) => sum + t.amount, 0), [transactions]);

  const changeDate = (days: number) => {
    const current = new Date(selectedDate + 'T12:00:00');
    current.setDate(current.getDate() + days);
    setSelectedDate(current.toISOString().split('T')[0]);
  };

  const isToday = selectedDate === new Date().toISOString().split('T')[0];

  const groupedSales = useMemo(() => {
    if (type !== 'sale') return null;
    const groups: Record<string, { total: number, count: number, date: string }> = {};

    transactions
      .filter(t => t.type === 'sale')
      .filter(t => new Date(t.date).toISOString().split('T')[0] === selectedDate)
      .forEach(t => {
        const dateStr = new Date(t.date).toLocaleDateString('pt-BR');
        if (!groups[dateStr]) groups[dateStr] = { total: 0, count: 0, date: t.date };
        groups[dateStr].total += t.amount;
        groups[dateStr].count += 1;
      });
    return Object.entries(groups).sort((a, b) => new Date(b[1].date).getTime() - new Date(a[1].date).getTime());
  }, [transactions, type, selectedDate]);

  const filteredTransactions = transactions.filter(t => t.type === activeType).reverse();

  const toggleCategoryMode = () => {
    setIsCustomCategory(!isCustomCategory);
    setCategory('');
    setCustomCategory('');
  };

  return (
    <div className="space-y-6 animate-premium">
      {/* Header Section */}
      <div className="flex flex-col gap-6">
        <div className="flex items-center justify-between">
          <div className="flex flex-col">
            <h2 className="text-2xl font-black text-slate-900 tracking-tight">
              {type === 'sale' ? 'Vendas Diárias' : 'Movimentações'}
            </h2>
            <p className="text-[10px] font-bold text-blue-600 uppercase tracking-widest mt-1">Registros de fluxo de caixa</p>
          </div>
          <button 
            onClick={() => setIsOpen(true)} 
            className="bg-blue-600 text-white p-4 rounded-[24px] shadow-xl shadow-blue-600/20 active:scale-90 transition-all border-4 border-blue-50"
          >
            <Plus size={24} strokeWidth={3} />
          </button>
        </div>

        {type === 'sale' && (
          <div className="glass-card p-4 rounded-[32px] flex items-center justify-between shadow-sm">
            <button 
              onClick={() => changeDate(-1)} 
              className="p-3 text-slate-400 hover:text-blue-600 transition-all rounded-2xl hover:bg-white"
            >
              <ChevronLeft size={20} />
            </button>
            <div className="flex flex-col items-center">
              <input 
                type="date" 
                value={selectedDate} 
                onChange={(e) => setSelectedDate(e.target.value)}
                className="text-sm font-black text-slate-900 bg-transparent cursor-pointer text-center focus:outline-none"
              />
              <span className="text-[9px] text-blue-600 font-black uppercase tracking-[0.2em] mt-1">
                {isToday ? 'Hoje' : new Date(selectedDate + 'T12:00:00').toLocaleDateString('pt-BR', { weekday: 'long' })}
              </span>
            </div>
            <button 
              onClick={() => changeDate(1)} 
              disabled={isToday}
              className={`p-3 transition-all rounded-2xl ${isToday ? 'opacity-10 cursor-not-allowed' : 'text-slate-400 hover:text-blue-600 hover:bg-white'}`}
            >
              <ChevronRight size={20} />
            </button>
          </div>
        )}

        {type !== 'sale' && (
          <div className="flex bg-slate-200/40 backdrop-blur-sm p-1.5 rounded-[28px] border border-white/50">
            <button onClick={() => setSubType('expense')} className={`flex-1 py-4 px-4 rounded-[22px] text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${subType === 'expense' ? 'bg-white text-blue-600 shadow-xl' : 'text-slate-500'}`}><TrendingDown size={14} /> Saídas</button>
            <button onClick={() => setSubType('investment')} className={`flex-1 py-4 px-4 rounded-[22px] text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${subType === 'investment' ? 'bg-white text-amber-600 shadow-xl' : 'text-slate-500'}`}><Landmark size={14} /> Investir</button>
          </div>
        )}
      </div>

      {type !== 'sale' && (
        <div className={`p-8 rounded-[40px] flex flex-col gap-2 shadow-sm transition-all border-l-8 ${subType === 'investment' ? 'glass-card border-l-amber-500' : 'glass-card border-l-rose-500'}`}>
          <div className="flex items-center gap-2 text-slate-400 text-[10px] font-black uppercase tracking-widest"><Info size={12} /> Acumulado</div>
          <div className={`text-3xl font-black tracking-tight ${subType === 'investment' ? 'text-amber-700' : 'text-rose-700'}`}>
            {(subType === 'investment' ? totalInvested : totalExpenses).toLocaleString()} Kz
          </div>
        </div>
      )}

      {/* Transaction List */}
      <div className="space-y-4">
        {activeType === 'sale' ? (
          groupedSales && groupedSales.length > 0 ? (
            groupedSales.map(([dateStr, data]) => (
              <div key={dateStr} className="glass-card p-6 rounded-[32px] flex items-center justify-between group active:scale-98 transition-all">
                <div className="flex items-center gap-5">
                  <div className="bg-blue-600 p-4 rounded-2xl text-white shadow-lg shadow-blue-600/20">
                    <ShoppingCart size={22} />
                  </div>
                  <div className="flex flex-col">
                    <span className="font-black text-slate-900 text-base leading-none mb-1.5">{dateStr}</span>
                    <span className="text-[10px] text-slate-400 uppercase font-black tracking-widest">{data.count} LANÇAMENTOS</span>
                  </div>
                </div>
                <div className="flex flex-col items-end">
                  <span className="font-black text-blue-600 text-xl tracking-tight">+ {data.total.toLocaleString()} Kz</span>
                </div>
              </div>
            ))
          ) : (
            <div className="bg-white/30 backdrop-blur-sm p-16 rounded-[40px] border-4 border-dashed border-white/40 text-center flex flex-col items-center gap-4">
              <div className="p-6 bg-white/50 rounded-full">
                <Calendar size={48} className="text-slate-300" />
              </div>
              <p className="text-slate-400 text-xs font-black uppercase tracking-[0.1em] max-w-[150px] leading-relaxed">
                Sem vendas registradas hoje.
              </p>
            </div>
          )
        ) : (
          filteredTransactions.map(t => (
            <div key={t.id} className="glass-card p-6 rounded-[32px] flex items-center justify-between active:scale-98 transition-all">
              <div className="flex items-center gap-5">
                <div className={`p-4 rounded-2xl ${activeType === 'investment' ? 'bg-amber-100 text-amber-600 shadow-amber-500/10' : 'bg-rose-100 text-rose-600 shadow-rose-500/10'}`}>
                  {activeType === 'investment' ? <Landmark size={22} /> : <TrendingDown size={22} />}
                </div>
                <div className="flex flex-col">
                  <span className="font-black text-slate-900 text-base leading-none mb-1.5">{t.category}</span>
                  <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{new Date(t.date).toLocaleDateString('pt-BR')}</span>
                </div>
              </div>
              <div className="flex flex-col items-end">
                <span className={`font-black text-lg tracking-tight ${activeType === 'investment' ? 'text-amber-600' : 'text-rose-500'}`}>
                  - {t.amount.toLocaleString()} Kz
                </span>
              </div>
            </div>
          ))
        )}
      </div>

      {/* Modal Form */}
      {isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-xl" onClick={() => setIsOpen(false)} />
          <div className="relative bg-white w-full max-w-sm rounded-[48px] p-10 shadow-2xl animate-premium border border-white/40">
            <div className="flex justify-between items-center mb-10">
              <div className="flex flex-col">
                <h3 className="text-2xl font-black text-slate-900 tracking-tight">Novo Registro</h3>
                <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest">{activeType === 'sale' ? 'Faturamento' : 'Despesa'}</span>
              </div>
              <button onClick={() => setIsOpen(false)} className="text-slate-300 p-2 hover:bg-slate-50 rounded-full"><X size={32} /></button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-8">
              <div className="space-y-3">
                <div className="flex items-center justify-between px-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Categoria</label>
                  {activeType === 'investment' && (
                    <button 
                      type="button" 
                      onClick={toggleCategoryMode}
                      className="text-[9px] font-black text-blue-600 bg-blue-50 px-3 py-1.5 rounded-xl hover:bg-blue-100 transition-colors"
                    >
                      {isCustomCategory ? 'Ver Lista' : 'Criar Nova'}
                    </button>
                  )}
                </div>

                {isCustomCategory ? (
                  <input 
                    autoFocus
                    type="text" 
                    value={customCategory} 
                    onChange={e => setCustomCategory(e.target.value)} 
                    placeholder="Nome da categoria..." 
