export type TransactionType = 'sale' | 'expense' | 'investment';

export interface Transaction {
  id: string;
  date: string;
  type: TransactionType;
  category: string;
  amount: number;
  description: string;
  quantity?: number;
}

export interface InventoryItem {
  id: string;
  name: string;
  quantity: number;
  unit: string;
  minThreshold: number;
  price: number;
}

export interface InventoryMovement {
  id: string;
  itemId: string;
  itemName: string;
  quantity: number;
  date: string; // ISO string
}

export interface PHRecord {
  id: string;
  date: string;
  value: number;
  status: 'Ideal' | 'Alerta' | 'Crítico';
}

export interface AppNotification {
  id: string;
  title: string;
  message: string;
  type: 'warning' | 'info' | 'danger';
  date: string;
  read: boolean;
}

export interface BusinessState {
  transactions: Transaction[];
  inventory: InventoryItem[];
  inventoryMovements: InventoryMovement[];
  phRecords: PHRecord[];
  notifications: AppNotification[];
}

export interface Store {
  id: string;
  name: string;
  state: BusinessState;
}

export type ViewType = 'dashboard' | 'sales' | 'expenses' | 'inventory' | 'reports';

import React, { useState, useEffect, useMemo } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import TransactionForm from './components/TransactionForm';
import InventoryView from './components/InventoryView';
import ReportsView from './components/ReportsView';
import NotificationToast from './components/NotificationToast';
import { BusinessState, ViewType, Transaction, InventoryItem, Store, AppNotification, PHRecord } from './types';
import { INITIAL_INVENTORY } from './constants';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [toast, setToast] = useState<AppNotification | null>(null);

  // Multi-Store State
  const [stores, setStores] = useState<Store[]>(() => {
    const saved = localStorage.getItem('agua_cristalina_stores');
    if (saved) return JSON.parse(saved);

    // Migração de dados antigos ou estado inicial
    const legacyData = localStorage.getItem('agua_cristalina_state');
    const initialState: BusinessState = legacyData ? JSON.parse(legacyData) : {
      transactions: [],
      inventory: INITIAL_INVENTORY,
      inventoryMovements: [],
      phRecords: [],
      notifications: []
    };

    return [{
      id: 'default',
      name: 'Loja Principal',
      state: initialState
    }];
  });

  const [activeStoreId, setActiveStoreId] = useState<string>(() => {
    return localStorage.getItem('agua_cristalina_active_id') || 'default';
  });

  // Derived current store state
  const activeStore = useMemo(() => 
    stores.find(s => s.id === activeStoreId) || stores[0], 
  [stores, activeStoreId]);

  const state = activeStore.state;

  useEffect(() => {
    localStorage.setItem('agua_cristalina_stores', JSON.stringify(stores));
    localStorage.setItem('agua_cristalina_active_id', activeStoreId);
  }, [stores, activeStoreId]);

  const updateActiveStoreState = (updater: (prev: BusinessState) => BusinessState) => {
    setStores(prev => prev.map(s => 
      s.id === activeStoreId ? { ...s, state: updater(s.state) } : s
    ));
  };

  const handleAddStore = (name: string) => {
    const newStore: Store = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      state: {
        transactions: [],
        inventory: INITIAL_INVENTORY,
        inventoryMovements: [],
        phRecords: [],
        notifications: []
      }
    };
    setStores(prev => [...prev, newStore]);
    setActiveStoreId(newStore.id);
  };

  const addNotification = (title: string, message: string, type: 'warning' | 'info' | 'danger') => {
    const newNotif: AppNotification = {
      id: Math.random().toString(36).substr(2, 9),
      title,
      message,
      type,
      date: new Date().toISOString(),
      read: false
    };

    updateActiveStoreState(prev => ({
      ...prev,
      notifications: [newNotif, ...prev.notifications].slice(0, 50)
    }));

    setToast(newNotif);
    setTimeout(() => setToast(null), 5000);
  };

  const markAllNotificationsAsRead = () => {
    updateActiveStoreState(prev => ({
      ...prev,
      notifications: prev.notifications.map(n => ({ ...n, read: true }))
    }));
  };

  const handleAddTransaction = (newT: Omit<Transaction, 'id'>) => {
    const transaction: Transaction = {
      ...newT,
      id: Math.random().toString(36).substr(2, 9)
    };

    updateActiveStoreState(prev => ({
      ...prev,
      transactions: [...prev.transactions, transaction]
    }));
  };

  const handleAddPHRecord = (value: number) => {
    let status: 'Ideal' | 'Alerta' | 'Crítico' = 'Ideal';
    if (value < 6.5 || value > 8.5) status = 'Crítico';
    else if (value < 7.0 || value > 8.0) status = 'Alerta';

    const record: PHRecord = {
      id: Math.random().toString(36).substr(2, 9),
      date: new Date().toISOString(),
      value,
      status
    };

    updateActiveStoreState(prev => ({
      ...prev,
      phRecords: [record, ...prev.phRecords]
    }));

    if (status === 'Crítico') {
      addNotification('Qualidade Crítica', `O pH medido (${value}) está fora dos padrões de segurança!`, 'danger');
    }
  };

  const updateInventory = (id: string, delta: number) => {
    updateActiveStoreState(prev => {
      const item = prev.inventory.find(i => i.id === id);
      if (!item) return prev;

      const newQuantity = Math.max(0, item.quantity + delta);
      const newMovements = [...prev.inventoryMovements];

      if (delta < 0) {
        newMovements.push({
          id: Math.random().toString(36).substr(2, 9),
          itemId: id,
          itemName: item.name,
          quantity: Math.abs(delta),
          date: new Date().toISOString()
        });
      }

      if (newQuantity <= item.minThreshold && item.quantity > item.minThreshold) {
        setTimeout(() => {
          addNotification(
            'Estoque Baixo!', 
            `O item "${item.name}" atingiu o limite crítico (${newQuantity} ${item.unit} restantes).`, 
            'warning'
          );
        }, 100);
      }

      return {
        ...prev,
        inventory: prev.inventory.map(i => 
          i.id === id ? { ...i, quantity: newQuantity } : i
        ),
        inventoryMovements: newMovements
      };
    });
  };

  const handleAddInventoryItem = (newItem: Omit<InventoryItem, 'id'>) => {
    const item: InventoryItem = {
      ...newItem,
      id: Math.random().toString(36).substr(2, 9)
    };
    updateActiveStoreState(prev => ({
      ...prev,
      inventory: [...prev.inventory, item]
    }));
    addNotification('Novo Item', `"${item.name}" foi adicionado ao catálogo de estoque.`, 'info');
  };

  const renderContent = () => {
    switch (activeView) {
      case 'dashboard':
        return <Dashboard state={state} />;
      case 'sales':
        return <TransactionForm type="sale" onAdd={handleAddTransaction} transactions={state.transactions} />;
      case 'expenses':
        return <TransactionForm type="expense" onAdd={handleAddTransaction} transactions={state.transactions} />;
      case 'inventory':
        return <InventoryView inventory={state.inventory} movements={state.inventoryMovements} onUpdate={updateInventory} onAddItem={handleAddInventoryItem} />;
      case 'reports':
        return <ReportsView state={state} onAddPH={handleAddPHRecord} />;
      default:
        return <Dashboard state={state} />;
    }
  };

  return (
    <Layout 
      activeView={activeView} 
      setActiveView={setActiveView} 
      notifications={state.notifications}
      onMarkRead={markAllNotificationsAsRead}
      stores={stores}
      activeStoreId={activeStoreId}
      onSwitchStore={setActiveStoreId}
      onAddStore={handleAddStore}
    >
      <div className="pb-8">
        {renderContent()}
      </div>
      {toast && <NotificationToast notification={toast} onClose={() => setToast(null)} />}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { ViewType, AppNotification, Store } from '../types';
import { NAV_ITEMS } from '../constants';
import { Bell, X, Calendar, AlertTriangle, Info, AlertCircle, Droplets, ChevronDown, Plus, Store as StoreIcon } from 'lucide-react';

interface LayoutProps {
  children: React.ReactNode;
  activeView: ViewType;
  setActiveView: (view: ViewType) => void;
  notifications: AppNotification[];
  onMarkRead: () => void;
  stores: Store[];
  activeStoreId: string;
  onSwitchStore: (id: string) => void;
  onAddStore: (name: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ 
  children, 
  activeView, 
  setActiveView, 
  notifications, 
  onMarkRead,
  stores,
  activeStoreId,
  onSwitchStore,
  onAddStore
}) => {
  const [showNotifications, setShowNotifications] = useState(false);
  const [showStoreSwitcher, setShowStoreSwitcher] = useState(false);
  const [showAddStoreModal, setShowAddStoreModal] = useState(false);
  const [newStoreName, setNewStoreName] = useState('');

  const unreadCount = notifications.filter(n => !n.read).length;
  const activeStore = stores.find(s => s.id === activeStoreId) || stores[0];

  const handleOpenNotifications = () => {
    setShowNotifications(true);
    onMarkRead();
  };

  const handleAddStoreSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newStoreName.trim()) {
      onAddStore(newStoreName.trim());
      setNewStoreName('');
      setShowAddStoreModal(false);
      setShowStoreSwitcher(false);
    }
  };

  const getIcon = (type: string) => {
    switch(type) {
      case 'warning': return <AlertTriangle size={18} className="text-amber-500" />;
      case 'danger': return <AlertCircle size={18} className="text-red-500" />;
      default: return <Info size={18} className="text-blue-500" />;
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-md mx-auto relative overflow-hidden font-jakarta">
      {/* Header Premium */}
      <header className="px-6 py-6 flex items-center justify-between z-30 sticky top-0">
        <div className="flex items-center gap-3">
          <div className="w-11 h-11 bg-gradient-to-br from-blue-600 to-cyan-500 rounded-2xl flex items-center justify-center shadow-xl shadow-blue-500/20 ring-4 ring-white">
            <Droplets className="text-white" size={24} />
          </div>
          <button 
            onClick={() => setShowStoreSwitcher(!showStoreSwitcher)}
            className="flex flex-col items-start active:scale-95 transition-transform"
          >
            <div className="flex items-center gap-1">
              <h1 className="font-extrabold text-lg tracking-tight text-slate-900 leading-none">{activeStore.name}</h1>
              <ChevronDown size={14} className={`text-blue-600 transition-transform ${showStoreSwitcher ? 'rotate-180' : ''}`} />
            </div>
            <span className="text-[9px] text-blue-600 font-black uppercase tracking-[0.3em] mt-1">Agua Cristalina</span>
          </button>
        </div>

        <button 
          onClick={handleOpenNotifications}
          className="relative p-3 rounded-2xl glass-button text-slate-500 active:scale-90 transition-all border border-white/80"
        >
