const RenderCustomDot = (props: any) => {
  const { cx, cy, payload } = props;
  if (payload.status === 'Crítico') {
    return (
      <g>
        <circle cx={cx} cy={cy} r={12} fill={COLORS.Crítico} fillOpacity={0.2} className="animate-ping" />
