    );
  }
  return <circle cx={cx} cy={cy} r={4} fill={payload.status === 'Ideal' ? COLORS.Ideal : COLORS.Alerta} stroke="#fff" strokeWidth={2} />;
};

const CustomPHTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
