  const [phValue, setPhValue] = useState('');
  const [showPHForm, setShowPHForm] = useState(false);
  const [qualityDate, setQualityDate] = useState(new Date().toISOString().split('T')[0]);
  const [showFlashSummary, setShowFlashSummary] = useState(false);
  const [flashOffset, setFlashOffset] = useState(1);

  const changeQualityDate = (days: number) => {
    const current = new Date(qualityDate + 'T12:00:00');
    current.setDate(current.getDate() + days);
    setQualityDate(current.toISOString().split('T')[0]);
  };

  const isToday = qualityDate === new Date().toISOString().split('T')[0];

  const filteredPhRecords = useMemo(() => {
    return state.phRecords
      .filter(r => new Date(r.date).toISOString().split('T')[0] === qualityDate)
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [state.phRecords, qualityDate]);

  const hourlyPhData = useMemo(() => {
    return filteredPhRecords.map(r => ({
      time: new Date(r.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      value: r.value,
      status: r.status
    }));
  }, [filteredPhRecords]);

  const stabilityScore = useMemo(() => {
    if (filteredPhRecords.length === 0) return null;
    const idealCount = filteredPhRecords.filter(r => r.status === 'Ideal').length;
    return Math.round((idealCount / filteredPhRecords.length) * 100);
  }, [filteredPhRecords]);

  const monthlyStats = useMemo(() => {
    const now = new Date();
    const currentMonth = now.getMonth();
    const currentYear = now.getFullYear();
    const daysInMonth = now.getDate();
    const monthlySales = state.transactions.filter(t => {
      const d = new Date(t.date);
      return t.type === 'sale' && d.getMonth() === currentMonth && d.getFullYear() === currentYear;
    });
    const totalSales = monthlySales.reduce((sum, t) => sum + t.amount, 0);
    const avgDaily = daysInMonth > 0 ? totalSales / daysInMonth : 0;
    const categories: Record<string, number> = {};
    monthlySales.forEach(t => { categories[t.category] = (categories[t.category] || 0) + t.amount; });
    const bestCategory = Object.entries(categories).sort((a, b) => b[1] - a[1])[0]?.[0] || 'N/A';
    return { totalSales, avgDaily, bestCategory, monthName: new Intl.DateTimeFormat('pt-BR', { month: 'long' }).format(now) };
  }, [state.transactions]);

  const flashStats = useMemo(() => {
    const targetDate = new Date();
    targetDate.setDate(targetDate.getDate() - flashOffset);
    const dateKey = targetDate.toISOString().split('T')[0];
    const dayTransactions = state.transactions.filter(t => new Date(t.date).toISOString().split('T')[0] === dateKey);
    let label = flashOffset === 1 ? 'Ontem' : `${flashOffset} dias atrás`;
    return {
      sales: dayTransactions.filter(t => t.type === 'sale').reduce((sum, t) => sum + t.amount, 0),
      expenses: dayTransactions.filter(t => t.type === 'expense').reduce((sum, t) => sum + t.amount, 0),
      investments: dayTransactions.filter(t => t.type === 'investment').reduce((sum, t) => sum + t.amount, 0),
      dateStr: targetDate.toLocaleDateString('pt-BR', { day: '2-digit', month: 'short' }),
      relativeLabel: label
    };
  }, [state.transactions, flashOffset]);

  const groupedTransactions = useMemo(() => {
    const groups: Record<string, { date: string, sales: number, expenses: number, investments: number, items: Transaction[] }> = {};
    state.transactions.filter(t => filterType === 'all' || t.type === filterType).forEach(t => {
      const dateKey = new Date(t.date).toISOString().split('T')[0];
      if (!groups[dateKey]) { groups[dateKey] = { date: dateKey, sales: 0, expenses: 0, investments: 0, items: [] }; }
      if (t.type === 'sale') groups[dateKey].sales += t.amount;
      else if (t.type === 'expense') groups[dateKey].expenses += t.amount;
      else if (t.type === 'investment') groups[dateKey].investments += t.amount;
      groups[dateKey].items.push(t);
    });
    return Object.values(groups).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [state.transactions, filterType]);

  const handlePHSubmit = (e: React.FormEvent) => {
