import React, { useMemo } from 'react';
import { ResponsiveContainer, XAxis, YAxis, Tooltip, CartesianGrid, AreaChart, Area, BarChart, Bar } from 'recharts';
import { BusinessState } from '../types';
import { TrendingUp, TrendingDown, Wallet, BarChart3, Calendar, Sparkles, AlertCircle } from 'lucide-react';

interface DashboardProps {
  state: BusinessState;
}

const Dashboard: React.FC<DashboardProps> = ({ state }) => {
  const sales = state.transactions.filter(t => t.type === 'sale').reduce((sum, t) => sum + t.amount, 0);
  const expenses = state.transactions.filter(t => t.type === 'expense').reduce((sum, t) => sum + t.amount, 0);
  const investments = state.transactions.filter(t => t.type === 'investment').reduce((sum, t) => sum + t.amount, 0);

  const balance = sales - expenses - investments;

  const dailyTrends = useMemo(() => {
    const now = new Date();
    const daysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();
    const data = [];
    const salesMap: Record<number, number> = {};

    state.transactions
      .filter(t => t.type === 'sale')
      .forEach(t => {
        const d = new Date(t.date);
        if (d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear()) {
          const day = d.getDate();
          salesMap[day] = (salesMap[day] || 0) + t.amount;
        }
      });

    for (let i = 1; i <= daysInMonth; i++) {
      data.push({ day: i, total: salesMap[i] || 0 });
    }
    return data;
  }, [state.transactions]);

  const salesByCategory = state.transactions
    .filter(t => t.type === 'sale')
    .reduce((acc, t) => {
      acc[t.category] = (acc[t.category] || 0) + t.amount;
      return acc;
    }, {} as Record<string, number>);

  const topSalesData = Object.entries(salesByCategory)
    .map(([name, value]) => ({ name, value }))
    .sort((a, b) => (Number(b.value) - Number(a.value)))
    .slice(0, 5);

  const currentMonthName = new Intl.DateTimeFormat('pt-BR', { month: 'long' }).format(new Date());

  return (
    <div className="space-y-6 animate-premium pb-10">
      {/* Wallet Summary Card com escala ativa */}
      <div className="glass-card p-6 rounded-[40px] relative overflow-hidden active:scale-95 transition-all cursor-pointer shadow-blue-500/5 hover:shadow-blue-500/10 border border-white/50">
        <div className="relative z-10">
          <div className="flex justify-between items-start mb-6">
            <div className="flex flex-col">
              <span className="text-[10px] font-black text-blue-600 uppercase tracking-[0.2em] mb-1">Lucro Líquido Real</span>
              <span className={`text-4xl font-black tracking-tight ${balance >= 0 ? 'text-slate-900' : 'text-red-600'}`}>
                {balance.toLocaleString()} Kz
              </span>
            </div>
            <div className="bg-blue-600 p-4 rounded-3xl text-white shadow-xl shadow-blue-500/40 group-active:rotate-12 transition-transform">
              <Wallet size={28} />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="bg-emerald-50/60 p-4 rounded-3xl border border-emerald-100/50 hover:bg-emerald-50 transition-colors">
              <div className="flex items-center gap-2 mb-1.5">
                <TrendingUp size={14} className="text-emerald-600" />
                <span className="text-[9px] font-extrabold text-emerald-600 uppercase tracking-widest">Entradas</span>
              </div>
              <span className="text-lg font-black text-slate-800">+{sales.toLocaleString()} Kz</span>
            </div>
            <div className="bg-rose-50/60 p-4 rounded-3xl border border-rose-100/50 hover:bg-rose-50 transition-colors">
              <div className="flex items-center gap-2 mb-1.5">
                <TrendingDown size={14} className="text-rose-600" />
                <span className="text-[9px] font-extrabold text-rose-600 uppercase tracking-widest">Saídas</span>
              </div>
              <span className="text-lg font-black text-slate-800">-{(expenses + investments).toLocaleString()} Kz</span>
            </div>
          </div>
        </div>
        <Sparkles className="absolute -right-6 -bottom-6 w-32 h-32 text-blue-500/10 animate-pulse" />
      </div>

      {/* Daily Trends Chart */}
      <div className="glass-card p-6 rounded-[40px] active:scale-[0.99] transition-all border border-white/50">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-slate-900 font-extrabold text-base tracking-tight flex items-center gap-2">
            <Calendar size={20} className="text-blue-500" />
            Vendas Diárias
          </h3>
          <span className="bg-blue-50 text-blue-600 text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest border border-blue-100">{currentMonthName}</span>
        </div>
        <div className="h-56 w-full">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={dailyTrends}>
              <defs>
                <linearGradient id="colorTotal" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#2563eb" stopOpacity={0.3}/>
                  <stop offset="95%" stopColor="#2563eb" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(0,0,0,0.05)" />
              <XAxis dataKey="day" tick={{fontSize: 10, fontWeight: 700, fill: '#94a3b8'}} axisLine={false} tickLine={false} />
              <YAxis hide />
              <Tooltip 
                contentStyle={{ borderRadius: '24px', border: 'none', boxShadow: '0 20px 40px rgba(0,0,0,0.1)', background: 'rgba(255,255,255,0.95)' }}
                itemStyle={{ color: '#1e293b', fontWeight: 800, fontSize: '12px' }}
                labelStyle={{ color: '#64748b', fontWeight: 600, fontSize: '10px' }}
              />
              <Area type="monotone" dataKey="total" stroke="#2563eb" strokeWidth={4} fillOpacity={1} fill="url(#colorTotal)" animationDuration={2000} />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-6">
        {/* Categories Bar Chart */}
        <div className="glass-card p-6 rounded-[40px] active:scale-[0.98] transition-all border border-white/50">
          <h3 className="text-slate-900 font-extrabold text-base tracking-tight mb-6 flex items-center gap-2">
            <BarChart3 size={20} className="text-blue-500" />
            Categorias em Alta
          </h3>
          <div className="h-52 w-full">
            {topSalesData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={topSalesData} layout="vertical" margin={{ left: -10, right: 20 }}>
                  <XAxis type="number" hide />
                  <YAxis dataKey="name" type="category" width={100} tick={{ fontSize: 10, fontWeight: 800, fill: '#475569' }} axisLine={false} tickLine={false} />
                  <Tooltip 
                    cursor={{ fill: 'rgba(0,0,0,0.03)' }}
                    contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 10px 20px rgba(0,0,0,0.05)' }}
                  />
                  <Bar dataKey="value" fill="#3b82f6" radius={[0, 10, 10, 0]} barSize={20} animationDuration={1500} />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-slate-300 gap-3">
                <BarChart3 size={32} className="opacity-20" />
                <span className="text-[10px] font-bold uppercase tracking-widest">Sem vendas registradas</span>
              </div>
            )}
          </div>
        </div>

        {/* Low Stock Alerts */}
        <div className="glass-card p-6 rounded-[40px] border border-white/50">
          <h3 className="text-slate-900 font-extrabold text-sm tracking-tight mb-4 uppercase opacity-60">Status de Insumos</h3>
          <div className="space-y-4">
            {state.inventory.filter(i => i.quantity <= i.minThreshold).length === 0 ? (
              <div className="flex items-center gap-3 p-5 bg-emerald-50/50 rounded-3xl border border-emerald-100 shadow-sm active:scale-95 transition-all">
                <div className="w-2.5 h-2.5 rounded-full bg-emerald-500 animate-pulse shadow-sm shadow-emerald-200"></div>
                <p className="text-emerald-700 text-[10px] font-black uppercase tracking-[0.1em] italic">Estoque 100% em conformidade.</p>
              </div>
            ) : (
              state.inventory
                .filter(i => i.quantity <= i.minThreshold)
                .map(item => (
                  <div key={item.id} className="flex items-center justify-between p-5 bg-rose-50/50 rounded-3xl border border-rose-100 group active:scale-95 transition-all shadow-sm hover:shadow-rose-100">
                    <div className="flex flex-col">
                      <div className="flex items-center gap-2 mb-0.5">
                        <AlertCircle size={12} className="text-rose-600" />
                        <span className="text-slate-900 text-xs font-extrabold">{item.name}</span>
                      </div>
                      <span className="text-[9px] text-rose-600 font-black uppercase tracking-widest pl-5">Nível Crítico</span>
                    </div>
                    <span className="bg-rose-500 text-white text-[11px] px-5 py-2 rounded-2xl font-black shadow-lg shadow-rose-200">
                      {item.quantity} {item.unit}
                    </span>
                  </div>
                ))
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

