              </div>
              <span className="text-base font-black text-slate-800">+{sales.toLocaleString()}</span>
            </div>
            <div className="bg-rose-50/70 p-4 rounded-3xl border border-rose-100/50">
              <div className="flex items-center gap-2 mb-1.5">
                <TrendingDown size={14} className="text-rose-600" />
                <span className="text-[9px] font-black text-rose-600 uppercase tracking-widest">Gastos</span>
              </div>
              <span className="text-base font-black text-slate-800">-{(expenses + investments).toLocaleString()}</span>
            </div>
          </div>
        </div>
        <Sparkles className="absolute -right-8 -bottom-8 w-36 h-36 text-blue-500/5 opacity-50" />
      </div>

      {/* Daily Trends - INTERACTIVE */}
      <div className="glass-panel p-6 rounded-[40px] active:scale-[0.98] transition-all duration-300 border border-white/40 cursor-pointer">
