          <h3 className="text-slate-900 font-extrabold text-[10px] tracking-widest mb-4 uppercase opacity-50">Status Biológico e Insumos</h3>
          <div className="space-y-4">
            {state.inventory.filter(i => i.quantity <= i.minThreshold).length === 0 ? (
              <div className="flex items-center gap-3 p-5 bg-emerald-50/40 rounded-3xl border border-emerald-100/40">
                <div className="w-2.5 h-2.5 rounded-full bg-emerald-500 animate-pulse"></div>
                <p className="text-emerald-700 text-[10px] font-black uppercase tracking-widest">Tudo em conformidade.</p>
