interface ReportsViewProps {
  state: BusinessState;
  onAddPH: (value: number) => void;
}

type ReportTab = 'transactions' | 'inventory' | 'quality' | 'ai';

const COLORS = {
  Ideal: '#10b981',   // emerald-500
  Alerta: '#f59e0b',  // amber-500
  Crítico: '#ef4444', // red-500
};

const STATUS_MESSAGES = {
  Ideal: "A água está em perfeitas condições para consumo humano. Distribuição autorizada.",
  Alerta: "Leve desvio detectado. Verifique os filtros e realize uma nova medição em 1 hora.",
  Crítico: "RISCO DETECTADO! Interrompa a distribuição imediatamente e revise o sistema de filtragem."
};

const RenderCustomDot = (props: any) => {
  const { cx, cy, payload } = props;
  if (payload.status === 'Crítico') {
    return (
      <g>
        <circle cx={cx} cy={cy} r={14} fill={COLORS.Crítico} fillOpacity={0.2} className="animate-ping" />
        <circle cx={cx} cy={cy} r={7} fill={COLORS.Crítico} stroke="#fff" strokeWidth={2} />
      </g>
    );
  }
  return <circle cx={cx} cy={cy} r={5} fill={payload.status === 'Ideal' ? COLORS.Ideal : COLORS.Alerta} stroke="#fff" strokeWidth={2} />;
};

const CustomPHTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    const data = payload[0].payload;
