          <div className="flex justify-between items-start mb-6">
            <div className="flex flex-col">
              <span className="text-[10px] font-black text-blue-600 uppercase tracking-[0.3em] mb-1">Caixa Disponível</span>
              <span className={`text-4xl font-black tracking-tight ${balance >= 0 ? 'text-slate-900' : 'text-red-600'}`}>
                {balance.toLocaleString()} Kz
              </span>
            </div>
            <div className="bg-blue-600 p-4 rounded-3xl text-white shadow-2xl shadow-blue-500/40 group-active:scale-90 transition-transform">
              <Wallet size={28} />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="bg-emerald-50/70 p-4 rounded-3xl border border-emerald-100/50">
              <div className="flex items-center gap-2 mb-1.5">
                <TrendingUp size={14} className="text-emerald-600" />
                <span className="text-[9px] font-black text-emerald-600 uppercase tracking-widest">Ganhos</span>
              </div>
              <span className="text-base font-black text-slate-800">+{sales.toLocaleString()}</span>
            </div>
            <div className="bg-rose-50/70 p-4 rounded-3xl border border-rose-100/50">
