import React, { useMemo, useState } from 'react';
import { InventoryItem, InventoryMovement } from '../types';
import { Plus, Minus, AlertCircle, History, ChevronLeft, ChevronRight, X, ArrowDownRight, ArrowUpRight, PackagePlus, CircleDollarSign, Box } from 'lucide-react';

interface InventoryViewProps {
  inventory: InventoryItem[];
  movements: InventoryMovement[];
  onUpdate: (id: string, delta: number) => void;
  onAddItem: (item: Omit<InventoryItem, 'id'>) => void;
}

const InventoryView: React.FC<InventoryViewProps> = ({ inventory, movements, onUpdate, onAddItem }) => {
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
  const [adjustmentModal, setAdjustmentModal] = useState<{ isOpen: boolean; itemId: string; itemName: string; type: 'in' | 'out' } | null>(null);
  const [newItemModal, setNewItemModal] = useState(false);
  const [adjustmentAmount, setAdjustmentAmount] = useState('');

  const [newName, setNewName] = useState('');
  const [newUnit, setNewUnit] = useState('un');
  const [newMin, setNewMin] = useState('10');
  const [newInitial, setNewInitial] = useState('0');
  const [newPrice, setNewPrice] = useState('0');

  const inventoryValue = useMemo(() => {
    return inventory.reduce((sum, item) => sum + (item.quantity * item.price), 0);
  }, [inventory]);

  const handleAdjustmentSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const amount = parseInt(adjustmentAmount);
    if (adjustmentModal && !isNaN(amount) && amount > 0) {
      const delta = adjustmentModal.type === 'in' ? amount : -amount;
      onUpdate(adjustmentModal.itemId, delta);
      setAdjustmentModal(null);
      setAdjustmentAmount('');
    }
  };

  const handleCreateItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName) return;
    onAddItem({
      name: newName,
      unit: newUnit,
      minThreshold: parseInt(newMin) || 0,
      quantity: parseInt(newInitial) || 0,
      price: parseFloat(newPrice) || 0
    });
    setNewItemModal(false);
    setNewName('');
    setNewInitial('0');
    setNewPrice('0');
  };

  return (
    <div className="space-y-8 animate-premium pb-10">
      <div className="flex items-center justify-between">
        <div className="flex flex-col">
          <h2 className="text-2xl font-black text-slate-900 tracking-tight">Gestão de Estoque</h2>
          <p className="text-[10px] font-black text-blue-600 uppercase tracking-widest mt-1">Insumos e Galões</p>
        </div>
        <button 
          onClick={() => setNewItemModal(true)}
          className="bg-blue-600 text-white p-4 rounded-[22px] shadow-xl shadow-blue-600/20 active:scale-90 transition-all border-4 border-white"
        >
          <PackagePlus size={24} />
        </button>
      </div>

      <div className="glass-card rounded-[40px] p-8 relative overflow-hidden bg-gradient-to-br from-white/90 to-blue-50/50 border border-white">
        <div className="relative z-10 flex justify-between items-center">
          <div className="flex flex-col">
            <h3 className="text-[10px] font-black text-blue-600 uppercase tracking-widest mb-1">Valor em Ativos</h3>
            <h4 className="text-4xl font-black tracking-tight text-slate-900">{inventoryValue.toLocaleString()} Kz</h4>
          </div>
          <div className="bg-blue-600/10 p-4 rounded-3xl text-blue-600">
            <CircleDollarSign size={32} />
          </div>
        </div>
        <Box size={160} className="absolute -right-12 -bottom-12 text-blue-500/5" />
      </div>

      <div className="space-y-4">
        <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] px-2">Itens em Monitoramento</h3>
        {inventory.map(item => {
          const isLow = item.quantity <= item.minThreshold;
          return (
            <div key={item.id} className={`p-6 rounded-[32px] glass-card flex flex-col gap-6 transition-all group ${isLow ? 'ring-2 ring-rose-500/10' : ''} border border-white/50 shadow-sm`}>
              <div className="flex justify-between items-start">
                <div className="flex flex-col">
