const COLORS = {
  Ideal: '#10b981',   // emerald-500
  Alerta: '#f59e0b',  // amber-500
  Crítico: '#ef4444', // red-500
};

const STATUS_MESSAGES = {
  Ideal: "Qualidade Premium. pH ideal para consumo humano. Distribuição autorizada.",
  Alerta: "Monitoramento necessário. Leve desvio químico detectado.",
  Crítico: "ALERTA CRÍTICO: Água fora dos padrões de segurança! Revise os filtros."
};

const RenderCustomDot = (props: any) => {
  const { cx, cy, payload } = props;
  if (payload.status === 'Crítico') {
    return (
      <g>
        <circle cx={cx} cy={cy} r={16} fill={COLORS.Crítico} fillOpacity={0.2} className="animate-ping" />
        <circle cx={cx} cy={cy} r={8} fill={COLORS.Crítico} stroke="#fff" strokeWidth={3} className="shadow-lg" />
      </g>
    );
  }
  return <circle cx={cx} cy={cy} r={6} fill={payload.status === 'Ideal' ? COLORS.Ideal : COLORS.Alerta} stroke="#fff" strokeWidth={2} />;
};

const CustomPHTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    const data = payload[0].payload;
    const statusColor = COLORS[data.status as keyof typeof COLORS];
    const message = STATUS_MESSAGES[data.status as keyof typeof STATUS_MESSAGES];

    return (
      <div className="bg-white/95 backdrop-blur-xl p-5 rounded-[28px] shadow-2xl border border-white flex flex-col gap-3 min-w-[240px] animate-premium ring-8 ring-black/5">
        <div className="flex items-center justify-between border-b border-slate-100 pb-2">
          <div className="flex items-center gap-1.5 text-slate-400">
            <Clock size={14} className="text-blue-500" />
            <span className="text-[10px] font-black uppercase tracking-[0.1em]">{label}</span>
          </div>
          {data.status === 'Crítico' ? <TriangleAlert size={16} className="text-red-500 animate-pulse" /> : <ShieldCheck size={14} className="text-emerald-500" />}
        </div>

        <div className="flex flex-col gap-1">
          <div className="flex items-baseline gap-1.5">
            <span className="text-4xl font-black text-slate-900 leading-none">{data.value.toFixed(1)}</span>
            <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest">pH</span>
          </div>
          <div 
            className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest w-fit mt-1 shadow-sm border"
            style={{ backgroundColor: `${statusColor}15`, color: statusColor, borderColor: `${statusColor}30` }}
          >
            <div className={`w-2 h-2 rounded-full ${data.status === 'Crítico' ? 'animate-ping' : ''}`} style={{ backgroundColor: statusColor }}></div>
            {data.status}
          </div>
        </div>

        <p className="text-[10px] text-slate-600 font-bold leading-relaxed mt-1 border-t border-slate-50 pt-3 italic">
          "{message}"
        </p>
      </div>
    );
  }
  return null;
};

const ReportsView: React.FC<ReportsViewProps> = ({ state, onAddPH }) => {
  const [activeTab, setActiveTab] = useState<ReportTab>('transactions');
  const [filterType, setFilterType] = useState<'all' | 'sale' | 'expense' | 'investment'>('all');
  const [phValue, setPhValue] = useState('');
  const [showPHForm, setShowPHForm] = useState(false);
  const [qualityDate, setQualityDate] = useState(new Date().toISOString().split('T')[0]);
  const [showFlashSummary, setShowFlashSummary] = useState(false);
  const [flashOffset, setFlashOffset] = useState(1);

  const changeQualityDate = (days: number) => {
    const current = new Date(qualityDate + 'T12:00:00');
    current.setDate(current.getDate() + days);
    setQualityDate(current.toISOString().split('T')[0]);
  };

  const isToday = qualityDate === new Date().toISOString().split('T')[0];

  const filteredPhRecords = useMemo(() => {
    return state.phRecords
      .filter(r => new Date(r.date).toISOString().split('T')[0] === qualityDate)
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [state.phRecords, qualityDate]);

  const hourlyPhData = useMemo(() => {
    return filteredPhRecords.map(r => ({
      time: new Date(r.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      value: r.value,
      status: r.status
    }));
  }, [filteredPhRecords]);

  const stabilityScore = useMemo(() => {
    if (filteredPhRecords.length === 0) return null;
    const idealCount = filteredPhRecords.filter(r => r.status === 'Ideal').length;
    return Math.round((idealCount / filteredPhRecords.length) * 100);
  }, [filteredPhRecords]);

  // Estatísticas de Inventário
  const inventoryStats = useMemo(() => {
    const totalValue = state.inventory.reduce((sum, item) => sum + (item.quantity * item.price), 0);
    const lowStockCount = state.inventory.filter(i => i.quantity <= i.minThreshold).length;
    return { totalValue, lowStockCount };
  }, [state.inventory]);

  // Transações Agrupadas com Performance
  const groupedTransactions = useMemo(() => {
    const groups: Record<string, { 
      date: string, 
      sales: number, 
      expenses: number, 
      investments: number, 
      count: number,
      items: Transaction[] 
    }> = {};

    state.transactions
      .filter(t => filterType === 'all' || t.type === filterType)
      .forEach(t => {
        const dateKey = new Date(t.date).toISOString().split('T')[0];
        if (!groups[dateKey]) { 
          groups[dateKey] = { date: dateKey, sales: 0, expenses: 0, investments: 0, count: 0, items: [] }; 
        }
        if (t.type === 'sale') groups[dateKey].sales += t.amount;
        else if (t.type === 'expense') groups[dateKey].expenses += t.amount;
        else if (t.type === 'investment') groups[dateKey].investments += t.amount;
        groups[dateKey].count += 1;
        groups[dateKey].items.push(t);
      });

    return Object.values(groups).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [state.transactions, filterType]);

  const handlePHSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const val = parseFloat(phValue);
    if (!isNaN(val)) {
