                const progress = Math.min(100, (item.quantity / (item.quantity + totalMovements || 100)) * 100);

                return (
                  <div key={item.id} className="bg-white p-5 rounded-[32px] border border-slate-100 shadow-sm space-y-4 active:scale-[0.98] transition-all">
                    <div className="flex justify-between items-start">
