                             <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{item.quantity} {item.unit} em posse</span>
                             <div className="w-1 h-1 rounded-full bg-slate-200"></div>
                             <span className="text-[10px] text-blue-600 font-black">{(item.quantity * item.price).toLocaleString()} Kz</span>
                          </div>
                       </div>
                       <div className={`p-2 rounded-xl ${isCritical ? 'bg-red-50 text-red-500 animate-pulse' : 'bg-blue-50 text-blue-500'}`}>
                          <Package size={20} />
                       </div>
                    </div>

                    <div className="space-y-1.5">
                       <div className="flex justify-between text-[8px] font-black uppercase tracking-widest">
                          <span className={isCritical ? 'text-red-500' : 'text-slate-400'}>Min: {item.minThreshold}</span>
                          <span className="text-slate-400">Total: {item.quantity + totalMovements}</span>
                       </div>
                       <div className="h-3 bg-slate-50 rounded-full overflow-hidden border border-slate-100 p-0.5">
                          <div 
                            className={`h-full rounded-full transition-all duration-1000 ${isCritical ? 'bg-gradient-to-r from-red-500 to-rose-400 shadow-[0_0_8px_rgba(239,68,68,0.3)]' : 'bg-gradient-to-r from-blue-600 to-cyan-500'}`}
                            style={{ width: `${progress}%` }}
                          ></div>
                       </div>
                    </div>

                    <div className="flex justify-between items-center pt-2 border-t border-slate-50">
                       <div className="flex items-center gap-1.5">
                          <Coins size={12} className="text-slate-400" />
