import React, { useMemo, useState } from 'react';
import { InventoryItem, InventoryMovement } from '../types';
import { 
  Plus, 
  Minus, 
  AlertCircle, 
  History, 
  ChevronLeft, 
  ChevronRight, 
  X, 
  ArrowDownRight, 
  ArrowUpRight, 
  PackagePlus, 
  CircleDollarSign, 
  Box,
  Coins,
  Package,
  Sparkles
} from 'lucide-react';

interface InventoryViewProps {
  inventory: InventoryItem[];
  movements: InventoryMovement[];
  onUpdate: (id: string, delta: number) => void;
  onAddItem: (item: Omit<InventoryItem, 'id'>) => void;
}

const InventoryView: React.FC<InventoryViewProps> = ({ inventory, movements, onUpdate, onAddItem }) => {
  const [adjustmentModal, setAdjustmentModal] = useState<{ isOpen: boolean; itemId: string; itemName: string; type: 'in' | 'out' } | null>(null);
  const [newItemModal, setNewItemModal] = useState(false);
  const [adjustmentAmount, setAdjustmentAmount] = useState('');

  const [newName, setNewName] = useState('');
  const [newUnit, setNewUnit] = useState('un');
  const [newMin, setNewMin] = useState('10');
  const [newInitial, setNewInitial] = useState('0');
  const [newPrice, setNewPrice] = useState('0');

  const inventoryValue = useMemo(() => {
    return inventory.reduce((sum, item) => sum + (item.quantity * item.price), 0);
  }, [inventory]);

  const lowStockCount = useMemo(() => {
    return inventory.filter(i => i.quantity <= i.minThreshold).length;
  }, [inventory]);

  const handleAdjustmentSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const amount = parseInt(adjustmentAmount);
    if (adjustmentModal && !isNaN(amount) && amount > 0) {
      const delta = adjustmentModal.type === 'in' ? amount : -amount;
      onUpdate(adjustmentModal.itemId, delta);
      setAdjustmentModal(null);
      setAdjustmentAmount('');
    }
  };

  const handleCreateItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName) return;
    onAddItem({
      name: newName,
      unit: newUnit,
      minThreshold: parseInt(newMin) || 0,
      quantity: parseInt(newInitial) || 0,
      price: parseFloat(newPrice) || 0
    });
    setNewItemModal(false);
    setNewName('');
    setNewInitial('0');
    setNewPrice('0');
  };

  return (
    <div className="space-y-8 animate-premium pb-10">
      <div className="flex items-center justify-between">
        <div className="flex flex-col">
          <h2 className="text-2xl font-black text-slate-900 tracking-tight">Estoque</h2>
          <p className="text-[10px] font-black text-blue-600 uppercase tracking-widest mt-1">Gestão de Ativos Agua C</p>
        </div>
        <button 
          onClick={() => setNewItemModal(true)}
          className="bg-blue-600 text-white p-4 rounded-[22px] shadow-xl shadow-blue-600/20 active:scale-90 transition-all border-4 border-white"
        >
          <PackagePlus size={24} />
        </button>
      </div>

      {/* Dashboard de Ativos (Estilo Premium) */}
      <div className="bg-gradient-to-br from-slate-900 to-slate-800 p-8 rounded-[40px] text-white shadow-xl relative overflow-hidden active:scale-[0.99] transition-transform">
         <div className="relative z-10 flex justify-between items-end">
            <div className="flex flex-col gap-2">
               <div className="flex items-center gap-2 text-blue-400">
                  <Box size={16} />
                  <span className="text-[10px] font-black uppercase tracking-widest">Patrimônio em Insumos</span>
               </div>
               <h3 className="text-4xl font-black tracking-tight">{inventoryValue.toLocaleString()} Kz</h3>
               <div className="flex items-center gap-2 mt-2">
                  <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase border backdrop-blur-md ${lowStockCount > 0 ? 'bg-red-500/20 border-red-500/30 text-red-400' : 'bg-emerald-500/20 border-emerald-500/30 text-emerald-400'}`}>
                    {lowStockCount > 0 ? `${lowStockCount} Itens Críticos` : 'Fluxo em Conformidade'}
                  </span>
               </div>
            </div>
            <Sparkles size={120} className="text-white/5 absolute -right-6 -bottom-6 rotate-12" />
         </div>
      </div>

      <div className="space-y-4">
        <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] px-2">Monitoramento de Insumos</h3>
        {inventory.map(item => {
          const totalMovements = movements.filter(m => m.itemId === item.id).reduce((s, m) => s + m.quantity, 0);
          const isCritical = item.quantity <= item.minThreshold;
          // Cálculo de progresso para visualização analítica
          const progress = Math.min(100, (item.quantity / (item.quantity + totalMovements || (item.minThreshold * 2) || 100)) * 100);

          return (
            <div key={item.id} className={`bg-white p-6 rounded-[36px] border border-slate-100 shadow-sm space-y-5 active:scale-[0.98] transition-all group ${isCritical ? 'ring-2 ring-red-500/5' : ''}`}>
              <div className="flex justify-between items-start">
                 <div className="flex flex-col">
                    <h4 className="font-black text-slate-900 text-lg mb-1">{item.name}</h4>
                    <div className="flex items-center gap-2">
                       <span className={`text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-xl ${isCritical ? 'bg-red-50 text-red-600' : 'bg-blue-50 text-blue-600'}`}>
                          {item.quantity} {item.unit}
                       </span>
                       <div className="w-1 h-1 rounded-full bg-slate-200"></div>
                       <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{(item.quantity * item.price).toLocaleString()} Kz totais</span>
                    </div>
                 </div>
                 <div className={`p-3 rounded-2xl ${isCritical ? 'bg-red-50 text-red-500 animate-pulse' : 'bg-slate-50 text-slate-400'}`}>
                    {isCritical ? <AlertCircle size={20} /> : <Package size={20} />}
                 </div>
              </div>

              {/* Barra de Consumo Analítica */}
              <div className="space-y-2">
                 <div className="flex justify-between text-[8px] font-black uppercase tracking-widest">
                    <span className={isCritical ? 'text-red-500' : 'text-slate-400'}>Limite: {item.minThreshold}</span>
                    <span className="text-slate-400">Preço Un: {item.price.toLocaleString()} Kz</span>
                 </div>
                 <div className="h-3.5 bg-slate-50 rounded-full overflow-hidden border border-slate-100 p-0.5">
                    <div 
                      className={`h-full rounded-full transition-all duration-1000 ${isCritical ? 'bg-gradient-to-r from-red-500 to-rose-400 shadow-[0_0_8px_rgba(239,68,68,0.2)]' : 'bg-gradient-to-r from-blue-600 to-cyan-500'}`}
                      style={{ width: `${progress}%` }}
                    ></div>
                 </div>
              </div>

              {/* Ações Granulares */}
              <div className="flex gap-3 pt-1">
                <button 
                  onClick={() => setAdjustmentModal({ isOpen: true, itemId: item.id, itemName: item.name, type: 'out' })}
                  className="flex-1 bg-slate-50 text-slate-900 py-4 rounded-2xl font-black text-[9px] uppercase tracking-widest border border-slate-100 active:scale-95 transition-all flex items-center justify-center gap-2"
                >
                  <ArrowDownRight size={14} className="text-red-500" /> Baixa
                </button>
                <button 
                  onClick={() => setAdjustmentModal({ isOpen: true, itemId: item.id, itemName: item.name, type: 'in' })}
                  className="flex-1 bg-blue-600 text-white py-4 rounded-2xl font-black text-[9px] uppercase tracking-widest active:scale-95 transition-all flex items-center justify-center gap-2 shadow-lg shadow-blue-500/10"
                >
                  <ArrowUpRight size={14} /> Reposição
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {/* Modal de Ajuste (Entrada/Saída) */}
      {adjustmentModal?.isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-xl" onClick={() => setAdjustmentModal(null)} />
          <div className="relative bg-white w-full max-w-sm rounded-[48px] p-10 shadow-2xl animate-premium text-center">
            <h3 className="text-2xl font-black text-slate-900 mb-2">
              {adjustmentModal.type === 'in' ? 'Entrada' : 'Saída'} de Estoque
            </h3>
            <p className="text-[10px] text-blue-600 font-black uppercase tracking-widest mb-10">{adjustmentModal.itemName}</p>
            <form onSubmit={handleAdjustmentSubmit} className="space-y-8">
              <input 
                autoFocus
                type="number" 
                value={adjustmentAmount} 
                onChange={e => setAdjustmentAmount(e.target.value)} 
                placeholder="0" 
                className="w-full bg-slate-50 border border-slate-100 rounded-[32px] py-10 text-6xl font-black text-center focus:ring-8 focus:ring-blue-50 focus:outline-none" 
                required 
              />
              <button 
                type="submit" 
                className={`w-full text-white font-black py-6 rounded-[28px] shadow-2xl active:scale-95 transition-all ${
                  adjustmentModal.type === 'in' ? 'bg-blue-600 shadow-blue-500/20' : 'bg-red-600 shadow-red-500/20'
                }`}
              >
                CONFIRMAR {adjustmentModal.type === 'in' ? 'REPOSIÇÃO' : 'BAIXA'}
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Modal de Novo Item (Insumo) */}
      {newItemModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-xl" onClick={() => setNewItemModal(false)} />
          <div className="relative bg-white w-full max-w-sm rounded-[48px] p-10 shadow-2xl animate-premium">
            <div className="flex justify-between items-center mb-10">
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Novo Insumo</h3>
              <button onClick={() => setNewItemModal(false)} className="text-slate-300 p-2 hover:bg-slate-50 rounded-full"><X size={32} /></button>
            </div>
            <form onSubmit={handleCreateItem} className="space-y-6">
              <input value={newName} onChange={e => setNewName(e.target.value)} placeholder="Nome do Item" className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-4 text-sm font-bold focus:outline-none" required />
              <div className="grid grid-cols-2 gap-4">
                <input value={newUnit} onChange={e => setNewUnit(e.target.value)} placeholder="Unidade (un, L)" className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-4 text-sm font-bold focus:outline-none" required />
                <input type="number" value={newMin} onChange={e => setNewMin(e.target.value)} placeholder="Qtd Mínima" className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-4 text-sm font-bold focus:outline-none" required />
              </div>
              <input type="number" step="0.01" value={newPrice} onChange={e => setNewPrice(e.target.value)} placeholder="Preço de Custo (Kz)" className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-4 text-xl font-black focus:outline-none" required />
              <button type="submit" className="w-full bg-blue-600 text-white font-black py-5 rounded-[28px] shadow-2xl active:scale-95 transition-all mt-4">
                CADASTRAR ATIVO
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default InventoryView;

