  TriangleAlert,
  Megaphone,
  Lightbulb,
  Target,
  Rocket,
  ArrowRightLeft,
  Coins,
  Box
} from 'lucide-react';

interface ReportsViewProps {
  state: BusinessState;
  onAddPH: (value: number) => void;
}

type ReportTab = 'transactions' | 'quality' | 'ai';

const COLORS = {
  Ideal: '#10b981',   // emerald-500
  Alerta: '#f59e0b',  // amber-500
  Crítico: '#ef4444', // red-500
};

const STATUS_MESSAGES = {
  Ideal: "Qualidade Premium. pH ideal para consumo humano. Distribuição autorizada.",
  Alerta: "Monitoramento necessário. Leve desvio químico detectado.",
  Crítico: "ALERTA CRÍTICO: Água fora dos padrões de segurança! Revise os filtros."
};

const RenderCustomDot = (props: any) => {
  const { cx, cy, payload } = props;
  if (payload.status === 'Crítico') {
    return (
      <g>
        <circle cx={cx} cy={cy} r={16} fill={COLORS.Crítico} fillOpacity={0.2} className="animate-ping" />
        <circle cx={cx} cy={cy} r={8} fill={COLORS.Crítico} stroke="#fff" strokeWidth={3} className="shadow-lg" />
      </g>
    );
  }
  return <circle cx={cx} cy={cy} r={6} fill={payload.status === 'Ideal' ? COLORS.Ideal : COLORS.Alerta} stroke="#fff" strokeWidth={2} />;
};

const CustomPHTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    const data = payload[0].payload;
    const statusColor = COLORS[data.status as keyof typeof COLORS];
    const message = STATUS_MESSAGES[data.status as keyof typeof STATUS_MESSAGES];

    return (
      <div className="bg-white/95 backdrop-blur-xl p-5 rounded-[28px] shadow-2xl border border-white flex flex-col gap-3 min-w-[240px] animate-premium ring-8 ring-black/5">
        <div className="flex items-center justify-between border-b border-slate-100 pb-2">
          <div className="flex items-center gap-1.5 text-slate-400">
            <Clock size={14} className="text-blue-500" />
            <span className="text-[10px] font-black uppercase tracking-[0.1em]">{label}</span>
          </div>
          {data.status === 'Crítico' ? <TriangleAlert size={16} className="text-red-500 animate-pulse" /> : <ShieldCheck size={14} className="text-emerald-500" />}
        </div>

        <div className="flex flex-col gap-1">
          <div className="flex items-baseline gap-1.5">
            <span className="text-4xl font-black text-slate-900 leading-none">{data.value.toFixed(1)}</span>
            <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest">pH</span>
          </div>
          <div 
            className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest w-fit mt-1 shadow-sm border"
            style={{ backgroundColor: `${statusColor}15`, color: statusColor, borderColor: `${statusColor}30` }}
          >
            <div className={`w-2 h-2 rounded-full ${data.status === 'Crítico' ? 'animate-ping' : ''}`} style={{ backgroundColor: statusColor }}></div>
            {data.status}
          </div>
        </div>

        <p className="text-[10px] text-slate-600 font-bold leading-relaxed mt-1 border-t border-slate-50 pt-3 italic">
          "{message}"
        </p>
      </div>
    );
  }
  return null;
};

const ReportsView: React.FC<ReportsViewProps> = ({ state, onAddPH }) => {
  const [activeTab, setActiveTab] = useState<ReportTab>('transactions');
  const [filterType, setFilterType] = useState<'all' | 'sale' | 'expense' | 'investment'>('all');
  const [phValue, setPhValue] = useState('');
  const [showPHForm, setShowPHForm] = useState(false);
  const [qualityDate, setQualityDate] = useState(new Date().toISOString().split('T')[0]);

  const changeQualityDate = (days: number) => {
    const current = new Date(qualityDate + 'T12:00:00');
    current.setDate(current.getDate() + days);
    setQualityDate(current.toISOString().split('T')[0]);
  };

  const isToday = qualityDate === new Date().toISOString().split('T')[0];

  const filteredPhRecords = useMemo(() => {
    return state.phRecords
      .filter(r => new Date(r.date).toISOString().split('T')[0] === qualityDate)
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [state.phRecords, qualityDate]);

  const hourlyPhData = useMemo(() => {
    return filteredPhRecords.map(r => ({
      time: new Date(r.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      value: r.value,
      status: r.status
    }));
  }, [filteredPhRecords]);

  const stabilityScore = useMemo(() => {
    if (filteredPhRecords.length === 0) return null;
    const idealCount = filteredPhRecords.filter(r => r.status === 'Ideal').length;
    return Math.round((idealCount / filteredPhRecords.length) * 100);
  }, [filteredPhRecords]);

  // Transações Agrupadas com Performance
  const groupedTransactions = useMemo(() => {
    const groups: Record<string, { 
      date: string, 
      sales: number, 
      expenses: number, 
      investments: number, 
      count: number,
      items: Transaction[] 
    }> = {};

    state.transactions
      .filter(t => filterType === 'all' || t.type === filterType)
      .forEach(t => {
        const dateKey = new Date(t.date).toISOString().split('T')[0];
        if (!groups[dateKey]) { 
          groups[dateKey] = { date: dateKey, sales: 0, expenses: 0, investments: 0, count: 0, items: [] }; 
        }
        if (t.type === 'sale') groups[dateKey].sales += t.amount;
        else if (t.type === 'expense') groups[dateKey].expenses += t.amount;
        else if (t.type === 'investment') groups[dateKey].investments += t.amount;
        groups[dateKey].count += 1;
        groups[dateKey].items.push(t);
      });

    return Object.values(groups).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [state.transactions, filterType]);

  const handlePHSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const val = parseFloat(phValue);
    if (!isNaN(val)) {
      onAddPH(val);
      setPhValue('');
      setShowPHForm(false);
      setQualityDate(new Date().toISOString().split('T')[0]);
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn pb-12">
      <div className="flex flex-col gap-1">
        <h2 className="text-2xl font-black text-slate-800 tracking-tight">Relatórios</h2>
        <p className="text-slate-500 text-sm">Visão analítica da Água Cristalina.</p>
      </div>

      <div className="flex bg-slate-200/50 p-1 rounded-2xl overflow-x-auto no-scrollbar">
        <button onClick={() => setActiveTab('transactions')} className={`flex-1 px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'transactions' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><History size={14} /> Histórico</button>
        <button onClick={() => setActiveTab('quality')} className={`flex-1 px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'quality' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><Droplet size={14} /> Qualidade</button>
        <button onClick={() => setActiveTab('ai')} className={`flex-1 px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${activeTab === 'ai' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}><Sparkles size={14} /> IA & MKT</button>
      </div>

      {activeTab === 'transactions' && (
        <div className="space-y-6 animate-premium">
          {/* Card de Resumo de Fluxo */}
          <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm grid grid-cols-2 gap-4">
             <div className="flex flex-col gap-1">
                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Saldo do Período</span>
                <span className="text-xl font-black text-slate-900 leading-none">
                  {(state.transactions.filter(t => t.type === 'sale').reduce((s,t) => s+t.amount, 0) - state.transactions.filter(t => t.type !== 'sale').reduce((s,t) => s+t.amount, 0)).toLocaleString()} Kz
                </span>
             </div>
             <div className="flex flex-col gap-1 border-l border-slate-50 pl-4">
                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Ticket Médio</span>
                <span className="text-xl font-black text-blue-600 leading-none">
                  {Math.round(state.transactions.filter(t => t.type === 'sale').reduce((s,t) => s+t.amount, 0) / (state.transactions.filter(t => t.type === 'sale').length || 1)).toLocaleString()} Kz
                </span>
             </div>
          </div>

          <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1 px-1">
            {(['all', 'sale', 'expense', 'investment'] as const).map(type => (
              <button 
                key={type} 
                onClick={() => setFilterType(type)} 
                className={`px-4 py-2 rounded-full text-[10px] font-bold whitespace-nowrap transition-all border active:scale-90 ${filterType === type ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-slate-500 border-slate-200'}`}
              >
                {type === 'all' ? 'TUDO' : type === 'sale' ? 'VENDAS' : type === 'expense' ? 'SAÍDAS' : 'INVESTIMENTOS'}
              </button>
            ))}
          </div>

          <div className="space-y-8 px-1">
            {groupedTransactions.length === 0 ? (
              <div className="text-center py-20 opacity-30 flex flex-col items-center gap-4">
                <History size={48} />
                <span className="text-xs font-black uppercase tracking-widest">Nenhuma transação encontrada</span>
              </div>
            ) : (
              groupedTransactions.map(group => (
                <div key={group.date} className="space-y-3">
                  <div className="sticky top-0 bg-slate-50/90 backdrop-blur-md py-2 z-10 flex items-center justify-between px-2">
                    <span className="text-xs font-black text-slate-400 uppercase tracking-widest">
                      {new Date(group.date + 'T12:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: 'long' })}
                    </span>
                    <div className="flex gap-3">
                       <span className="text-[10px] font-black text-green-600">+{group.sales.toLocaleString()}</span>
                       <span className="text-[10px] font-black text-red-600">-{group.expenses.toLocaleString()}</span>
                    </div>
                  </div>
                  <div className="space-y-2">
                    {group.items.sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).map(t => (
                      <div key={t.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-50 flex items-center justify-between transition-all active:scale-95 group">
                        <div className="flex items-center gap-3">
                          <div className={`p-2.5 rounded-xl ${t.type === 'sale' ? 'bg-green-50 text-green-600' : t.type === 'expense' ? 'bg-red-50 text-red-600' : 'bg-amber-50 text-amber-600'}`}>
                            {t.type === 'sale' ? <ArrowUpRight size={16} /> : t.type === 'expense' ? <ArrowDownLeft size={16} /> : <Landmark size={16} />}
                          </div>
                          <div className="flex flex-col">
                            <span className="font-bold text-slate-800 text-sm mb-0.5 leading-none group-active:text-blue-600">{t.category}</span>
                            <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">{new Date(t.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                          </div>
                        </div>
                        <span className={`font-black text-sm tracking-tight ${t.type === 'sale' ? 'text-green-600' : 'text-red-600'}`}>
                          {t.type === 'sale' ? '+' : '-'} {t.amount.toLocaleString()} Kz
                        </span>
                      </div>
                    ))}
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {activeTab === 'quality' && (
        <div className="space-y-6 animate-premium">
          {stabilityScore !== null && (
            <div className="bg-white p-5 rounded-[32px] border border-slate-100 shadow-sm flex items-center justify-between active:scale-95 transition-transform cursor-pointer">
              <div className="flex items-center gap-4">
                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center ${stabilityScore >= 90 ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>
                  <CheckCircle2 size={32} />
                </div>
                <div className="flex flex-col">
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-0.5">Estabilidade Biológica</span>
                  <span className="text-lg font-black text-slate-800">{stabilityScore}% de Pureza Ideal</span>
                </div>
              </div>
              <div className="text-right">
                <span className={`text-xs font-black uppercase tracking-widest ${stabilityScore >= 90 ? 'text-emerald-500' : 'text-amber-500'}`}>
                  {stabilityScore >= 90 ? 'Conforme' : 'Atenção'}
                </span>
              </div>
            </div>
          )}

          <div className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center justify-between">
            <button onClick={() => changeQualityDate(-1)} className="p-2 text-slate-400 hover:text-blue-600 transition-colors active:scale-90"><ChevronLeft size={20} /></button>
            <div className="flex flex-col items-center">
              <input type="date" value={qualityDate} onChange={(e) => setQualityDate(e.target.value)} className="text-sm font-black text-slate-800 focus:outline-none bg-transparent cursor-pointer text-center" />
              <span className="text-[10px] text-blue-600 font-black uppercase tracking-widest mt-0.5">{isToday ? 'HOJE' : new Date(qualityDate + 'T12:00:00').toLocaleDateString('pt-BR', { weekday: 'short' })}</span>
            </div>
            <button onClick={() => changeQualityDate(1)} disabled={isToday} className={`p-2 transition-colors active:scale-90 ${isToday ? 'text-slate-100' : 'text-slate-400 hover:text-blue-600'}`}><ChevronRight size={20} /></button>
          </div>

          <div className="bg-white p-8 rounded-[40px] border border-slate-100 shadow-xl space-y-8 relative overflow-hidden">
            <div className="flex items-center justify-between relative z-10">
              <div className="flex flex-col">
                <h3 className="text-[10px] font-black text-blue-600 uppercase tracking-[0.2em] flex items-center gap-2 mb-1">
                  <ShieldCheck size={16} /> Monitoramento de Pureza
                </h3>
                <span className="text-base font-black text-slate-800 tracking-tight">Análise de pH Agua C</span>
              </div>
              <div className="flex flex-col items-end">
                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Alvo Neutro</span>
                <span className="text-sm font-black text-blue-600">7.0 pH</span>
              </div>
            </div>

            <div className="h-80 w-full relative z-10">
              {hourlyPhData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={hourlyPhData} margin={{ top: 20, right: 10, left: -25, bottom: 0 }}>
                    <defs>
                      <linearGradient id="uvGradient" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#2563eb" stopOpacity={0.3}/>
                        <stop offset="95%" stopColor="#2563eb" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f8fafc" />
                    <XAxis dataKey="time" tick={{fontSize: 9, fontBold: 900, fill: '#64748b'}} axisLine={false} tickLine={false} />
                    <YAxis domain={[5.5, 9.5]} ticks={[6.0, 6.5, 6.8, 7.0, 7.5, 8.0, 9.0]} tick={{fontSize: 8, fontBold: 800, fill: '#94a3b8'}} axisLine={false} tickLine={false} />

                    <Tooltip content={<CustomPHTooltip />} animationDuration={200} />

                    <ReferenceArea y1={5.5} y2={6.5} fill={COLORS.Crítico} fillOpacity={0.06} />
                    <ReferenceArea y1={6.5} y2={6.8} fill={COLORS.Alerta} fillOpacity={0.08} />
                    <ReferenceArea y1={6.8} y2={7.5} fill={COLORS.Ideal} fillOpacity={0.12}>
                       <Label value="ESTADO IDEAL" position="insideRight" fill={COLORS.Ideal} fontSize={8} fontWeight={900} offset={20} />
                    </ReferenceArea>
                    <ReferenceArea y1={7.5} y2={8.0} fill={COLORS.Alerta} fillOpacity={0.08} />
                    <ReferenceArea y1={8.0} y2={9.5} fill={COLORS.Crítico} fillOpacity={0.06} />

                    <ReferenceLine y={7.0} stroke="#3b82f6" strokeWidth={1} strokeDasharray="5 5" />

                    <Area 
                      type="monotone" 
                      dataKey="value" 
                      stroke="#2563eb" 
                      strokeWidth={5} 
                      fill="url(#uvGradient)" 
                      animationDuration={1500}
                      dot={<RenderCustomDot />}
                      activeDot={{ r: 8, strokeWidth: 4, stroke: '#fff', fill: '#2563eb' }}
                    />
                  </AreaChart>
                </ResponsiveContainer>
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-slate-300 gap-4 border-4 border-dashed border-slate-50 rounded-[40px] bg-slate-50/50">
                   <div className="bg-white p-6 rounded-full shadow-lg">
                    <Droplet size={48} className="text-slate-100" />
                   </div>
                   <span className="text-[11px] font-black uppercase tracking-[0.2em] block text-slate-400">Sem Coletas no Período</span>
                </div>
              )}
            </div>
          </div>

          <div className="bg-blue-600 p-8 rounded-[40px] text-white shadow-2xl shadow-blue-500/20 active:scale-[0.98] transition-all">
            {!showPHForm ? (
              <button onClick={() => setShowPHForm(true)} className="w-full flex items-center justify-between group">
                <div className="flex flex-col items-start text-left">
                  <span className="text-[10px] font-black opacity-70 uppercase tracking-[0.3em] mb-2">Protocolo de Segurança</span>
                  <span className="text-2xl font-black tracking-tight">Verificar Qualidade</span>
                </div>
                <div className="bg-white/20 p-4 rounded-3xl group-active:scale-90 transition-transform backdrop-blur-md border border-white/20">
                  <Plus size={28} strokeWidth={3} />
                </div>
              </button>
            ) : (
              <form onSubmit={handlePHSubmit} className="space-y-6 animate-premium">
                <div className="flex justify-between items-center mb-2">
                  <span className="text-xs font-black uppercase tracking-widest">Nova Medição</span>
                  <button type="button" onClick={() => setShowPHForm(false)} className="opacity-60 bg-white/10 p-2 rounded-xl active:scale-90"><ChevronDown size={20} /></button>
                </div>
