                  <input 
                    type="number" 
                    step="0.1" 
                    value={phValue} 
                    onChange={e => setPhValue(e.target.value)} 
                    placeholder="7.0" 
                    className="w-full bg-white/10 border border-white/30 rounded-[32px] px-8 py-8 text-6xl font-black text-white focus:outline-none focus:ring-8 focus:ring-white/10 placeholder:text-white/20 text-center" 
                    autoFocus 
                    required 
                  />
                  <div className="absolute right-8 bottom-8 flex items-center gap-1.5 opacity-40">
