                  CONFIRMAR PUREZA
                </button>
              </form>
            )}
          </div>
        </div>
      )}

      {activeTab === 'ai' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-gradient-to-br from-indigo-600 to-blue-700 p-8 rounded-[40px] text-white shadow-xl shadow-indigo-100 relative overflow-hidden active:scale-[0.98] transition-all cursor-pointer">
             <div className="relative z-10 space-y-5">
                <div className="flex items-center gap-3">
                  <div className="bg-white/20 p-2 rounded-2xl backdrop-blur-md">
                    <Megaphone size={22} className="text-white" />
                  </div>
                  <h3 className="text-sm font-black uppercase tracking-widest">Sugestão de Marketing</h3>
                </div>

                <div className="grid grid-cols-1 gap-3">
                   <div className="bg-white/10 p-5 rounded-3xl border border-white/10 backdrop-blur-sm">
                      <div className="flex items-center gap-2 mb-2">
                        <Lightbulb size={16} className="text-amber-400" />
                        <span className="text-[10px] font-black uppercase tracking-widest opacity-80">WhatsApp Pro</span>
                      </div>
                      <p className="text-xs font-bold leading-relaxed">
                        "Envie uma mensagem para clientes que não compram há 15 dias: 'Olá! Notamos que seu galão deve estar quase vazio. Que tal repor hoje com entrega grátis?' Luanda ama conveniência!"
                      </p>
                   </div>
                </div>

                <button 
                  onClick={() => setActiveTab('ai')}
                  className="w-full bg-white text-indigo-700 py-4 rounded-[24px] text-xs font-black uppercase tracking-widest shadow-lg shadow-black/10 active:scale-95 transition-all flex items-center justify-center gap-2"
                >
                  <Rocket size={16} /> Consultar Estratégia Completa
                </button>
             </div>
             <Sparkles size={140} className="absolute -right-12 -bottom-12 opacity-10 rotate-12" />
          </div>

          <AIAdvisor state={state} />
