            <Clock size={12} className="text-blue-500" />
            <span className="text-[10px] font-black uppercase tracking-[0.1em]">{label}</span>
          </div>
          <div className="flex items-center gap-1 px-2 py-0.5 rounded-full" style={{ backgroundColor: `${statusColor}15` }}>
            <div className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: statusColor }}></div>
            <span className="text-[9px] font-black uppercase tracking-widest" style={{ color: statusColor }}>
              {data.status}
            </span>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <span className="text-3xl font-black text-slate-900 leading-none">{data.value.toFixed(1)}</span>
          <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest">pH Coletado</span>
        </div>

        <p className="text-[10px] text-slate-600 font-bold leading-tight mt-1 bg-slate-50 p-2 rounded-xl">
          {message}
        </p>
      </div>
    );
  }
  return null;
};

const ReportsView: React.FC<ReportsViewProps> = ({ state, onAddPH }) => {
  const [activeTab, setActiveTab] = useState<ReportTab>('transactions');
  const [filterType, setFilterType] = useState<'all' | 'sale' | 'expense' | 'investment'>('all');
