import { TrendingUp, TrendingDown, Wallet, BarChart3, Calendar, Sparkles, AlertCircle } from 'lucide-react';

interface DashboardProps {
  state: BusinessState;
}

const Dashboard: React.FC<DashboardProps> = ({ state }) => {
  const sales = state.transactions.filter(t => t.type === 'sale').reduce((sum, t) => sum + t.amount, 0);
  const expenses = state.transactions.filter(t => t.type === 'expense').reduce((sum, t) => sum + t.amount, 0);
  const investments = state.transactions.filter(t => t.type === 'investment').reduce((sum, t) => sum + t.amount, 0);

  const balance = sales - expenses - investments;

  const dailyTrends = useMemo(() => {
    const now = new Date();
    const daysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();
    const data = [];
    const salesMap: Record<number, number> = {};

    state.transactions
      .filter(t => t.type === 'sale')
      .forEach(t => {
        const d = new Date(t.date);
        if (d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear()) {
          const day = d.getDate();
          salesMap[day] = (salesMap[day] || 0) + t.amount;
        }
      });

    for (let i = 1; i <= daysInMonth; i++) {
      data.push({ day: i, total: salesMap[i] || 0 });
    }
    return data;
  }, [state.transactions]);

  const salesByCategory = state.transactions
    .filter(t => t.type === 'sale')
    .reduce((acc, t) => {
      acc[t.category] = (acc[t.category] || 0) + t.amount;
      return acc;
    }, {} as Record<string, number>);

  const topSalesData = Object.entries(salesByCategory)
    .map(([name, value]) => ({ name, value }))
    .sort((a, b) => (Number(b.value) - Number(a.value)))
    .slice(0, 5);

  const currentMonthName = new Intl.DateTimeFormat('pt-BR', { month: 'long' }).format(new Date());

  return (
    <div className="space-y-8 animate-premium">

      {/* Top Section Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Wallet Summary Card */}
        <div className="lg:col-span-1 glass-panel p-10 rounded-[48px] relative overflow-hidden transition-all duration-300 shadow-sm border border-white hover:shadow-xl group bg-white/60">
          <div className="relative z-10">
            <div className="flex justify-between items-start mb-10">
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-blue-600 uppercase tracking-[0.4em] mb-2">Saldo em Caixa</span>
                <span className={`text-5xl font-black tracking-tight ${balance >= 0 ? 'text-slate-900' : 'text-red-600'}`}>
                  {balance.toLocaleString()} Kz
                </span>
              </div>
              <div className="bg-blue-600 p-5 rounded-3xl text-white shadow-2xl shadow-blue-500/30 group-hover:scale-110 transition-transform">
                <Wallet size={32} />
              </div>
            </div>

            <div className="grid grid-cols-1 gap-4">
              <div className="bg-emerald-50/70 p-6 rounded-3xl border border-emerald-100 flex items-center justify-between">
                <div className="flex flex-col">
                  <span className="text-[9px] font-black text-emerald-600 uppercase tracking-widest mb-1">Ganhos Totais</span>
                  <span className="text-xl font-black text-slate-800">+{sales.toLocaleString()}</span>
                </div>
                <TrendingUp size={24} className="text-emerald-500 opacity-30" />
              </div>
              <div className="bg-rose-50/70 p-6 rounded-3xl border border-rose-100 flex items-center justify-between">
                <div className="flex flex-col">
                  <span className="text-[9px] font-black text-rose-600 uppercase tracking-widest mb-1">Gastos Totais</span>
                  <span className="text-xl font-black text-slate-800">-{(expenses + investments).toLocaleString()}</span>
                </div>
                <TrendingDown size={24} className="text-rose-500 opacity-30" />
              </div>
            </div>
          </div>
          <Sparkles className="absolute -right-8 -bottom-8 w-48 h-48 text-blue-500/5 opacity-50" />
        </div>

        {/* Daily Trends - Desktop Expanded */}
        <div className="lg:col-span-2 glass-panel p-10 rounded-[48px] transition-all duration-300 border border-white shadow-sm hover:shadow-xl bg-white/60">
          <div className="flex justify-between items-center mb-10">
            <h3 className="text-slate-900 font-extrabold text-xl tracking-tight flex items-center gap-3">
              <Calendar size={24} className="text-blue-500" />
              Relatório de Fluxo de Caixa
            </h3>
            <span className="bg-blue-600 text-white text-[10px] font-black px-5 py-2 rounded-full uppercase tracking-widest shadow-lg shadow-blue-100">{currentMonthName}</span>
          </div>
          <div className="h-64 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={dailyTrends}>
                <defs>
                  <linearGradient id="colorTotal" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#2563eb" stopOpacity={0.3}/>
                    <stop offset="95%" stopColor="#2563eb" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(0,0,0,0.05)" />
                <XAxis dataKey="day" tick={{fontSize: 10, fontWeight: 800, fill: '#94a3b8'}} axisLine={false} tickLine={false} />
                <YAxis tick={{fontSize: 10, fontWeight: 800, fill: '#94a3b8'}} axisLine={false} tickLine={false} tickFormatter={(val) => `${(val/1000).toFixed(0)}k`} />
                <Tooltip 
                  contentStyle={{ borderRadius: '24px', border: 'none', boxShadow: '0 25px 50px rgba(0,0,0,0.1)', background: 'rgba(255,255,255,0.98)', padding: '20px' }}
                  itemStyle={{ color: '#1e293b', fontWeight: 900, fontSize: '14px' }}
                  cursor={{ stroke: '#3b82f6', strokeWidth: 2, strokeDasharray: '5 5' }}
                />
                <Area type="monotone" dataKey="total" stroke="#2563eb" strokeWidth={6} fillOpacity={1} fill="url(#colorTotal)" animationDuration={2000} />
              </AreaChart>
