      doc.setFont("helvetica", "bold");
      doc.text(`Saldo do Dia: ${(dSales - dExp - dInv).toLocaleString()} Kz`, 30, 105);

      doc.setFontSize(16);
      doc.setTextColor(37, 99, 235);
