                   <button type="submit" className="w-full bg-blue-600 text-white font-black py-7 rounded-[32px] shadow-2xl hover:scale-[1.02] active:scale-95 transition-all text-sm tracking-widest">
                     CONFIRMAR PUREZA DO LOTE
                   </button>
