import React, { useState, useEffect } from 'react';
import { Lock, Delete, Sparkles } from 'lucide-react';

interface LoginPinProps {
  onSuccess: () => void;
}

const REQUIRED_PIN = "244126";

const LoginPin: React.FC<LoginPinProps> = ({ onSuccess }) => {
  const [pin, setPin] = useState<string>('');
  const [error, setError] = useState(false);

  const handleKeyPress = (val: string) => {
    if (pin.length < 6) {
      setError(false);
      setPin(prev => prev + val);
    }
  };

  const handleDelete = () => {
    setPin(prev => prev.slice(0, -1));
    setError(false);
  };

  useEffect(() => {
    if (pin.length === 6) {
      if (pin === REQUIRED_PIN) {
        onSuccess();
      } else {
        setError(true);
        const timer = setTimeout(() => {
          setPin('');
          setError(false);
        }, 600);
        return () => clearTimeout(timer);
      }
    }
  }, [pin, onSuccess]);

  return (
    <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center px-8 bg-[#020617] overflow-hidden">
      {/* Background Glows */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[600px] bg-blue-600/10 rounded-full blur-[120px] pointer-events-none" />
      <div className="absolute -top-24 -left-24 w-96 h-96 bg-cyan-600/5 rounded-full blur-[80px] pointer-events-none" />

      {/* Branding */}
      <div className="relative flex flex-col items-center mb-12 space-y-6 animate-premium">
        <div className="relative group">
          <div className="absolute inset-0 bg-blue-500/20 blur-2xl rounded-full scale-110 group-hover:scale-125 transition-transform duration-700" />
          <div className="relative w-48 h-48 flex items-center justify-center">
            {/* Logo Image Placeholder - Assuming logo.png is present */}
            <img 
              src="https://raw.githubusercontent.com/ai-gen-images/placeholders/main/crystal-one-logo.png" 
              alt="CrystalOne Logo" 
              className="w-full h-full object-contain drop-shadow-[0_0_30px_rgba(59,130,246,0.5)]"
              onError={(e) => {
                // Fallback icon if image is missing
                e.currentTarget.style.display = 'none';
                e.currentTarget.parentElement?.classList.add('bg-gradient-to-br', 'from-blue-600', 'to-cyan-400', 'rounded-[40px]', 'shadow-2xl');
              }}
            />
          </div>
        </div>

        <div className="text-center">
          <h1 className="text-3xl font-black text-white tracking-tighter mb-1">CrystalOne</h1>
          <div className="flex items-center justify-center gap-2 opacity-60">
            <div className="h-[1px] w-8 bg-blue-400/50" />
            <span className="text-[10px] text-blue-300 font-bold uppercase tracking-[0.5em]">Gestão Premium</span>
            <div className="h-[1px] w-8 bg-blue-400/50" />
          </div>
        </div>
      </div>

      {/* PIN Display */}
      <div className={`relative flex gap-5 mb-16 ${error ? 'animate-shake' : ''}`}>
        {[...Array(6)].map((_, i) => (
          <div 
            key={i} 
            className={`w-3.5 h-3.5 rounded-full border transition-all duration-500 ${
              pin.length > i 
                ? (error ? 'bg-red-500 border-red-500 scale-125' : 'bg-blue-400 border-blue-400 scale-110 shadow-[0_0_15px_rgba(96,165,250,0.8)]') 
                : 'border-white/20 bg-white/5'
            }`}
          />
        ))}
      </div>

      {/* Keypad */}
      <div className="grid grid-cols-3 gap-5 w-full max-w-[320px] relative z-10">
        {['1', '2', '3', '4', '5', '6', '7', '8', '9'].map(num => (
          <button
            key={num}
            onClick={() => handleKeyPress(num)}
            className="w-full aspect-square rounded-[28px] bg-white/5 border border-white/10 text-xl font-bold text-white/90 backdrop-blur-md active:scale-90 active:bg-blue-600 active:border-blue-400 transition-all flex flex-col items-center justify-center hover:bg-white/10"
          >
            {num}
            <span className="text-[8px] opacity-40 mt-1 font-black">
              {num === '2' ? 'ABC' : num === '3' ? 'DEF' : num === '4' ? 'GHI' : num === '5' ? 'JKL' : num === '6' ? 'MNO' : num === '7' ? 'PQRS' : num === '8' ? 'TUV' : num === '9' ? 'WXYZ' : ''}
            </span>
          </button>
        ))}
        <div className="flex items-center justify-center">
           <Sparkles size={20} className="text-blue-500/30" />
        </div>
        <button
          onClick={() => handleKeyPress('0')}
          className="w-full aspect-square rounded-[28px] bg-white/5 border border-white/10 text-xl font-bold text-white/90 backdrop-blur-md active:scale-90 active:bg-blue-600 transition-all flex items-center justify-center hover:bg-white/10"
        >
          0
        </button>
        <button
          onClick={handleDelete}
          className="w-full aspect-square rounded-[28px] text-white/30 active:scale-90 active:text-red-500 transition-all flex items-center justify-center hover:text-white/60"
        >
          <Delete size={28} />
        </button>
