  return (
    <div className="flex h-screen bg-transparent relative overflow-hidden font-jakarta">

      {/* SIDEBAR - DESKTOP ONLY */}
      <aside className="hidden md:flex flex-col w-72 glass-panel border-r border-white/20 z-50 m-4 rounded-[40px] shadow-2xl">
        <div className="p-8">
          <div className="flex items-center gap-4 mb-10">
            <div className="w-14 h-14 bg-slate-900 rounded-2xl flex items-center justify-center shadow-xl shadow-blue-500/10 overflow-hidden p-1 border border-white/10">
              <img 
                src="https://raw.githubusercontent.com/ai-gen-images/placeholders/main/crystal-one-logo.png" 
