import React, { useState, useEffect, useMemo, useRef } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import TransactionForm from './components/TransactionForm';
import InventoryView from './components/InventoryView';
import ReportsView from './components/ReportsView';
import NotificationToast from './components/NotificationToast';
import LoginView from './components/LoginView';
import { BusinessState, ViewType, Transaction, InventoryItem, Store, AppNotification, PHRecord } from './types';
import { INITIAL_INVENTORY } from './constants';
import { supabase } from './services/supabase';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [toast, setToast] = useState<AppNotification | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isInitialLoading, setIsInitialLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);

  const [stores, setStores] = useState<Store[]>([]);
  const [activeStoreId, setActiveStoreId] = useState<string>('default');

  // Check Supabase session on mount
  useEffect(() => {
    const checkSession = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      setIsAuthenticated(!!session);

      // Listen for auth changes
      supabase.auth.onAuthStateChange((_event, session) => {
        setIsAuthenticated(!!session);
      });

      if (session) {
        await fetchData();
      } else {
        setIsInitialLoading(false);
      }
    };

    checkSession();
  }, []);

  const fetchData = async () => {
    setIsInitialLoading(true);
    try {
      const { data, error } = await supabase
        .from('stores')
        .select('*')
        .order('name', { ascending: true });

      if (error) throw error;

      if (data && data.length > 0) {
        setStores(data);
        const lastActiveId = localStorage.getItem('agua_cristalina_active_id');
        if (lastActiveId && data.find(s => s.id === lastActiveId)) {
          setActiveStoreId(lastActiveId);
        } else {
          setActiveStoreId(data[0].id);
        }
      } else {
        const defaultStore: Store = {
          id: 'default',
          name: 'Unidade Central CrystalOne',
          state: {
            transactions: [],
            inventory: INITIAL_INVENTORY,
            inventoryMovements: [],
            phRecords: [],
            notifications: []
          }
        };

        await supabase.from('stores').insert([defaultStore]);
        setStores([defaultStore]);
        setActiveStoreId('default');
      }
    } catch (err) {
      console.error('Erro ao carregar do Supabase:', err);
    } finally {
      setIsInitialLoading(false);
    }
  };

  // Persistence to Supabase (Debounced)
  const saveTimeoutRef = useRef<number | null>(null);
  useEffect(() => {
    if (isInitialLoading || stores.length === 0 || !isAuthenticated) return;

    if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);

    saveTimeoutRef.current = window.setTimeout(async () => {
      setIsSyncing(true);
      try {
        const activeStore = stores.find(s => s.id === activeStoreId);
        if (activeStore) {
          const { error } = await supabase
            .from('stores')
            .upsert({ 
              id: activeStore.id, 
              name: activeStore.name, 
              state: activeStore.state,
              updated_at: new Date().toISOString()
            });

          if (error) throw error;
          localStorage.setItem('agua_cristalina_active_id', activeStoreId);
        }
      } catch (err) {
        console.error('Erro ao salvar no Supabase:', err);
      } finally {
        setIsSyncing(false);
      }
    }, 1000);

    return () => {
      if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
    };
  }, [stores, activeStoreId, isInitialLoading, isAuthenticated]);

  const activeStore = useMemo(() => 
    stores.find(s => s.id === activeStoreId) || stores[0] || ({ id: 'default', name: 'Carregando...', state: { transactions: [], inventory: [], inventoryMovements: [], phRecords: [], notifications: [] } } as Store), 
  [stores, activeStoreId]);

  const state = activeStore.state;

  const handleLoginSuccess = async () => {
    setIsAuthenticated(true);
    await fetchData();
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setIsAuthenticated(false);
    setStores([]);
  };

  const updateActiveStoreState = (updater: (prev: BusinessState) => BusinessState) => {
    setStores(prev => prev.map(s => 
      s.id === activeStoreId ? { ...s, state: updater(s.state) } : s
    ));
  };

  const handleAddStore = async (name: string) => {
    const newStore: Store = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      state: {
        transactions: [],
        inventory: INITIAL_INVENTORY,
        inventoryMovements: [],
        phRecords: [],
        notifications: []
      }
    };

    setStores(prev => [...prev, newStore]);
    setActiveStoreId(newStore.id);
    await supabase.from('stores').insert([newStore]);
  };

  const addNotification = (title: string, message: string, type: 'warning' | 'info' | 'danger') => {
    const newNotif: AppNotification = {
      id: Math.random().toString(36).substr(2, 9),
      title,
      message,
      type,
      date: new Date().toISOString(),
      read: false
    };

    updateActiveStoreState(prev => ({
      ...prev,
      notifications: [newNotif, ...prev.notifications].slice(0, 50)
    }));

    setToast(newNotif);
    setTimeout(() => setToast(null), 5000);
  };

  const markAllNotificationsAsRead = () => {
    updateActiveStoreState(prev => ({
      ...prev,
      notifications: prev.notifications.map(n => ({ ...n, read: true }))
    }));
  };

  const handleAddTransaction = (newT: Omit<Transaction, 'id'>) => {
    const transaction: Transaction = {
      ...newT,
      id: Math.random().toString(36).substr(2, 9)
    };

    updateActiveStoreState(prev => ({
      ...prev,
      transactions: [...prev.transactions, transaction]
    }));
  };

  const handleAddPHRecord = (value: number) => {
    let status: 'Ideal' | 'Alerta' | 'Crítico' = 'Ideal';
    if (value < 6.5 || value > 8.0) status = 'Crítico';
    else if ((value >= 6.5 && value < 6.8) || (value > 7.5 && value <= 8.0)) status = 'Alerta';

    const record: PHRecord = {
      id: Math.random().toString(36).substr(2, 9),
      date: new Date().toISOString(),
      value,
      status
    };

    updateActiveStoreState(prev => ({
      ...prev,
      phRecords: [record, ...prev.phRecords]
    }));

    if (status === 'Crítico') {
      addNotification('RISCO BIOLÓGICO', `pH medido (${value}) fora dos padrões!`, 'danger');
    }
  };

  const updateInventory = (id: string, delta: number) => {
    updateActiveStoreState(prev => {
      const item = prev.inventory.find(i => i.id === id);
      if (!item) return prev;

      const newQuantity = Math.max(0, item.quantity + delta);
      const newMovements = [...prev.inventoryMovements];
      const newTransactions = [...prev.transactions];

      if (delta < 0) {
        const absDelta = Math.abs(delta);
        const saleAmount = absDelta * item.price;

        newMovements.push({
          id: Math.random().toString(36).substr(2, 9),
          itemId: id,
          itemName: item.name,
          quantity: absDelta,
          date: new Date().toISOString()
        });

        newTransactions.push({
          id: Math.random().toString(36).substr(2, 9),
          date: new Date().toISOString(),
          type: 'sale',
          category: item.name,
          amount: saleAmount,
          description: `Venda automática via estoque (${absDelta} ${item.unit})`,
          quantity: absDelta
        });
      }

      return {
        ...prev,
        inventory: prev.inventory.map(i => 
          i.id === id ? { ...i, quantity: newQuantity } : i
        ),
        inventoryMovements: newMovements,
        transactions: newTransactions
      };
    });
  };

  const handleAddInventoryItem = (newItem: Omit<InventoryItem, 'id'>) => {
    const item: InventoryItem = {
      ...newItem,
      id: Math.random().toString(36).substr(2, 9)
    };
    updateActiveStoreState(prev => ({
      ...prev,
      inventory: [...prev.inventory, item]
    }));
  };

  if (!isAuthenticated) return <LoginView onSuccess={handleLoginSuccess} />;

  if (isInitialLoading) {
    return (
      <div className="fixed inset-0 flex items-center justify-center bg-blue-50/50 backdrop-blur-md">
        <div className="flex flex-col items-center gap-6 animate-pulse">
          <div className="w-24 h-24 bg-blue-600 rounded-[36px] flex items-center justify-center shadow-2xl">
            <div className="w-10 h-10 border-4 border-white border-t-transparent rounded-full animate-spin" />
          </div>
          <span className="text-blue-600 font-black text-xs uppercase tracking-[0.4em]">Sincronizando Nuvem...</span>
        </div>
      </div>
    );
  }

  const renderContent = () => {
    switch (activeView) {
      case 'dashboard': return <Dashboard state={state} />;
      case 'sales': return <TransactionForm type="sale" onAdd={handleAddTransaction} transactions={state.transactions} />;
      case 'expenses': return <TransactionForm type="expense" onAdd={handleAddTransaction} transactions={state.transactions} />;
      case 'inventory': return <InventoryView inventory={state.inventory} movements={state.inventoryMovements} onUpdate={updateInventory} onAddItem={handleAddInventoryItem} />;
      case 'reports': return <ReportsView state={state} onAddPH={handleAddPHRecord} storeName={activeStore.name} />;
      default: return <Dashboard state={state} />;
    }
  };

  return (
    <Layout 
      activeView={activeView} 
      setActiveView={setActiveView} 
      notifications={state.notifications}
      onMarkRead={markAllNotificationsAsRead}
      stores={stores}
      activeStoreId={activeStoreId}
      onSwitchStore={setActiveStoreId}
      onAddStore={handleAddStore}
      onLogout={handleLogout}
    >
      <div className="pb-8 relative">
        {isSyncing && (
          <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[200] bg-white/90 backdrop-blur-xl px-6 py-2 rounded-full border border-blue-100 shadow-xl flex items-center gap-3 animate-slideInDown">
            <div className="w-2 h-2 bg-blue-500 rounded-full animate-pulse" />
            <span className="text-[9px] font-black text-blue-600 uppercase tracking-widest">Salvando no Supabase</span>
          </div>
        )}
        {renderContent()}
      </div>
      {toast && <NotificationToast notification={toast} onClose={() => setToast(null)} />}
    </Layout>
  );
};

export default App;

