              ) : (
                notifications.map(n => (
                  <div key={n.id} className={`p-6 rounded-3xl border transition-all ${n.read ? 'bg-white border-slate-50 opacity-60' : 'bg-blue-50/30 border-blue-100 shadow-sm'}`}>
