                FINALIZAR CADASTRO
              </button>
            </form>
          </div>
        </div>
      )}

    </div>
  );
};

export default Layout;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import TransactionForm from './components/TransactionForm';
import InventoryView from './components/InventoryView';
import ReportsView from './components/ReportsView';
import NotificationToast from './components/NotificationToast';
import LoginView from './components/LoginView';
import { BusinessState, ViewType, Transaction, InventoryItem, Store, AppNotification, PHRecord, InventoryMovement } from './types';
import { INITIAL_INVENTORY } from './constants';
import { supabase } from './services/supabase';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [toast, setToast] = useState<AppNotification | null>(null);
  const [isInitialLoading, setIsInitialLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);

  const [stores, setStores] = useState<any[]>([]);
  const [activeStoreId, setActiveStoreId] = useState<string | null>(null);

  // Estados segmentados
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [inventory, setInventory] = useState<InventoryItem[]>([]);
  const [movements, setMovements] = useState<InventoryMovement[]>([]);
  const [phRecords, setPhRecords] = useState<PHRecord[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);

  useEffect(() => {
    const checkSession = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      setIsAuthenticated(!!session);

      supabase.auth.onAuthStateChange((_event, session) => {
        setIsAuthenticated(!!session);
      });

      if (session) {
        await fetchStores();
      } else {
        setIsInitialLoading(false);
      }
    };

    checkSession();
  }, []);

  const fetchStores = async () => {
    try {
      const { data, error } = await supabase.from('stores').select('*').order('name');
      if (error) throw error;

      if (data && data.length > 0) {
        setStores(data);
        const savedId = localStorage.getItem('c1_active_store_id');
        const initialId = (savedId && data.find(s => s.id === savedId)) ? savedId : data[0].id;
        setActiveStoreId(initialId);
      } else {
        // Criar loja inicial se vazio
        const { data: newStore, error: createError } = await supabase
          .from('stores')
          .insert([{ name: 'Unidade Central CrystalOne' }])
          .select()
          .single();

        if (createError) throw createError;
        setStores([newStore]);
        setActiveStoreId(newStore.id);

        // Seed inicial de estoque
        const seedInventory = INITIAL_INVENTORY.map(item => ({
            store_id: newStore.id,
            name: item.name,
            quantity: item.quantity,
            unit: item.unit,
            min_threshold: item.minThreshold,
            price: item.price
        }));
        await supabase.from('inventory_items').insert(seedInventory);
      }
    } catch (err) {
      console.error('Erro lojas:', err);
    } finally {
      setIsInitialLoading(false);
    }
  };

  // Carregar dados da loja ativa
  useEffect(() => {
    if (!activeStoreId || !isAuthenticated) return;

    const loadStoreData = async () => {
      localStorage.setItem('c1_active_store_id', activeStoreId);

      const [tRes, iRes, phRes, nRes] = await Promise.all([
        supabase.from('transactions').select('*').eq('store_id', activeStoreId).order('created_at', { ascending: false }),
        supabase.from('inventory_items').select('*').eq('store_id', activeStoreId),
        supabase.from('ph_records').select('*').eq('store_id', activeStoreId).order('created_at', { ascending: false }),
        supabase.from('notifications').select('*').eq('store_id', activeStoreId).order('created_at', { ascending: false })
      ]);

      setTransactions(tRes.data || []);
      setInventory(iRes.data || []);
      setPhRecords(phRes.data || []);
      setNotifications(nRes.data || []);
    };

    loadStoreData();
  }, [activeStoreId, isAuthenticated]);

  const activeStoreName = useMemo(() => 
    stores.find(s => s.id === activeStoreId)?.name || 'Carregando...', 
  [stores, activeStoreId]);

  const businessState: BusinessState = {
    transactions,
    inventory,
    inventoryMovements: [], // Carregado sob demanda se necessário
    phRecords,
    notifications
  };

  const handleLoginSuccess = async () => {
    setIsAuthenticated(true);
    await fetchStores();
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setIsAuthenticated(false);
    setStores([]);
  };

  const handleAddStore = async (name: string) => {
    const { data, error } = await supabase.from('stores').insert([{ name }]).select().single();
    if (!error && data) {
      setStores(prev => [...prev, data]);
      setActiveStoreId(data.id);
    }
  };

  const handleAddTransaction = async (newT: Omit<Transaction, 'id'>) => {
    const { data, error } = await supabase.from('transactions').insert([{
      store_id: activeStoreId,
      type: newT.type,
      category: newT.category,
      amount: newT.amount,
      description: newT.description,
      quantity: newT.quantity
    }]).select().single();

    if (!error && data) setTransactions(prev => [data, ...prev]);
  };

  const handleAddPHRecord = async (value: number) => {
    let status: 'Ideal' | 'Alerta' | 'Crítico' = 'Ideal';
    if (value < 6.5 || value > 8.0) status = 'Crítico';
    else if ((value >= 6.5 && value < 6.8) || (value > 7.5 && value <= 8.0)) status = 'Alerta';

    const { data, error } = await supabase.from('ph_records').insert([{
      store_id: activeStoreId,
      value,
      status
    }]).select().single();

    if (!error && data) setPhRecords(prev => [data, ...prev]);
  };

  const updateInventory = async (id: string, delta: number) => {
    const item = inventory.find(i => i.id === id);
    if (!item) return;

    const newQty = Math.max(0, item.quantity + delta);
    const { error } = await supabase.from('inventory_items').update({ quantity: newQty }).eq('id', id);

    if (!error) {
      setInventory(prev => prev.map(i => i.id === id ? { ...i, quantity: newQty } : i));

      // Registrar movimento
      await supabase.from('inventory_movements').insert([{
        item_id: id,
        quantity: Math.abs(delta),
        type: delta > 0 ? 'in' : 'out'
      }]);

      // Se for saída, registrar venda automática
      if (delta < 0) {
        await handleAddTransaction({
          date: new Date().toISOString(),
          type: 'sale',
          category: item.name,
          amount: Math.abs(delta) * item.price,
          description: `Venda via estoque`,
          quantity: Math.abs(delta)
        });
      }
    }
  };

  const handleAddInventoryItem = async (newItem: Omit<InventoryItem, 'id'>) => {
    const { data, error } = await supabase.from('inventory_items').insert([{
      store_id: activeStoreId,
      name: newItem.name,
      quantity: newItem.quantity,
      unit: newItem.unit,
      min_threshold: newItem.minThreshold,
      price: newItem.price
    }]).select().single();

    if (!error && data) setInventory(prev => [...prev, data]);
  };

  if (!isAuthenticated) return <LoginView onSuccess={handleLoginSuccess} />;

  if (isInitialLoading) {
    return (
      <div className="fixed inset-0 flex items-center justify-center bg-slate-950">
        <div className="flex flex-col items-center gap-6">
          <div className="w-16 h-16 border-4 border-blue-600 border-t-transparent rounded-full animate-spin" />
          <span className="text-blue-500 font-black text-[10px] uppercase tracking-widest">Iniciando Cloud...</span>
        </div>
      </div>
    );
  }

  return (
    <Layout 
      activeView={activeView} 
      setActiveView={setActiveView} 
      notifications={notifications}
      onMarkRead={() => {}} 
      stores={stores}
      activeStoreId={activeStoreId || ''}
      onSwitchStore={setActiveStoreId}
      onAddStore={handleAddStore}
      onLogout={handleLogout}
    >
      <div className="pb-8">
        {activeView === 'dashboard' && <Dashboard state={businessState} />}
        {activeView === 'sales' && <TransactionForm type="sale" onAdd={handleAddTransaction} transactions={transactions} />}
        {activeView === 'expenses' && <TransactionForm type="expense" onAdd={handleAddTransaction} transactions={transactions} />}
        {activeView === 'inventory' && <InventoryView inventory={inventory} movements={[]} onUpdate={updateInventory} onAddItem={handleAddInventoryItem} />}
        {activeView === 'reports' && <ReportsView state={businessState} onAddPH={handleAddPHRecord} storeName={activeStoreName} />}
      </div>
      {toast && <NotificationToast notification={toast} onClose={() => setToast(null)} />}
    </Layout>
  );
};

export default App;

export type TransactionType = 'sale' | 'expense' | 'investment';

export interface Transaction {
  id: string;
  store_id?: string;
  date: string;
  type: TransactionType;
  category: string;
  amount: number;
  description: string;
  quantity?: number;
  created_at?: string;
}

export interface InventoryItem {
  id: string;
  store_id?: string;
  name: string;
  quantity: number;
  unit: string;
  min_threshold: number; // Mapeado do SQL min_threshold
  price: number;
  created_at?: string;
}

export interface InventoryMovement {
  id: string;
  item_id: string;
  quantity: number;
  type: 'in' | 'out';
  created_at: string;
}

export interface PHRecord {
  id: string;
  store_id?: string;
  value: number;
  status: 'Ideal' | 'Alerta' | 'Crítico';
  created_at: string;
}

export interface AppNotification {
  id: string;
  store_id?: string;
  title: string;
  message: string;
  type: 'warning' | 'info' | 'danger';
  read: boolean;
  created_at: string;
}

export interface BusinessState {
  transactions: Transaction[];
  inventory: InventoryItem[];
  inventoryMovements: InventoryMovement[];
  phRecords: PHRecord[];
  notifications: AppNotification[];
}

export interface Store {
  id: string;
  name: string;
  user_id: string;
  created_at: string;
}

export type ViewType = 'dashboard' | 'sales' | 'expenses' | 'inventory' | 'reports';

import React, { useState } from 'react';
import { ViewType, AppNotification, Store } from '../types';
import { NAV_ITEMS } from '../constants';
import { Bell, X, Calendar, AlertTriangle, Info, AlertCircle, Droplets, ChevronDown, Plus, Store as StoreIcon, LogOut } from 'lucide-react';

interface LayoutProps {
  children: React.ReactNode;
  activeView: ViewType;
  setActiveView: (view: ViewType) => void;
  notifications: AppNotification[];
  onMarkRead: () => void;
  stores: Store[];
  activeStoreId: string;
  onSwitchStore: (id: string) => void;
  onAddStore: (name: string) => void;
  onLogout?: () => void;
}

const Layout: React.FC<LayoutProps> = ({ 
  children, 
  activeView, 
  setActiveView, 
  notifications, 
  onMarkRead,
  stores,
  activeStoreId,
  onSwitchStore,
  onAddStore,
  onLogout
}) => {
  const [showNotifications, setShowNotifications] = useState(false);
  const [showStoreSwitcher, setShowStoreSwitcher] = useState(false);
  const [showAddStoreModal, setShowAddStoreModal] = useState(false);
  const [newStoreName, setNewStoreName] = useState('');

  const unreadCount = notifications.filter(n => !n.read).length;
  const activeStore = stores.find(s => s.id === activeStoreId) || stores[0] || { name: 'Carregando...' };

  const handleOpenNotifications = () => {
    setShowNotifications(true);
    onMarkRead();
  };

  const handleAddStoreSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newStoreName.trim()) {
      onAddStore(newStoreName.trim());
      setNewStoreName('');
      setShowAddStoreModal(false);
      setShowStoreSwitcher(false);
    }
  };

  const getIcon = (type: string) => {
    switch(type) {
      case 'warning': return <AlertTriangle size={18} className="text-amber-500" />;
      case 'danger': return <AlertCircle size={18} className="text-red-500" />;
      default: return <Info size={18} className="text-blue-500" />;
    }
  };

  return (
    <div className="flex h-screen bg-transparent relative overflow-hidden font-jakarta">

      {/* SIDEBAR - DESKTOP ONLY */}
      <aside className="hidden md:flex flex-col w-72 glass-panel border-r border-white/20 z-50 m-4 rounded-[40px] shadow-2xl">
        <div className="p-8">
          <div className="flex items-center gap-4 mb-10">
            <div className="w-12 h-12 bg-gradient-to-br from-blue-600 to-cyan-500 rounded-2xl flex items-center justify-center shadow-xl shadow-blue-500/20">
              <Droplets className="text-white" size={26} />
            </div>
            <div className="flex flex-col">
              <h1 className="font-extrabold text-lg text-slate-900 leading-none">CrystalOne</h1>
              <span className="text-[9px] text-blue-600 font-black uppercase tracking-[0.2em] mt-1">Management</span>
            </div>
          </div>

          <button 
            onClick={() => setShowStoreSwitcher(!showStoreSwitcher)}
            className="w-full flex items-center justify-between p-4 bg-white/50 rounded-2xl border border-white hover:bg-white transition-all group mb-8"
          >
            <div className="flex items-center gap-3 overflow-hidden">
              <StoreIcon size={18} className="text-blue-600 flex-shrink-0" />
              <span className="font-bold text-sm text-slate-700 truncate">{activeStore.name}</span>
            </div>
            <ChevronDown size={14} className={`text-slate-400 transition-transform ${showStoreSwitcher ? 'rotate-180' : ''}`} />
          </button>

          <nav className="space-y-2">
            {NAV_ITEMS.map((item) => {
              const isActive = activeView === item.id;
              return (
                <button
                  key={item.id}
                  onClick={() => setActiveView(item.id)}
                  className={`w-full flex items-center gap-4 p-4 rounded-2xl transition-all ${
                    isActive 
                      ? 'bg-blue-600 text-white shadow-xl shadow-blue-500/20' 
                      : 'text-slate-500 hover:bg-white hover:text-blue-600'
                  }`}
                >
                  {React.cloneElement(item.icon as React.ReactElement<any>, { size: 20 })}
                  <span className="font-bold text-sm">{item.label}</span>
                </button>
              );
            })}
          </nav>
        </div>

        <div className="mt-auto p-8 border-t border-white/10">
           <button onClick={onLogout} className="flex items-center gap-4 p-4 w-full text-slate-400 hover:text-red-500 transition-colors">
              <LogOut size={20} />
              <span className="font-bold text-sm">Sair do App</span>
           </button>
        </div>
      </aside>

      <div className="flex-1 flex flex-col relative overflow-hidden">

        {/* HEADER - MOBILE & DESKTOP (Notifications) */}
        <header className="px-6 py-6 flex items-center justify-between z-30 sticky top-0 md:bg-transparent">
          {/* Mobile Logo Only */}
          <div className="flex items-center gap-3 md:hidden">
            <div className="w-10 h-10 bg-gradient-to-br from-blue-600 to-cyan-500 rounded-xl flex items-center justify-center shadow-lg">
              <Droplets className="text-white" size={20} />
            </div>
            <button 
              onClick={() => setShowStoreSwitcher(!showStoreSwitcher)}
              className="flex flex-col items-start"
            >
              <div className="flex items-center gap-1">
                <h1 className="font-extrabold text-sm text-slate-900 leading-none">{activeStore.name}</h1>
                <ChevronDown size={12} className="text-blue-600" />
              </div>
            </button>
          </div>

          <div className="hidden md:block">
            {/* Espaço reservado para alinhar as notificações à direita no desktop */}
          </div>

          <button 
            onClick={handleOpenNotifications}
            className="relative p-3 rounded-2xl glass-button text-slate-500 active:scale-90 transition-all border border-white hover:shadow-lg"
          >
            <Bell size={20} />
            {unreadCount > 0 && (
              <span className="absolute top-2 right-2 w-4 h-4 bg-red-500 text-white text-[8px] font-black flex items-center justify-center rounded-full border-2 border-white">
                {unreadCount}
              </span>
            )}
          </button>
        </header>

        {/* CONTENT AREA */}
        <main className="flex-1 overflow-y-auto px-4 md:px-12 pb-24 md:pb-12 no-scrollbar z-10">
          <div className="max-w-6xl mx-auto py-4">
            {children}
          </div>
        </main>

        {/* BOTTOM NAV - MOBILE ONLY */}
        <div className="fixed bottom-6 left-6 right-6 z-40 md:hidden">
          <nav className="glass-panel rounded-[32px] flex justify-between items-center py-3 px-3 shadow-2xl border border-white/50">
            {NAV_ITEMS.map((item) => {
              const isActive = activeView === item.id;
              return (
                <button
                  key={item.id}
                  onClick={() => setActiveView(item.id)}
                  className={`flex flex-col items-center gap-1.5 transition-all duration-300 ${
                    isActive ? 'text-blue-600 scale-105' : 'text-slate-400'
