                className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${activeSeries.expenses ? 'bg-rose-500 text-white shadow-lg' : 'bg-slate-100 text-slate-400 opacity-50'}`}
