import React, { useState, useEffect, useMemo, useRef } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import TransactionForm from './components/TransactionForm';
import InventoryView from './components/InventoryView';
import ReportsView from './components/ReportsView';
import NotificationToast from './components/NotificationToast';
import LoginView from './components/LoginView';
import { BusinessState, ViewType, Transaction, InventoryItem, Store, AppNotification, PHRecord, InventoryMovement } from './types';
import { INITIAL_INVENTORY } from './constants';
import { supabase } from './services/supabase';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [toast, setToast] = useState<AppNotification | null>(null);
  const [isInitialLoading, setIsInitialLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);

  const [stores, setStores] = useState<any[]>([]);
  const [activeStoreId, setActiveStoreId] = useState<string | null>(null);

  // Estados segmentados
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [inventory, setInventory] = useState<InventoryItem[]>([]);
  const [movements, setMovements] = useState<InventoryMovement[]>([]);
  const [phRecords, setPhRecords] = useState<PHRecord[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);

  useEffect(() => {
    const checkSession = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      setIsAuthenticated(!!session);

      supabase.auth.onAuthStateChange((_event, session) => {
        setIsAuthenticated(!!session);
      });

      if (session) {
        await fetchStores();
      } else {
        setIsInitialLoading(false);
      }
    };

    checkSession();
  }, []);

  const fetchStores = async () => {
    try {
      const { data, error } = await supabase.from('stores').select('*').order('name');
      if (error) throw error;

      if (data && data.length > 0) {
        setStores(data);
        const savedId = localStorage.getItem('c1_active_store_id');
        const initialId = (savedId && data.find(s => s.id === savedId)) ? savedId : data[0].id;
        setActiveStoreId(initialId);
      } else {
        // Criar loja inicial se vazio
        const { data: newStore, error: createError } = await supabase
          .from('stores')
          .insert([{ name: 'Unidade Central CrystalOne' }])
          .select()
          .single();

        if (createError) throw createError;
        setStores([newStore]);
        setActiveStoreId(newStore.id);

        // Seed inicial de estoque
        const seedInventory = INITIAL_INVENTORY.map(item => ({
            store_id: newStore.id,
            name: item.name,
            quantity: item.quantity,
            unit: item.unit,
            min_threshold: item.minThreshold,
            price: item.price
        }));
        await supabase.from('inventory_items').insert(seedInventory);
      }
    } catch (err) {
      console.error('Erro lojas:', err);
    } finally {
      setIsInitialLoading(false);
    }
  };

  // Carregar dados da loja ativa
  useEffect(() => {
    if (!activeStoreId || !isAuthenticated) return;

    const loadStoreData = async () => {
      localStorage.setItem('c1_active_store_id', activeStoreId);

      const [tRes, iRes, phRes, nRes] = await Promise.all([
        supabase.from('transactions').select('*').eq('store_id', activeStoreId).order('created_at', { ascending: false }),
        supabase.from('inventory_items').select('*').eq('store_id', activeStoreId),
        supabase.from('ph_records').select('*').eq('store_id', activeStoreId).order('created_at', { ascending: false }),
        supabase.from('notifications').select('*').eq('store_id', activeStoreId).order('created_at', { ascending: false })
      ]);

      setTransactions(tRes.data || []);
      setInventory(iRes.data || []);
      setPhRecords(phRes.data || []);
      setNotifications(nRes.data || []);
    };

    loadStoreData();
  }, [activeStoreId, isAuthenticated]);

  const activeStoreName = useMemo(() => 
    stores.find(s => s.id === activeStoreId)?.name || 'Carregando...', 
  [stores, activeStoreId]);

  const businessState: BusinessState = {
    transactions,
    inventory,
    inventoryMovements: [], // Carregado sob demanda se necessário
    phRecords,
    notifications
  };

  const handleLoginSuccess = async () => {
    setIsAuthenticated(true);
    await fetchStores();
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setIsAuthenticated(false);
    setStores([]);
  };

  const handleAddStore = async (name: string) => {
    const { data, error } = await supabase.from('stores').insert([{ name }]).select().single();
    if (!error && data) {
      setStores(prev => [...prev, data]);
      setActiveStoreId(data.id);
    }
  };

  const handleAddTransaction = async (newT: Omit<Transaction, 'id'>) => {
    const { data, error } = await supabase.from('transactions').insert([{
      store_id: activeStoreId,
      type: newT.type,
      category: newT.category,
      amount: newT.amount,
      description: newT.description,
      quantity: newT.quantity
    }]).select().single();

    if (!error && data) setTransactions(prev => [data, ...prev]);
  };

  const handleAddPHRecord = async (value: number) => {
    let status: 'Ideal' | 'Alerta' | 'Crítico' = 'Ideal';
    if (value < 6.5 || value > 8.0) status = 'Crítico';
    else if ((value >= 6.5 && value < 6.8) || (value > 7.5 && value <= 8.0)) status = 'Alerta';

    const { data, error } = await supabase.from('ph_records').insert([{
      store_id: activeStoreId,
      value,
      status
    }]).select().single();

    if (!error && data) setPhRecords(prev => [data, ...prev]);
  };

  const updateInventory = async (id: string, delta: number) => {
    const item = inventory.find(i => i.id === id);
    if (!item) return;

    const newQty = Math.max(0, item.quantity + delta);
    const { error } = await supabase.from('inventory_items').update({ quantity: newQty }).eq('id', id);

    if (!error) {
      setInventory(prev => prev.map(i => i.id === id ? { ...i, quantity: newQty } : i));

      // Registrar movimento
      await supabase.from('inventory_movements').insert([{
        item_id: id,
        quantity: Math.abs(delta),
        type: delta > 0 ? 'in' : 'out'
      }]);

      // Se for saída, registrar venda automática
      if (delta < 0) {
        await handleAddTransaction({
          date: new Date().toISOString(),
          type: 'sale',
          category: item.name,
          amount: Math.abs(delta) * item.price,
          description: `Venda via estoque`,
          quantity: Math.abs(delta)
        });
      }
    }
  };

  const handleAddInventoryItem = async (newItem: Omit<InventoryItem, 'id'>) => {
    const { data, error } = await supabase.from('inventory_items').insert([{
      store_id: activeStoreId,
      name: newItem.name,
      quantity: newItem.quantity,
      unit: newItem.unit,
      /* Fix: change minThreshold to min_threshold */
      min_threshold: newItem.min_threshold,
      price: newItem.price
    }]).select().single();

    if (!error && data) setInventory(prev => [...prev, data]);
  };

  if (!isAuthenticated) return <LoginView onSuccess={handleLoginSuccess} />;

  if (isInitialLoading) {
    return (
      <div className="fixed inset-0 flex items-center justify-center bg-slate-950">
        <div className="flex flex-col items-center gap-6">
          <div className="w-16 h-16 border-4 border-blue-600 border-t-transparent rounded-full animate-spin" />
          <span className="text-blue-500 font-black text-[10px] uppercase tracking-widest">Iniciando Cloud...</span>
        </div>
      </div>
    );
  }

  return (
    <Layout 
      activeView={activeView} 
      setActiveView={setActiveView} 
      notifications={notifications}
      onMarkRead={() => {}} 
      stores={stores}
      activeStoreId={activeStoreId || ''}
      onSwitchStore={setActiveStoreId}
      onAddStore={handleAddStore}
      onLogout={handleLogout}
    >
      <div className="pb-8">
        {activeView === 'dashboard' && <Dashboard state={businessState} />}
        {activeView === 'sales' && <TransactionForm type="sale" onAdd={handleAddTransaction} transactions={transactions} />}
        {activeView === 'expenses' && <TransactionForm type="expense" onAdd={handleAddTransaction} transactions={transactions} />}
        {activeView === 'inventory' && <InventoryView inventory={inventory} movements={[]} onUpdate={updateInventory} onAddItem={handleAddInventoryItem} />}
        {activeView === 'reports' && <ReportsView state={businessState} onAddPH={handleAddPHRecord} storeName={activeStoreName} />}
      </div>
      {toast && <NotificationToast notification={toast} onClose={() => setToast(null)} />}
    </Layout>
  );
};

export default App;

