alter table transactions enable row level security;
alter table inventory_items enable row level security;
alter table inventory_movements enable row level security;
alter table ph_records enable row level security;
alter table notifications enable row level security;

create policy "Users can manage their stores" on stores for all using (auth.uid() = user_id);
create policy "Users can manage their transactions" on transactions for all using (exists (select 1 from stores where stores.id = transactions.store_id and stores.user_id = auth.uid()));
create policy "Users can manage their inventory" on inventory_items for all using (exists (select 1 from stores where stores.id = inventory_items.store_id and stores.user_id = auth.uid()));
create policy "Users can manage inventory movements" on inventory_movements for all using (exists (select 1 from inventory_items join stores on stores.id = inventory_items.store_id where inventory_items.id = item_id and stores.user_id = auth.uid()));
create policy "Users can manage ph records" on ph_records for all using (exists (select 1 from stores where stores.id = ph_records.store_id and stores.user_id = auth.uid()));
