import React, { useState, useEffect, useMemo } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import TransactionForm from './components/TransactionForm';
import InventoryView from './components/InventoryView';
import ReportsView from './components/ReportsView';
import NotificationToast from './components/NotificationToast';
import LoginView from './components/LoginView';
import { BusinessState, ViewType, Transaction, InventoryItem, Store, AppNotification, PHRecord } from './types';
import { INITIAL_INVENTORY } from './constants';
import { supabase, isSupabaseConfigured } from './services/supabase';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [toast, setToast] = useState<AppNotification | null>(null);
  const [isInitialLoading, setIsInitialLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(!isSupabaseConfigured());

  const [stores, setStores] = useState<Store[]>([{ id: 'local-store', name: 'Agua C - Loja Principal', user_id: 'local', created_at: new Date().toISOString() }]);
  const [activeStoreId, setActiveStoreId] = useState<string | null>('local-store');

  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [inventory, setInventory] = useState<InventoryItem[]>([]);
  const [phRecords, setPhRecords] = useState<PHRecord[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);

  // Carregamento Inicial (Híbrido)
  useEffect(() => {
    const initApp = async () => {
      if (isSupabaseConfigured()) {
        try {
          const { data: { session } } = await supabase.auth.getSession();
          if (session) {
            setIsAuthenticated(true);
            await loadSupabaseData();
          }
        } catch (e) {
          console.warn("Supabase Offline, usando modo local.");
          loadLocalData();
        }
      } else {
        loadLocalData();
      }
      setIsInitialLoading(false);
    };

    initApp();
  }, []);

  const loadLocalData = () => {
    const savedTransactions = localStorage.getItem('aguac_transactions');
    const savedInventory = localStorage.getItem('aguac_inventory');
    const savedPH = localStorage.getItem('aguac_ph');

    if (savedTransactions) setTransactions(JSON.parse(savedTransactions));
    if (savedInventory) {
      setInventory(JSON.parse(savedInventory));
    } else {
      // Popular com dados iniciais se for a primeira vez
      const initial = INITIAL_INVENTORY.map(item => ({
        ...item,
        store_id: 'local-store',
        min_threshold: item.minThreshold // Mapeamento de compatibilidade
      })) as unknown as InventoryItem[];
      setInventory(initial);
      localStorage.setItem('aguac_inventory', JSON.stringify(initial));
    }
    if (savedPH) setPhRecords(JSON.parse(savedPH));
  };

  const loadSupabaseData = async () => {
    // Implementação de busca no Supabase se configurado
    const { data: storeData } = await supabase.from('stores').select('*');
    if (storeData && storeData.length > 0) {
      setStores(storeData);
      setActiveStoreId(storeData[0].id);
    }
  };

  // Persistência Local Automática
  useEffect(() => {
    if (!isAuthenticated) return;
    localStorage.setItem('aguac_transactions', JSON.stringify(transactions));
    localStorage.setItem('aguac_inventory', JSON.stringify(inventory));
    localStorage.setItem('aguac_ph', JSON.stringify(phRecords));
  }, [transactions, inventory, phRecords, isAuthenticated]);

  const handleAddTransaction = async (newT: Omit<Transaction, 'id' | 'created_at' | 'store_id'>) => {
    const entry: Transaction = {
      ...newT,
      id: crypto.randomUUID(),
      store_id: activeStoreId || 'local-store',
      created_at: new Date().toISOString()
    };
    setTransactions(prev => [entry, ...prev]);

    if (isSupabaseConfigured() && isAuthenticated) {
      await supabase.from('transactions').insert([entry]);
    }
  };

  const handleUpdateInventory = async (id: string, delta: number) => {
    setInventory(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(0, item.quantity + delta);

        // Se for uma saída (venda), registra a transação
        if (delta < 0) {
          handleAddTransaction({
            type: 'sale',
            category: item.name,
            amount: Math.abs(delta) * item.price,
            description: `Venda automática de estoque`,
            quantity: Math.abs(delta)
          });
        }

        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const handleAddPHRecord = (value: number) => {
    let status: 'Ideal' | 'Alerta' | 'Crítico' = 'Ideal';
    if (value < 6.5 || value > 8.0) status = 'Crítico';
    else if ((value >= 6.5 && value < 6.8) || (value > 7.5 && value <= 8.0)) status = 'Alerta';

    const record: PHRecord = {
      id: crypto.randomUUID(),
      store_id: activeStoreId || 'local-store',
      value,
      status,
      created_at: new Date().toISOString()
    };
    setPhRecords(prev => [record, ...prev]);
  };

  const handleAddInventoryItem = (newItem: Omit<InventoryItem, 'id' | 'store_id' | 'created_at'>) => {
    const entry: InventoryItem = {
      ...newItem,
      id: crypto.randomUUID(),
      store_id: activeStoreId || 'local-store',
      created_at: new Date().toISOString()
    };
    setInventory(prev => [...prev, entry]);
  };

  if (isInitialLoading) {
    return (
      <div className="fixed inset-0 flex items-center justify-center bg-blue-50">
        <div className="flex flex-col items-center gap-4">
          <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
          <span className="text-blue-600 font-black text-[10px] uppercase tracking-widest">Carregando Agua C...</span>
        </div>
      </div>
    );
  }

  if (!isAuthenticated && isSupabaseConfigured()) {
    return <LoginView onSuccess={() => setIsAuthenticated(true)} />;
  }

  const businessState: BusinessState = {
    transactions,
    inventory,
    inventoryMovements: [],
    phRecords,
    notifications
  };

  return (
    <Layout 
      activeView={activeView} 
      setActiveView={setActiveView} 
      notifications={notifications}
      onMarkRead={() => {}} 
      stores={stores}
      activeStoreId={activeStoreId || ''}
      onSwitchStore={setActiveStoreId}
      onAddStore={(name) => {
        const newStore = { id: crypto.randomUUID(), name, user_id: 'local', created_at: new Date().toISOString() };
        setStores(prev => [...prev, newStore]);
      }}
      onLogout={() => {
        if (isSupabaseConfigured()) supabase.auth.signOut();
        setIsAuthenticated(false);
      }}
    >
      <div className="pb-24">
        {activeView === 'dashboard' && <Dashboard state={businessState} />}
        {activeView === 'sales' && <TransactionForm type="sale" onAdd={handleAddTransaction} transactions={transactions} />}
        {activeView === 'expenses' && <TransactionForm type="expense" onAdd={handleAddTransaction} transactions={transactions} />}
        {activeView === 'inventory' && <InventoryView inventory={inventory} movements={[]} onUpdate={handleUpdateInventory} onAddItem={handleAddInventoryItem} />}
        {activeView === 'reports' && <ReportsView state={businessState} onAddPH={handleAddPHRecord} storeName={stores.find(s => s.id === activeStoreId)?.name} />}
      </div>
      {toast && <NotificationToast notification={toast} onClose={() => setToast(null)} />}
    </Layout>
  );
};

export default App;

