import React, { useState, useEffect, useMemo } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import TransactionForm from './components/TransactionForm';
import InventoryView from './components/InventoryView';
import ReportsView from './components/ReportsView';
import NotificationToast from './components/NotificationToast';
import LoginView from './components/LoginView';
import { BusinessState, ViewType, Transaction, InventoryItem, Store, AppNotification, PHRecord } from './types';
import { INITIAL_INVENTORY } from './constants';
import { supabase } from './services/supabase';
import { Database } from 'lucide-react';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [toast, setToast] = useState<AppNotification | null>(null);
  const [isInitialLoading, setIsInitialLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [dbError, setDbError] = useState<string | null>(null);

  const [stores, setStores] = useState<Store[]>([]);
  const [activeStoreId, setActiveStoreId] = useState<string | null>(null);

  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [inventory, setInventory] = useState<InventoryItem[]>([]);
  const [phRecords, setPhRecords] = useState<PHRecord[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);

  useEffect(() => {
    const checkSession = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        setIsAuthenticated(!!session);

        supabase.auth.onAuthStateChange((_event, session) => {
          setIsAuthenticated(!!session);
          if (!session) {
            setStores([]);
            setActiveStoreId(null);
          }
        });

        if (session) {
          await fetchStores();
        } else {
          setIsInitialLoading(false);
        }
      } catch (err) {
        console.error("Erro ao verificar sessão:", err);
        setIsInitialLoading(false);
      }
    };

    checkSession();
  }, []);

  const fetchStores = async () => {
    try {
      const { data, error } = await supabase.from('stores').select('*').order('name');

      if (error) {
        if (error.code === '42P01' || error.message.includes('relation "public.stores" does not exist')) {
          setDbError('As tabelas ainda não foram criadas no Supabase.');
          setIsInitialLoading(false);
          return;
        }
        throw error;
      }

      if (data && data.length > 0) {
        setStores(data);
        const lastId = localStorage.getItem('c1_active_id');
        const validId = lastId && data.find(s => s.id === lastId) ? lastId : data[0].id;
        setActiveStoreId(validId);
      } else {
        const { data: newStore, error: createError } = await supabase
          .from('stores')
          .insert([{ name: 'Agua C - Principal' }])
          .select()
          .single();

        if (createError) throw createError;
        setStores([newStore]);
        setActiveStoreId(newStore.id);

        const seed = INITIAL_INVENTORY.map(item => ({
            store_id: newStore.id,
            name: item.name,
            quantity: item.quantity,
            unit: item.unit,
            min_threshold: item.minThreshold,
            price: item.price
        }));
        await supabase.from('inventory_items').insert(seed);
      }
    } catch (err) {
      console.error('Erro ao inicializar:', err);
    } finally {
      setIsInitialLoading(false);
    }
  };

  useEffect(() => {
    if (!activeStoreId || !isAuthenticated) return;

    const loadData = async () => {
      try {
        const [tRes, iRes, phRes, nRes] = await Promise.all([
          supabase.from('transactions').select('*').eq('store_id', activeStoreId).order('created_at', { ascending: false }),
          supabase.from('inventory_items').select('*').eq('store_id', activeStoreId).order('name'),
          supabase.from('ph_records').select('*').eq('store_id', activeStoreId).order('created_at', { ascending: false }),
          supabase.from('notifications').select('*').eq('store_id', activeStoreId).order('created_at', { ascending: false })
        ]);

        setTransactions(tRes.data || []);
        setInventory(iRes.data || []);
        setPhRecords(phRes.data || []);
        setNotifications(nRes.data || []);
      } catch (err) {
        console.error("Erro ao carregar dados da loja:", err);
      }
    };

    loadData();
  }, [activeStoreId, isAuthenticated]);

  const handleAddTransaction = async (newT: Omit<Transaction, 'id' | 'created_at' | 'store_id'>) => {
    try {
      const { data, error } = await supabase
        .from('transactions')
        .insert([{ ...newT, store_id: activeStoreId }])
        .select()
        .single();

      if (error) throw error;
      if (data) setTransactions(prev => [data, ...prev]);
      return data;
    } catch (err) {
      console.error("Erro ao salvar transação:", err);
      // Fallback local se o DB falhar
      const fallback: Transaction = {
        ...newT,
        id: crypto.randomUUID(),
        store_id: activeStoreId || '',
        created_at: new Date().toISOString()
      };
      setTransactions(prev => [fallback, ...prev]);
      return fallback;
    }
  };

  const handleUpdateInventory = async (id: string, delta: number) => {
    const item = inventory.find(i => i.id === id);
    if (!item) return;

    const newQty = Math.max(0, item.quantity + delta);

    // 1. Atualiza estado local imediatamente para fluidez
    setInventory(prev => prev.map(i => i.id === id ? { ...i, quantity: newQty } : i));

    // 2. Se for uma saída (delta negativo), registra automaticamente como venda
    if (delta < 0) {
      const quantitySold = Math.abs(delta);
      const totalSaleAmount = quantitySold * item.price;

      await handleAddTransaction({
        type: 'sale',
        category: item.name,
        amount: totalSaleAmount,
        description: `Venda automática via controle de estoque (${quantitySold} ${item.unit})`,
        quantity: quantitySold
      });

      setToast({
        id: crypto.randomUUID(),
        store_id: activeStoreId || '',
        title: 'Venda Registrada',
        message: `${item.name}: +${totalSaleAmount.toLocaleString()} Kz adicionados ao caixa.`,
        type: 'info',
        read: false,
        created_at: new Date().toISOString()
      });
    }

    // 3. Persiste no banco
    try {
      await supabase.from('inventory_items').update({ quantity: newQty }).eq('id', id);
      await supabase.from('inventory_movements').insert([{
        item_id: id,
        quantity: Math.abs(delta),
        type: delta > 0 ? 'in' : 'out'
      }]);
    } catch (err) {
      console.error("Erro ao sincronizar estoque com DB:", err);
    }
  };

  const handleAddPHRecord = async (value: number) => {
    let status: 'Ideal' | 'Alerta' | 'Crítico' = 'Ideal';
    if (value < 6.5 || value > 8.0) status = 'Crítico';
    else if ((value >= 6.5 && value < 6.8) || (value > 7.5 && value <= 8.0)) status = 'Alerta';

    try {
      const { data } = await supabase.from('ph_records').insert([{
        store_id: activeStoreId,
        value,
        status
      }]).select().single();
      if (data) setPhRecords(prev => [data, ...prev]);
    } catch (err) {}
  };

  const handleAddInventoryItem = async (newItem: Omit<InventoryItem, 'id' | 'store_id' | 'created_at'>) => {
    try {
      const { data } = await supabase
        .from('inventory_items')
        .insert([{ ...newItem, store_id: activeStoreId }])
        .select()
        .single();
      if (data) setInventory(prev => [...prev, data]);
    } catch (err) {}
  };

  if (dbError) {
    return (
      <div className="fixed inset-0 flex items-center justify-center bg-slate-950 p-8">
        <div className="w-full max-w-md bg-white rounded-[40px] p-10 shadow-2xl space-y-8 animate-premium">
          <div className="flex flex-col items-center gap-4 text-center">
             <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center text-red-600">
               <Database size={32} />
             </div>
             <h2 className="text-xl font-black text-slate-900">Configuração Necessária</h2>
             <p className="text-sm text-slate-500 font-medium leading-relaxed">
               As tabelas do banco de dados ainda não foram detectadas no Supabase.
             </p>
          </div>
          <button 
            onClick={() => window.location.reload()}
            className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest active:scale-95 transition-all"
          >
            Tentar Novamente
          </button>
        </div>
      </div>
    );
  }

  if (!isAuthenticated) return <LoginView onSuccess={() => setIsAuthenticated(true)} />;

  if (isInitialLoading) {
    return (
      <div className="fixed inset-0 flex items-center justify-center bg-slate-950">
        <div className="flex flex-col items-center gap-6">
          <div className="w-16 h-16 border-4 border-blue-600 border-t-transparent rounded-full animate-spin" />
          <span className="text-blue-500 font-black text-[10px] uppercase tracking-widest">Agua C Cloud</span>
        </div>
      </div>
    );
  }

  return (
    <Layout 
      activeView={activeView} 
      setActiveView={setActiveView} 
      notifications={notifications}
      onMarkRead={() => {}} 
      stores={stores}
      activeStoreId={activeStoreId || ''}
      onSwitchStore={setActiveStoreId}
      onAddStore={async (name) => {
        const { data } = await supabase.from('stores').insert([{ name }]).select().single();
        if (data) setStores(prev => [...prev, data]);
      }}
      onLogout={async () => {
        await supabase.auth.signOut();
        setIsAuthenticated(false);
      }}
    >
      <div className="pb-8">
        {activeView === 'dashboard' && <Dashboard state={{ transactions, inventory, inventoryMovements: [], phRecords, notifications }} />}
        {activeView === 'sales' && <TransactionForm type="sale" onAdd={handleAddTransaction} transactions={transactions} />}
        {activeView === 'expenses' && <TransactionForm type="expense" onAdd={handleAddTransaction} transactions={transactions} />}
        {activeView === 'inventory' && <InventoryView inventory={inventory} movements={[]} onUpdate={handleUpdateInventory} onAddItem={handleAddInventoryItem} />}
        {activeView === 'reports' && <ReportsView state={{ transactions, inventory, inventoryMovements: [], phRecords, notifications }} onAddPH={handleAddPHRecord} storeName={stores.find(s => s.id === activeStoreId)?.name} />}
      </div>
      {toast && <NotificationToast notification={toast} onClose={() => setToast(null)} />}
    </Layout>
  );
};

export default App;

import React, { useMemo, useState } from 'react';
import { InventoryItem, InventoryMovement } from '../types';
import { 
  X, 
  ArrowDownRight, 
  ArrowUpRight, 
  PackagePlus, 
  Box,
  Package,
  Sparkles,
  AlertCircle,
  Coins,
  ChevronRight,
  TrendingUp
} from 'lucide-react';

interface InventoryViewProps {
  inventory: InventoryItem[];
  movements: InventoryMovement[];
  onUpdate: (id: string, delta: number) => void;
  onAddItem: (item: Omit<InventoryItem, 'id' | 'store_id' | 'created_at'>) => void;
}

const InventoryView: React.FC<InventoryViewProps> = ({ inventory, movements, onUpdate, onAddItem }) => {
  const [adjustmentModal, setAdjustmentModal] = useState<{ isOpen: boolean; itemId: string; itemName: string; type: 'in' | 'out' } | null>(null);
  const [newItemModal, setNewItemModal] = useState(false);
  const [adjustmentAmount, setAdjustmentAmount] = useState('');

  const [newName, setNewName] = useState('');
  const [newUnit, setNewUnit] = useState('un');
  const [newMin, setNewMin] = useState('10');
  const [newInitial, setNewInitial] = useState('0');
  const [newPrice, setNewPrice] = useState('0');

  const inventoryValue = useMemo(() => {
    return inventory.reduce((sum, item) => sum + (item.quantity * item.price), 0);
  }, [inventory]);

  const lowStockCount = useMemo(() => {
    return inventory.filter(i => i.quantity <= i.min_threshold).length;
  }, [inventory]);

  const handleAdjustmentSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const amount = parseInt(adjustmentAmount);
    if (adjustmentModal && !isNaN(amount) && amount > 0) {
      const delta = adjustmentModal.type === 'in' ? amount : -amount;
      onUpdate(adjustmentModal.itemId, delta);
      setAdjustmentModal(null);
      setAdjustmentAmount('');
    }
  };

  const handleCreateItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName) return;
    onAddItem({
      name: newName,
      unit: newUnit,
      min_threshold: parseInt(newMin) || 0,
      quantity: parseInt(newInitial) || 0,
      price: parseFloat(newPrice) || 0
    });
    setNewItemModal(false);
    setNewName('');
    setNewInitial('0');
    setNewPrice('0');
  };

  return (
    <div className="space-y-10 animate-premium">
      <div className="flex items-center justify-between">
        <div className="flex flex-col">
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">Estoque Agua C</h2>
          <p className="text-xs font-black text-blue-600 uppercase tracking-[0.3em] mt-2">Controle de Insumos e Vendas</p>
        </div>
        <button 
          onClick={() => setNewItemModal(true)}
          className="bg-blue-600 text-white p-4 rounded-2xl shadow-xl shadow-blue-500/30 hover:scale-105 active:scale-95 transition-all flex items-center justify-center"
        >
          <PackagePlus size={24} />
        </button>
      </div>

      <div className="bg-slate-900 p-12 rounded-[56px] text-white shadow-2xl relative overflow-hidden">
         <div className="relative z-10 grid grid-cols-1 md:grid-cols-2 gap-12 items-center">
            <div className="flex flex-col gap-3">
               <div className="flex items-center gap-3 text-blue-400">
                  <Box size={20} />
                  <span className="text-xs font-black uppercase tracking-[0.2em]">Patrimônio em Insumos</span>
               </div>
               <h3 className="text-6xl font-black tracking-tight">{inventoryValue.toLocaleString()} Kz</h3>
            </div>
            <div className="flex flex-wrap gap-4 md:justify-end">
               <div className={`px-8 py-4 rounded-[28px] border backdrop-blur-md flex flex-col items-center gap-1 ${lowStockCount > 0 ? 'bg-red-500/20 border-red-500/30 text-red-400' : 'bg-emerald-500/20 border-emerald-500/30 text-emerald-400'}`}>
                  <span className="text-[10px] font-black uppercase opacity-60">Alertas</span>
                  <span className="text-sm font-black uppercase">{lowStockCount > 0 ? `${lowStockCount} Críticos` : 'Estoque OK'}</span>
               </div>
