                <span className="text-[10px] font-black text-blue-600 uppercase tracking-[0.4em] mb-2">Caixa Global</span>
                <span className={`text-5xl font-black tracking-tight ${currentBalance >= 0 ? 'text-slate-900' : 'text-red-600'}`}>
                  {currentBalance.toLocaleString()} Kz
                </span>
              </div>
              <div className="bg-blue-600 p-5 rounded-3xl text-white shadow-2xl shadow-blue-500/30">
                <Wallet size={32} />
              </div>
            </div>

            <div className="flex items-center gap-4 bg-emerald-50/70 p-6 rounded-3xl border border-emerald-100">
               <TrendingUp size={24} className="text-emerald-500" />
               <div className="flex flex-col">
                 <span className="text-[9px] font-black text-emerald-600 uppercase tracking-widest">Vendas de Hoje</span>
