import React, { useMemo, useState } from 'react';
import { InventoryItem, InventoryMovement } from '../types';
import { 
  X, 
  ArrowUpRight, 
  PackagePlus, 
  Box,
  Package,
  Sparkles,
  TrendingUp,
  Plus
} from 'lucide-react';

interface InventoryViewProps {
  inventory: InventoryItem[];
  movements: InventoryMovement[];
  onUpdate: (id: string, delta: number) => void;
  onAddItem: (item: Omit<InventoryItem, 'id' | 'store_id' | 'created_at'>) => void;
}

const InventoryView: React.FC<InventoryViewProps> = ({ inventory, movements, onUpdate, onAddItem }) => {
  const [adjustmentModal, setAdjustmentModal] = useState<{ isOpen: boolean; itemId: string; itemName: string; type: 'in' | 'out' } | null>(null);
  const [newItemModal, setNewItemModal] = useState(false);
  const [adjustmentAmount, setAdjustmentAmount] = useState('');

  const [newName, setNewName] = useState('');
  const [newUnit, setNewUnit] = useState('un');
  const [newMin, setNewMin] = useState('10');
  const [newInitial, setNewInitial] = useState('0');
  const [newPrice, setNewPrice] = useState('0');

  const inventoryValue = useMemo(() => {
    return inventory.reduce((sum, item) => sum + (item.quantity * item.price), 0);
  }, [inventory]);

  const lowStockCount = useMemo(() => {
    return inventory.filter(i => i.quantity <= i.min_threshold).length;
  }, [inventory]);

  const handleAdjustmentSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const amount = parseInt(adjustmentAmount);
    if (adjustmentModal && !isNaN(amount) && amount > 0) {
      const delta = adjustmentModal.type === 'in' ? amount : -amount;
      onUpdate(adjustmentModal.itemId, delta);
      setAdjustmentModal(null);
      setAdjustmentAmount('');
    }
  };

  const handleCreateItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName) return;
    onAddItem({
      name: newName,
      unit: newUnit,
      min_threshold: parseInt(newMin) || 0,
      quantity: parseInt(newInitial) || 0,
      price: parseFloat(newPrice) || 0
    });
    setNewItemModal(false);
    setNewName('');
    setNewInitial('0');
    setNewPrice('0');
  };

  return (
    <div className="space-y-10 animate-premium">
      <div className="flex items-center justify-between">
        <div className="flex flex-col">
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">Estoque CrystalOne</h2>
          <p className="text-xs font-black text-blue-600 uppercase tracking-[0.3em] mt-2">Inteligência Logística</p>
        </div>
        <button 
          onClick={() => setNewItemModal(true)}
          className="bg-blue-600 text-white p-4 rounded-2xl shadow-xl shadow-blue-500/30 active:scale-95 transition-all"
        >
          <PackagePlus size={24} />
        </button>
      </div>

      {/* Inventory Value Summary */}
      <div className="bg-slate-900 p-12 rounded-[56px] text-white shadow-2xl relative overflow-hidden">
         <div className="relative z-10 grid grid-cols-1 md:grid-cols-2 gap-12 items-center">
            <div className="flex flex-col gap-3">
               <div className="flex items-center gap-3 text-blue-400">
                  <Box size={20} />
                  <span className="text-xs font-black uppercase tracking-[0.2em]">Patrimônio em Insumos</span>
               </div>
               <h3 className="text-6xl font-black tracking-tight">{inventoryValue.toLocaleString()} Kz</h3>
            </div>
            <div className="flex flex-wrap gap-4 md:justify-end">
               <div className={`px-8 py-4 rounded-[28px] border backdrop-blur-md flex flex-col items-center gap-1 ${lowStockCount > 0 ? 'bg-red-500/20 border-red-500/30 text-red-400' : 'bg-emerald-500/20 border-emerald-500/30 text-emerald-400'}`}>
                  <span className="text-[10px] font-black uppercase opacity-60">Status</span>
                  <span className="text-sm font-black uppercase">{lowStockCount > 0 ? `${lowStockCount} Críticos` : 'Estoque Saudável'}</span>
               </div>
            </div>
         </div>
         <Sparkles size={250} className="text-white/5 absolute -right-20 -bottom-20 rotate-12" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {inventory.map(item => {
          const isCritical = item.quantity <= item.min_threshold;

          return (
            <div key={item.id} className={`bg-white/80 backdrop-blur-xl p-8 rounded-[48px] border border-white shadow-sm flex flex-col hover:shadow-2xl transition-all group ${isCritical ? 'ring-2 ring-red-500/10' : ''}`}>
              <div className="flex justify-between items-start mb-8">
                 <div className="p-4 rounded-3xl bg-slate-50 text-slate-400 group-hover:bg-blue-600 group-hover:text-white transition-all">
                    <Package size={28} />
                 </div>
                 {isCritical && (
                   <span className="bg-red-500 text-white text-[9px] font-black px-4 py-1.5 rounded-full animate-pulse uppercase tracking-widest">Repor</span>
                 )}
              </div>

              <div className="flex-1">
                <h4 className="font-black text-slate-900 text-xl mb-2">{item.name}</h4>
                <div className="flex items-center gap-3 mb-6">
                   <span className={`text-sm font-black uppercase ${isCritical ? 'text-red-500' : 'text-blue-600'}`}>
                      {item.quantity} {item.unit}
                   </span>
                   <div className="w-1.5 h-1.5 rounded-full bg-slate-200"></div>
                   <span className="text-xs text-slate-400 font-bold">{item.price.toLocaleString()} Kz</span>
                </div>
              </div>

              <div className="space-y-4 pt-6 border-t border-slate-50">
                 <div className="flex gap-2">
                    <button 
                      onClick={() => onUpdate(item.id, -1)}
                      className="flex-1 bg-emerald-600 text-white py-4 rounded-2xl font-black text-[10px] uppercase active:scale-95 transition-all flex items-center justify-center gap-2 shadow-lg shadow-emerald-500/10"
                    >
                      <Plus size={16} /> +1 VENDA
                    </button>
                    <button 
                      onClick={() => setAdjustmentModal({ isOpen: true, itemId: item.id, itemName: item.name, type: 'in' })}
                      className="flex-1 bg-blue-600 text-white py-4 rounded-2xl font-black text-[10px] uppercase active:scale-95 transition-all flex items-center justify-center gap-2"
                    >
                      <ArrowUpRight size={16} /> REPOR
                    </button>
                 </div>
                 <button 
                    onClick={() => setAdjustmentModal({ isOpen: true, itemId: item.id, itemName: item.name, type: 'out' })}
                    className="w-full py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest hover:text-blue-600 transition-colors"
                  >
                    Venda Personalizada
                  </button>
              </div>
            </div>
          );
        })}
      </div>

      {/* Adjust Modal */}
      {adjustmentModal?.isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-xl" onClick={() => setAdjustmentModal(null)} />
          <div className="relative bg-white w-full max-w-lg rounded-[56px] p-16 shadow-2xl animate-premium text-center">
            <h3 className="text-3xl font-black text-slate-900 mb-2">
              {adjustmentModal.type === 'in' ? 'Reposição' : 'Baixa Manual'}
            </h3>
            <p className="text-sm text-blue-600 font-black uppercase tracking-[0.3em] mb-12">{adjustmentModal.itemName}</p>
            <form onSubmit={handleAdjustmentSubmit} className="space-y-10">
              <input 
                autoFocus
                type="number" 
                value={adjustmentAmount} 
                onChange={e => setAdjustmentAmount(e.target.value)} 
                placeholder="0" 
                className="w-full bg-slate-50 border border-slate-100 rounded-[40px] py-12 text-7xl font-black text-center focus:outline-none transition-all" 
                required 
              />
              <button 
                type="submit" 
                className={`w-full text-white font-black py-7 rounded-[32px] shadow-2xl transition-all text-sm tracking-widest ${
                  adjustmentModal.type === 'in' ? 'bg-blue-600' : 'bg-emerald-600'
                }`}
              >
                {adjustmentModal.type === 'in' ? 'CONFIRMAR ENTRADA' : 'FINALIZAR VENDA'}
              </button>
            </form>
          </div>
        </div>
      )}

      {/* New Item Modal (Simplified) */}
      {newItemModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-xl" onClick={() => setNewItemModal(false)} />
          <div className="relative bg-white w-full max-w-2xl rounded-[64px] p-12 shadow-2xl animate-premium">
             <form onSubmit={handleCreateItem} className="space-y-6">
                <input value={newName} onChange={e => setNewName(e.target.value)} placeholder="Nome do Insumo CrystalOne" className="w-full bg-slate-50 p-6 rounded-3xl font-bold border border-slate-100" required />
                <div className="grid grid-cols-2 gap-4">
                  <input type="number" value={newMin} onChange={e => setNewMin(e.target.value)} placeholder="Mínimo" className="bg-slate-50 p-6 rounded-3xl font-bold" />
                  <input type="number" value={newPrice} onChange={e => setNewPrice(e.target.value)} placeholder="Preço Kz" className="bg-slate-50 p-6 rounded-3xl font-bold" />
                </div>
                <button type="submit" className="w-full bg-blue-600 text-white font-black py-6 rounded-3xl shadow-xl">CADASTRAR</button>
             </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default InventoryView;

import React, { useState } from 'export type TransactionType = 'sale' | 'expense' | 'investment';
import { User, Lock, Droplets, ChevronRight, Eye, EyeOff, ShieldCheck, Mail, ArrowLeft, AlertCircle } from 'lucide-react';
import { supabase } from '../services/supabase';

interface LoginViewProps {
  onSuccess: () => void;
}

const LoginView: React.FC<LoginViewProps> = ({ onSuccess }) => {
  const [isSignUp, setIsSignUp] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    setSuccessMsg(null);

    try {
      if (isSignUp) {
        const { data, error: signUpError } = await supabase.auth.signUp({
          email,
          password,
          options: {
            emailRedirectTo: window.location.origin
          }
        });

        if (signUpError) throw signUpError;

        if (data?.session) {
          onSuccess();
        } else {
          setSuccessMsg("CONTA CRIADA! Verifique seu e-mail para confirmar antes do login.");
          setIsSignUp(false);
        }
      } else {
        const { data, error: signInError } = await supabase.auth.signInWithPassword({
          email,
          password,
        });

        if (signInError) throw signInError;
        if (data?.session) onSuccess();
      }
    } catch (err: any) {
      console.error("Erro de Autenticação:", err);
      if (err.message.includes("Email not confirmed")) {
        setError("E-mail não confirmado. Verifique sua caixa de entrada.");
      } else if (err.message.includes("Invalid login credentials")) {
        setError("Dados inválidos. Verifique e-mail e senha.");
      } else {
        setError(err.message || "Ocorreu um erro inesperado.");
      }
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center px-8 bg-slate-950 overflow-hidden">
      <div className="absolute top-[-10%] right-[-10%] w-[400px] h-[400px] bg-blue-600/10 rounded-full blur-[100px]" />
      <div className="absolute bottom-[-10%] left-[-10%] w-[300px] h-[300px] bg-cyan-600/10 rounded-full blur-[80px]" />

      <div className="w-full max-w-sm space-y-10 relative z-10 animate-premium">
        <div className="flex flex-col items-center space-y-6">
          <div className="relative">
            <div className="absolute inset-0 bg-blue-500/20 blur-2xl rounded-full scale-125" />
            <div className="relative w-24 h-24 bg-gradient-to-br from-blue-600 to-cyan-500 rounded-[32px] flex items-center justify-center shadow-2xl shadow-blue-500/20 border border-white/10">
               <Droplets className="text-white" size={48} />
            </div>
          </div>
          <div className="text-center">
            <h1 className="text-4xl font-black text-white tracking-tighter">CrystalOne</h1>
            <p className="text-[10px] text-blue-400 font-bold uppercase tracking-[0.4em] mt-1 opacity-60">
              {isSignUp ? 'Registro de Unidade' : 'Business Ecosystem'}
            </p>
          </div>
        </div>

        <form onSubmit={handleAuth} className="space-y-4">
          <div className="space-y-1.5">
            <div className="relative group">
              <div className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-500">
                <Mail size={18} />
              </div>
              <input 
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="Seu e-mail"
                className="w-full bg-white/5 border border-white/10 rounded-[24px] pl-14 pr-6 py-5 text-white font-bold placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-blue-500/50"
                required
              />
            </div>
          </div>

          <div className="space-y-1.5">
            <div className="relative group">
              <div className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-500">
                <Lock size={18} />
              </div>
              <input 
                type={showPassword ? "text" : "password"}
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Sua senha"
                className="w-full bg-white/5 border border-white/10 rounded-[24px] pl-14 pr-14 py-5 text-white font-bold placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-blue-500/50"
                required
              />
